// ===== TOOL PATHWAY CONNECTOR =====
function hwPathway(position,actions,nextTool){
  var h='<div style="margin-top:20px;padding:20px;background:linear-gradient(160deg,var(--bg2),rgba(200,168,124,.03));border:1px solid var(--border2);border-radius:12px">';
  // Attending Note format
  h+='<div style="font-size:11px;font-weight:600;color:var(--accent);text-transform:uppercase;letter-spacing:1.2px;margin-bottom:12px">Attending Note</div>';
  h+='<div style="font-size:13px;color:var(--text);line-height:1.7;margin-bottom:16px;font-family:var(--font-serif)">'+position+'</div>';
  if(actions&&actions.length){
    h+='<div style="font-size:10px;font-weight:600;color:var(--text3);text-transform:uppercase;letter-spacing:1.2px;margin-bottom:10px">What to do next</div>';
    actions.forEach(function(a,i){
      var timeColor=a.when==='this week'?'var(--red)':a.when==='this month'?'var(--accent)':'var(--text3)';
      h+='<div style="display:flex;gap:10px;padding:10px 12px;background:var(--bg);border-radius:8px;margin-bottom:6px;border-left:3px solid '+(i===0?'var(--green)':i===1?'var(--accent)':'var(--text3)')+'">';
      h+='<div style="font-size:14px;font-weight:700;color:var(--accent);flex-shrink:0;width:20px;text-align:center">'+(i+1)+'</div>';
      h+='<div style="flex:1"><div style="font-size:12px;color:var(--text);line-height:1.5">'+a.text+'</div>';
      h+='<div style="font-size:10px;color:'+timeColor+';font-weight:500;margin-top:3px">'+a.when+'</div></div></div>';
    });
  }
  if(nextTool){
    h+='<div style="margin-top:14px;padding:14px;background:var(--accent-dim);border:1px solid var(--border2);border-radius:10px;cursor:pointer;transition:all .2s" onclick="openFramework(\''+nextTool.id+'\')" onmouseenter="this.style.transform=\'translateY(-1px)\'" onmouseleave="this.style.transform=\'none\'">';
    h+='<div style="display:flex;align-items:center;gap:10px">';
    h+='<div style="font-size:22px;flex-shrink:0">'+nextTool.icon+'</div>';
    h+='<div style="flex:1"><div style="font-size:10px;font-weight:600;color:var(--accent);text-transform:uppercase;letter-spacing:1px;margin-bottom:2px">Run this next</div>';
    h+='<div style="font-size:13px;font-weight:600;color:var(--text)">'+nextTool.title+'</div>';
    h+='<div style="font-size:11px;color:var(--text3);margin-top:2px">'+nextTool.why+'</div></div></div></div>';
  }
  // Value anchoring
  h+='<div style="display:flex;align-items:center;gap:6px;margin-top:14px;padding:10px 12px;background:rgba(139,173,196,.04);border-radius:8px;border:1px solid rgba(139,173,196,.1)">';
  h+='<span style="font-size:12px;flex-shrink:0">📊</span>';
  h+='<span style="font-size:10px;color:var(--text3);line-height:1.5">This analysis is based on real match data, MGMA benchmarks, and career outcomes from thousands of physicians. A comparable consultation typically costs $150\u2013$300.</span>';
  h+='</div>';
  // Export buttons
  h+='<div style="display:flex;gap:8px;margin-top:14px">';
  h+='<button onclick="exportToolResult()" style="flex:1;padding:10px;font-size:11px;font-weight:600;color:var(--accent);background:rgba(198,168,94,.06);border:1px solid rgba(198,168,94,.2);border-radius:8px;cursor:pointer;transition:all .2s" onmouseenter="this.style.background=\'rgba(198,168,94,.12)\'" onmouseleave="this.style.background=\'rgba(198,168,94,.06)\'">📄 Save as PDF</button>';
  h+='<button onclick="copyToolResult()" style="flex:1;padding:10px;font-size:11px;font-weight:600;color:var(--text2);background:var(--bg2);border:1px solid var(--border);border-radius:8px;cursor:pointer;transition:all .2s" onmouseenter="this.style.background=\'var(--bg3)\'" onmouseleave="this.style.background=\'var(--bg2)\'">📋 Copy Text</button>';
  h+='</div>';
  h+='</div>';
  return h;
}

// ===== COLLAPSIBLE RESULTS SECTIONS =====
var hwSecCounter=0;
function hwSection(title,summary,content,open){
  var id='hw-sec-'+(++hwSecCounter);
  var h='<div class="hw-sec" style="margin-bottom:8px;border:1px solid var(--border);border-radius:10px;overflow:hidden">';
  h+='<div onclick="hwToggleSec(\''+id+'\')" style="display:flex;justify-content:space-between;align-items:center;padding:12px 14px;cursor:pointer;background:var(--bg2);-webkit-tap-highlight-color:transparent;user-select:none">';
  h+='<span style="font-size:12px;font-weight:600;color:var(--text)">'+title+'</span>';
  h+='<div style="display:flex;align-items:center;gap:8px">';
  if(summary)h+='<span style="font-size:11px;color:var(--accent);font-weight:500">'+summary+'</span>';
  h+='<span id="'+id+'-arrow" style="font-size:9px;color:var(--text3);transition:transform .2s;display:inline-block;transform:rotate('+(open?'90':'0')+'deg)">\u25B6</span>';
  h+='</div></div>';
  h+='<div id="'+id+'" style="'+(open?'':'display:none;')+'padding:14px;border-top:1px solid var(--border)">';
  h+=content;
  h+='</div></div>';
  return h;
}
function exportToolResult(){
  var content=document.getElementById('modal-q-content');
  if(!content)return;
  // Create a print-friendly window
  var win=window.open('','_blank');
  if(!win){notify('Pop-up blocked. Allow pop-ups for this site.',1);return}
  win.document.write('<!DOCTYPE html><html><head><title>HeartWise Report</title>');
  win.document.write('<style>body{font-family:Georgia,serif;max-width:700px;margin:40px auto;padding:20px;color:#1C1A17;line-height:1.6}h1,h2,h3{font-family:Georgia,serif}button,.hw-blur-overlay,.v-lock{display:none!important}.card{border:1px solid #E8E1D8;border-radius:8px;padding:12px;margin:8px 0}.hw-sec{border:1px solid #E8E1D8;border-radius:8px;margin:8px 0}');
  win.document.write('@media print{body{margin:20px}}</style></head><body>');
  win.document.write('<div style="text-align:center;margin-bottom:30px;padding-bottom:20px;border-bottom:2px solid #C6A85E"><h1 style="margin:0;color:#C6A85E;font-size:22px">HeartWise</h1><div style="font-size:12px;color:#8A8278;margin-top:4px">Physician Career Intelligence Report · '+new Date().toLocaleDateString('en-US',{month:'long',day:'numeric',year:'numeric'})+'</div></div>');
  // Expand all collapsed sections for export
  var clone=content.cloneNode(true);
  clone.querySelectorAll('[id^="hw-sec-"]').forEach(function(el){el.style.display=''});
  // Remove interactive elements
  clone.querySelectorAll('button,input,select,textarea').forEach(function(el){el.remove()});
  win.document.write(clone.innerHTML);
  win.document.write('<div style="margin-top:40px;padding-top:20px;border-top:1px solid #E8E1D8;text-align:center;font-size:11px;color:#8A8278">Generated by HeartWise · heartwisementor.com</div>');
  win.document.write('</body></html>');
  win.document.close();
  setTimeout(function(){win.print()},500);
}

function copyToolResult(){
  var content=document.getElementById('modal-q-content');
  if(!content)return;
  // Clone and expand sections
  var clone=content.cloneNode(true);
  clone.querySelectorAll('[id^="hw-sec-"]').forEach(function(el){el.style.display=''});
  // Remove buttons
  clone.querySelectorAll('button,input,select,textarea').forEach(function(el){el.remove()});
  var text=clone.innerText||clone.textContent;
  // Clean up whitespace
  text=text.replace(/\n{3,}/g,'\n\n').trim();
  text='HeartWise Report — '+new Date().toLocaleDateString('en-US',{month:'long',day:'numeric',year:'numeric'})+'\n\n'+text+'\n\nGenerated by HeartWise · heartwisementor.com';
  if(navigator.clipboard&&navigator.clipboard.writeText){
    navigator.clipboard.writeText(text).then(function(){notify('Report copied to clipboard ✓')}).catch(function(){fallbackCopy(text)});
  }else{fallbackCopy(text)}
}
function fallbackCopy(text){
  var ta=document.createElement('textarea');ta.value=text;ta.style.position='fixed';ta.style.left='-9999px';
  document.body.appendChild(ta);ta.select();
  try{document.execCommand('copy');notify('Report copied to clipboard ✓')}catch(e){notify('Could not copy. Try selecting the text manually.',1)}
  document.body.removeChild(ta);
}

function hwToggleSec(id){
  var el=document.getElementById(id);
  var arrow=document.getElementById(id+'-arrow');
  if(!el)return;
  if(el.style.display==='none'){
    el.style.display='';
    if(arrow)arrow.style.transform='rotate(90deg)';
  }else{
    el.style.display='none';
    if(arrow)arrow.style.transform='rotate(0deg)';
  }
}
function hwExpandAll(container){
  var secs=container?container.querySelectorAll('.hw-sec'):document.querySelectorAll('.hw-sec');
  secs.forEach(function(sec){
    var body=sec.querySelector('[id^="hw-sec-"]:not([id$="-arrow"])');
    var arrow=sec.querySelector('[id$="-arrow"]');
    if(body&&body.style)body.style.display='';
    if(arrow)arrow.style.transform='rotate(90deg)';
  });
}
function hwCollapseAll(container){
  var secs=container?container.querySelectorAll('.hw-sec'):document.querySelectorAll('.hw-sec');
  secs.forEach(function(sec){
    var body=sec.querySelector('[id^="hw-sec-"]:not([id$="-arrow"])');
    var arrow=sec.querySelector('[id$="-arrow"]');
    if(body&&body.style)body.style.display='none';
    if(arrow)arrow.style.transform='rotate(0deg)';
  });
}

// ===== TOPBAR SCROLL EFFECT =====
(function(){
  const lp=document.getElementById('pg-landing');
  const tb=document.getElementById('topbar');
  if(lp&&tb){
    function updateTopbar(scrollY){
      tb.classList.toggle('solid',scrollY>60);
      var heroEl=document.querySelector('.hero-lux');
      if(heroEl){
        var heroH=heroEl.offsetHeight;
        tb.classList.toggle('on-light',scrollY<heroH-80);
      }
    }
    lp.addEventListener('scroll',function(){updateTopbar(lp.scrollTop)});
    window.addEventListener('scroll',function(){updateTopbar(window.scrollY)});
    updateTopbar(0);
  }
})();

// ===== HERO SHOWCASE CAROUSEL =====
(function(){
  var currentSlide=0, totalSlides=7, timer=null, animated=[];
  var SLIDE_INTERVAL=6000;
  var taglines=[
    '72% of applicants overestimate their competitiveness',
    'Stop cold-emailing 200 programs. Target the right ones.',
    'The average physician loses $43K on their first contract',
    '68% of physicians say they\'d choose a different specialty',
    'A 2-year delay in financial planning costs $340K+',
    'The application window closes faster than you think',
    'One platform. Every career decision covered.'
  ];
  function updateTagline(idx){
    var el=document.getElementById('showcase-tagline');
    if(!el)return;
    el.style.opacity='0';
    setTimeout(function(){el.textContent=taglines[idx]||'';el.style.opacity='1'},300);
  }
  function updatePeek(idx){
    var left=document.querySelector('.showcase-peek-left');
    var right=document.querySelector('.showcase-peek-right');
    if(left)left.style.opacity=idx>0?'1':'0';
    if(right)right.style.opacity=idx<totalSlides-1?'1':'0';
  }
  function updateCounter(idx){
    var el=document.getElementById('showcase-cur');
    if(el)el.textContent=idx+1;
  }
  var progressRAF=null, progressStart=0;
  function startProgress(){
    var bar=document.getElementById('showcase-progress');
    if(!bar)return;
    bar.style.transition='none';
    bar.style.width='0%';
    if(progressRAF)cancelAnimationFrame(progressRAF);
    progressStart=performance.now();
    function tick(now){
      var elapsed=now-progressStart;
      var pct=Math.min((elapsed/SLIDE_INTERVAL)*100,100);
      bar.style.width=pct+'%';
      if(pct<100)progressRAF=requestAnimationFrame(tick);
    }
    progressRAF=requestAnimationFrame(tick);
  }
  function stopProgress(){
    if(progressRAF){cancelAnimationFrame(progressRAF);progressRAF=null}
    var bar=document.getElementById('showcase-progress');
    if(bar){bar.style.transition='width .3s ease';bar.style.width='0%'}
  }
  function animateSlide(idx){
    if(animated[idx])return; animated[idx]=true;
    if(idx===0){
      // Match Probability Calculator
      var scoreEl=document.querySelector('.showcase-slide[data-slide="0"] .sc-score');
      var target=76, cur=0;
      var si=setInterval(function(){cur+=2;if(cur>=target){cur=target;clearInterval(si)}if(scoreEl)scoreEl.textContent=cur},30);
      document.querySelectorAll('.showcase-slide[data-slide="0"] .sc-bar').forEach(function(b){setTimeout(function(){b.style.width=b.dataset.width+'%'},100)});
      document.querySelectorAll('.showcase-slide[data-slide="0"] .sc-pct').forEach(function(p){
        var t=parseInt(p.dataset.target),c=0;
        var pi=setInterval(function(){c+=2;if(c>=t){c=t;clearInterval(pi)}p.textContent=c+'%'},25);
      });
      setTimeout(function(){document.querySelectorAll('.showcase-slide[data-slide="0"] .sc-tag').forEach(function(t){t.style.opacity='1'})},1200);
    }else if(idx===1){
      // Observership Database
      setTimeout(function(){document.querySelectorAll('.obs-row').forEach(function(r){r.style.opacity='1';r.style.transform='translateX(0)'})},100);
      setTimeout(function(){document.querySelectorAll('.obs-tag').forEach(function(t){t.style.opacity='1'})},600);
    }else if(idx===2){
      // Contract Review Tool
      var valEl=document.querySelector('.contract-val'),rvuEl=document.querySelector('.contract-rvu');
      var tv=685000,cv=0;
      var vi=setInterval(function(){cv+=15000;if(cv>=tv){cv=tv;clearInterval(vi)}if(valEl)valEl.textContent='$'+cv.toLocaleString()},30);
      var tr=55,cr=0;
      var ri=setInterval(function(){cr+=1;if(cr>=tr){cr=tr;clearInterval(ri)}if(rvuEl)rvuEl.innerHTML='$'+cr+'<span style="font-size:11px;font-weight:300;color:var(--text3)">/wRVU</span>'},30);
      setTimeout(function(){document.querySelectorAll('.contract-flag').forEach(function(f){f.style.opacity='1';f.style.transform='translateX(0)'})},400);
    }else if(idx===3){
      // Specialty Fit Assessment
      setTimeout(function(){document.querySelectorAll('.sfa-row').forEach(function(r){r.style.opacity='1';r.style.transform='translateX(0)'})},100);
      setTimeout(function(){document.querySelectorAll('.sfa-tag').forEach(function(t){t.style.opacity='1'})},600);
    }else if(idx===4){
      // Financial Planner
      var amtEl=document.querySelector('.fin-amount'), diffEl=document.querySelector('.fin-diff');
      var t1=14.2,c1=0;
      var fi=setInterval(function(){c1+=0.3;if(c1>=t1){c1=t1;clearInterval(fi)}if(amtEl)amtEl.textContent='$'+c1.toFixed(1)+'M'},40);
      var t2=6.8,c2=0;
      var di=setInterval(function(){c2+=0.15;if(c2>=t2){c2=t2;clearInterval(di)}if(diffEl)diffEl.textContent='+$'+c2.toFixed(1)+'M'},40);
      setTimeout(function(){
        document.querySelectorAll('.fin-line-base,.fin-line-strat').forEach(function(l){l.style.strokeDashoffset='0'});
        var dot=document.querySelector('.fin-dot');if(dot)dot.style.opacity='1';
      },100);
    }else if(idx===5){
      // Career Roadmap
      setTimeout(function(){document.querySelectorAll('.fap-step').forEach(function(s){s.style.opacity='1';s.style.transform='translateX(0)'})},100);
      setTimeout(function(){document.querySelectorAll('.fap-tag').forEach(function(t){t.style.opacity='1'})},700);
    }else if(idx===6){
      // All 10 Tools
      var numEl=document.querySelector('.all17-number');
      if(numEl){numEl.style.opacity='1';numEl.style.transform='scale(1)'}
      setTimeout(function(){document.querySelectorAll('.all17-cat').forEach(function(c){c.style.opacity='1';c.style.transform='translateY(0)'})},200);
      setTimeout(function(){var cta=document.querySelector('.all17-cta');if(cta)cta.style.opacity='1'},500);
    }
  }
  window.goShowcase=function(idx){
    if(idx===currentSlide)return;
    clearInterval(timer);
    stopProgress();
    document.querySelectorAll('.showcase-slide').forEach(function(s){s.style.display='none'});
    document.querySelectorAll('.showcase-dot').forEach(function(d){d.style.background='var(--border2)';d.classList.remove('showcase-dot-active')});
    var slide=document.querySelector('.showcase-slide[data-slide="'+idx+'"]');
    var dot=document.querySelector('.showcase-dot[data-dot="'+idx+'"]');
    if(slide)slide.style.display='block';
    if(dot){dot.style.background='var(--accent)';dot.classList.add('showcase-dot-active')}
    currentSlide=idx;
    updateTagline(idx);
    updatePeek(idx);
    updateCounter(idx);
    setTimeout(function(){animateSlide(idx)},50);
    startTimer();
  };
  function startTimer(){
    clearInterval(timer);
    startProgress();
    timer=setInterval(function(){goShowcase((currentSlide+1)%totalSlides)},SLIDE_INTERVAL);
  }
  // Init on load via IntersectionObserver
  function initShowcase(){
    var el=document.getElementById('hero-showcase');
    if(!el)return;
    if('IntersectionObserver' in window){
      var obs=new IntersectionObserver(function(entries){
        entries.forEach(function(e){
          if(e.isIntersecting){animateSlide(0);updatePeek(0);startTimer();obs.disconnect()}
        });
      },{threshold:0.3});
      obs.observe(el);
    }else{animateSlide(0);updatePeek(0);startTimer()}
  }
  // Swipe support
  function initSwipe(){
    var card=document.getElementById('showcase-card');
    if(!card)return;
    var startX=0,startY=0,tracking=false;
    card.addEventListener('touchstart',function(e){
      startX=e.touches[0].clientX;
      startY=e.touches[0].clientY;
      tracking=true;
    },{passive:true});
    card.addEventListener('touchmove',function(e){
      if(!tracking)return;
      var dx=e.touches[0].clientX-startX;
      var dy=e.touches[0].clientY-startY;
      if(Math.abs(dx)>Math.abs(dy)&&Math.abs(dx)>10){
        e.preventDefault();
      }
    },{passive:false});
    card.addEventListener('touchend',function(e){
      if(!tracking)return;
      tracking=false;
      var endX=e.changedTouches[0].clientX;
      var dx=endX-startX;
      if(Math.abs(dx)<40)return;
      if(dx<0&&currentSlide<totalSlides-1){goShowcase(currentSlide+1)}
      else if(dx>0&&currentSlide>0){goShowcase(currentSlide-1)}
    },{passive:true});
    // Mouse drag for desktop
    var mouseDown=false,mouseX=0;
    card.addEventListener('mousedown',function(e){mouseDown=true;mouseX=e.clientX;e.preventDefault()});
    card.addEventListener('mousemove',function(e){if(mouseDown)e.preventDefault()});
    card.addEventListener('mouseup',function(e){
      if(!mouseDown)return;
      mouseDown=false;
      var dx=e.clientX-mouseX;
      if(Math.abs(dx)<40)return;
      if(dx<0&&currentSlide<totalSlides-1){goShowcase(currentSlide+1)}
      else if(dx>0&&currentSlide>0){goShowcase(currentSlide-1)}
    });
    card.addEventListener('mouseleave',function(){mouseDown=false});
  }
  if(document.readyState==='loading'){document.addEventListener('DOMContentLoaded',function(){initShowcase();initSwipe()})}else{initShowcase();initSwipe()}
})();

// ===== STICKY MOBILE CTA =====
(function(){
  var sticky=null,heroBtn=null,shown=false;
  function initSticky(){
    sticky=document.getElementById('sticky-cta');
    heroBtn=document.querySelector('.hero-btn-primary');
    if(!sticky||!heroBtn)return;
    // Only show on screens <= 768px wide
    function checkScroll(){
      if(window.innerWidth>768){if(shown){sticky.style.transform='translateY(100%)';shown=false}return}
      var rect=heroBtn.getBoundingClientRect();
      var heroGone=rect.bottom<0;
      if(heroGone&&!shown){sticky.style.display='';setTimeout(function(){sticky.style.transform='translateY(0)'},10);shown=true}
      else if(!heroGone&&shown){sticky.style.transform='translateY(100%)';shown=false}
    }
    window.addEventListener('scroll',checkScroll,{passive:true});
    window.addEventListener('resize',checkScroll,{passive:true});
  }
  if(document.readyState==='loading'){document.addEventListener('DOMContentLoaded',initSticky)}else{initSticky()}
})();

// ===== LANDING MENU =====
function toggleLandingMenu(e){
  e.stopPropagation();
  const m=document.getElementById('landing-menu');
  m.classList.toggle('hidden');
}
function closeLandingMenu(){
  const m=document.getElementById('landing-menu');
  if(m)m.classList.add('hidden');
}
function landingNav(id){
  closeLandingMenu();
  if(id==='pg-landing'){var hashTab={home:'home',questions:'tools',founder:'founder',pricing:'pricing'};var h=_initialHash;_initialHash='';var fromHash=hashTab[h]||null;var savedTab=null;try{savedTab=localStorage.getItem('hw_lp_tab')}catch(e){}lpTab(fromHash||savedTab||'home');return}
  var tabMap={'tools-sec':'tools','diff-sec':'compare','pricing-sec':'pricing','founder-sec':'founder'};
  if(tabMap[id]){lpTab(tabMap[id]);return}
  const el=document.getElementById(id);
  if(el)el.scrollIntoView({behavior:'smooth'});
}
function lpTab(name){
  closeLandingMenu();
  var tabs=document.querySelectorAll('.lp-tab');
  tabs.forEach(function(t){t.classList.remove('lp-tab-active')});
  var target=document.querySelector('.lp-tab[data-lptab="'+name+'"]');
  if(target)target.classList.add('lp-tab-active');
  // Highlight active nav link
  document.querySelectorAll('.lp-tab-link').forEach(function(a){a.classList.remove('active')});
  var activeLink=document.querySelector('.lp-tab-link[data-lptab="'+name+'"]');
  if(activeLink)activeLink.classList.add('active');
  // Update mobile tabs
  document.querySelectorAll('.lp-mtab').forEach(function(b){
    b.classList.remove('lp-mtab-active');
    b.style.background='transparent';b.style.color='#4A4A4A';b.style.fontWeight='500';b.style.borderColor='var(--border)';
  });
  var activeM=document.querySelector('.lp-mtab[data-lptab="'+name+'"]');
  if(activeM){activeM.classList.add('lp-mtab-active');activeM.style.background='rgba(198,168,94,.12)';activeM.style.color='#B89543';activeM.style.fontWeight='600';activeM.style.borderColor='rgba(198,168,94,.3)'}
  // Save tab in URL hash + localStorage
  var hashMap={home:'home',tools:'questions',founder:'founder',pricing:'pricing'};
  if(hashMap[name]){try{localStorage.setItem('hw_lp_tab',name)}catch(e){}}
  if(hashMap[name])history.replaceState(null,null,'#'+hashMap[name]);
  // Scroll to top of landing page — cover all scroll containers
  var pg=document.getElementById('pg-landing');
  if(pg)pg.scrollTo({top:0,behavior:'instant'});
  window.scrollTo({top:0,behavior:'instant'});
  document.documentElement.scrollTop=0;
  document.body.scrollTop=0;
  // Update topbar — only home tab has light hero
  var tb=document.getElementById('topbar');
  if(tb){
    if(name==='home'){tb.classList.add('on-light');tb.classList.remove('solid')}
    else{tb.classList.remove('on-light');tb.classList.add('solid')}
  }
  // Re-trigger reveal animations for newly visible tab
  if(target){
    target.querySelectorAll('.reveal').forEach(function(el){
      el.style.opacity='0';el.style.transform='translateY(24px)';
      setTimeout(function(){el.style.transition='opacity .6s ease,transform .6s ease';el.style.opacity='1';el.style.transform='translateY(0)'},50);
    });
  }
}



// Why HeartWise — stage tabs
function whyStage(stage){
  document.querySelectorAll('.why-stage-btn').forEach(function(b){
    if(b.getAttribute('data-stage')===stage){
      b.classList.add('why-stage-active');
      b.style.color='var(--accent)';b.style.background='var(--bg)';b.style.borderColor='var(--border2)';
    } else {
      b.classList.remove('why-stage-active');
      b.style.color='var(--text3)';b.style.background='var(--bg3)';b.style.borderColor='var(--border)';
    }
  });
  document.querySelectorAll('.why-stage-panel').forEach(function(p){
    if(p.getAttribute('data-stage')===stage){
      p.style.display='block';p.classList.add('why-stage-show');
    } else {
      p.style.display='none';p.classList.remove('why-stage-show');
    }
  });
}

