function showToolPreview(toolName,event){
  if(event)event.stopPropagation();
  var preview=TOOL_PREVIEWS[toolName];
  if(!preview)return;
  var existing=document.getElementById('tool-preview-modal');
  if(existing)existing.remove();
  var modal=document.createElement('div');
  modal.id='tool-preview-modal';
  modal.style.cssText='position:fixed;top:0;left:0;right:0;bottom:0;z-index:9999;display:flex;align-items:center;justify-content:center;padding:20px;animation:tpFadeIn .2s ease';
  var h='<div onclick="event.stopPropagation()" style="background:var(--bg);border:1px solid var(--border2);border-radius:16px;padding:24px;max-width:420px;width:100%;max-height:80vh;overflow-y:auto;box-shadow:0 20px 60px rgba(0,0,0,.3);position:relative">';
  h+='<div onclick="document.getElementById(\'tool-preview-modal\').remove()" style="position:absolute;top:12px;right:14px;width:28px;height:28px;border-radius:50%;background:var(--bg2);display:flex;align-items:center;justify-content:center;cursor:pointer;font-size:14px;color:var(--text3)">×</div>';
  h+='<div style="font-size:9px;font-weight:600;letter-spacing:1.5px;text-transform:uppercase;color:var(--accent);margin-bottom:6px">✦ Sample Output</div>';
  h+='<div style="font-size:16px;font-weight:600;color:var(--text);margin-bottom:16px">'+toolName+'</div>';
  h+=preview;
  h+='<div style="text-align:center;margin-top:16px"><button onclick="document.getElementById(\'tool-preview-modal\').remove();go(\'pg-onboard\')" class="btn btn-a" style="font-size:12px;padding:10px 24px">Try It Free →</button></div>';
  h+='</div>';
  modal.innerHTML=h;
  modal.onclick=function(){modal.remove()};
  document.body.appendChild(modal);
  if(!document.getElementById('tp-anim')){var s=document.createElement('style');s.id='tp-anim';s.textContent='@keyframes tpFadeIn{from{opacity:0}to{opacity:1}}';document.head.appendChild(s)}
}

