async function doLogin(e){
  e.preventDefault();
  var loginBtn=e.target.querySelector('button[type="submit"]')||e.target.querySelector('button');
  if(loginBtn){loginBtn.disabled=true;loginBtn.dataset.orig=loginBtn.textContent;loginBtn.textContent='Signing in...'}
  const email=document.getElementById('l-email').value.trim().toLowerCase();
  const pass=document.getElementById('l-pass').value;
  // Try Supabase auth first
  if(_supaClient){
    try{
      const{data,error}=await _supaClient.auth.signInWithPassword({email,password:pass});
      if(!error){
        const sbUser=data.user;
        let user=DB.users.find(u=>u.email.toLowerCase()===email);
        if(!user){
          const isAdmin=email===AE.toLowerCase();
          user={id:isAdmin?'admin':'u'+DB.nextUserId++,name:sbUser.user_metadata?.name||email.split('@')[0],email,pass:'__supabase__',role:isAdmin?'admin':'student',tier:isAdmin?'admin':'free',institution:'',usage:{ai:0,credits:isAdmin?999:0,month:new Date().getMonth()}};
          DB.users.push(user);saveDB();
        }
        // Ensure admin tier is always set for admin email
        if(email===AE.toLowerCase()&&user.tier!=='admin'){user.tier='admin';user.role='admin';saveDB()}
        // Sync trial status from Supabase profile
        try{
          var prof=await _supaClient.from('profiles').select('tier,is_trial,trial_end').eq('email',email).limit(1);
          if(!prof.error&&prof.data&&prof.data.length>0){
            var sp=prof.data[0];
            if(sp.trial_end){
              var now=new Date(),end=new Date(sp.trial_end);
              if(now>=end&&(sp.is_trial||user.isTrial)){
                user.tier='free';user.isTrial=false;
                await _supaClient.from('profiles').update({tier:'free',is_trial:false}).eq('email',email);
                saveDB();
              }else if(sp.is_trial){
                user.tier='core';user.isTrial=true;user.trialEnd=sp.trial_end;
                // Fix old trials that were created with elite tier
                if(sp.tier==='elite'){await _supaClient.from('profiles').update({tier:'core'}).eq('email',email)}
              }
            }
            if(sp.tier&&!sp.is_trial&&sp.tier!=='free'){user.tier=sp.tier;user.isTrial=false}
          }
        }catch(ex2){console.warn('Trial sync:',ex2)}
        U=user;if(!U.usage)U.usage={ai:0,credits:TIERS[U.tier]?.credits||0,month:new Date().getMonth()};
        localStorage.setItem('hw_session',JSON.stringify(U));
        // Restore session data from Supabase (career profile, tool history, etc.)
        loadFromSupabase(email,function(profile){
          if(profile&&profile.session_data){
            var sd=typeof profile.session_data==='string'?JSON.parse(profile.session_data):profile.session_data;
            // Supabase is source of truth — prefer its data if it has content
            if(sd.careerProfile&&sd.careerProfile.lastUpdated){
              var localDate=U.careerProfile&&U.careerProfile.lastUpdated?new Date(U.careerProfile.lastUpdated):new Date(0);
              var remoteDate=new Date(sd.careerProfile.lastUpdated);
              if(remoteDate>=localDate)U.careerProfile=sd.careerProfile;
            }
            if(sd.toolHistory&&sd.toolHistory.length>0){
              var localLen=(U.toolHistory||[]).length;
              if(sd.toolHistory.length>=localLen)U.toolHistory=sd.toolHistory;
            }
            if(sd.scoreHistory&&sd.scoreHistory.length>0){
              var localSLen=(U.scoreHistory||[]).length;
              if(sd.scoreHistory.length>=localSLen)U.scoreHistory=sd.scoreHistory;
            }
            if(sd.milestones&&sd.milestones.length>0&&(!U.milestones||sd.milestones.length>=U.milestones.length)){U.milestones=sd.milestones}
            if(sd.loginDays&&sd.loginDays.length>0){U.loginDays=sd.loginDays}
            if(sd.toolInputs){U.toolInputs=Object.assign(U.toolInputs||{},sd.toolInputs)}
            if(sd.weeklyGoals&&sd.weeklyGoals.length>0){U.weeklyGoals=sd.weeklyGoals}
            if(sd.checkins&&sd.checkins.length>0){U.checkins=sd.checkins}
            if(sd.achievements&&sd.achievements.length>0){U.achievements=sd.achievements}
            if(sd.lastCheckin){U.lastCheckin=sd.lastCheckin}
            if(sd.compIntel){U.compIntel=sd.compIntel}
            if(sd.outcomes&&sd.outcomes.length>0){U.outcomes=sd.outcomes}
            if(sd.readMsgIds&&Array.isArray(sd.readMsgIds)){_addLocalReadIdsQuiet(sd.readMsgIds)}
            localStorage.setItem('hw_session',JSON.stringify(U));
            var udb=DB.users.find(function(u){return u.id===U.id});
            if(udb){udb.careerProfile=U.careerProfile;udb.scoreHistory=U.scoreHistory;udb.toolHistory=U.toolHistory;udb.milestones=U.milestones;saveDB()}
            renderHome(); // Re-render with restored data
          }
        });
        if(!localStorage.getItem('hw_disc_'+U.id)){if(loginBtn){loginBtn.disabled=false;loginBtn.textContent=loginBtn.dataset.orig||'Sign In'}enterApp();showDisc()}else{if(loginBtn){loginBtn.disabled=false;loginBtn.textContent=loginBtn.dataset.orig||'Sign In'}enterApp()}
        return;
      }
    }catch(ex){}
  }
  // Fallback: check local DB
  const user=DB.users.find(u=>u.email.toLowerCase()===email&&u.pass===pass);
  if(!user){
    // Final fallback: check if profile exists in Supabase but auth failed
    if(_supaClient){
      try{
        var profileCheck=await _supaClient.from('profiles').select('id,name,email,tier,is_trial,trial_end,stage,specialty,goal,session_data').eq('email',email).limit(1);
        if(!profileCheck.error&&profileCheck.data&&profileCheck.data.length>0){
          var sp=profileCheck.data[0];
          // Profile exists in Supabase but auth failed — signUp likely failed during onboarding
          // Create the auth account now with whatever password they're entering
          var signUpFix=await _supaClient.auth.signUp({email:email,password:pass,options:{data:{name:sp.name||email.split('@')[0]}}}).catch(function(e){return{error:e}});
          if(signUpFix&&signUpFix.data&&!signUpFix.error){
            // Auth account created (or already existed) — try signing in
            var signInFix=await _supaClient.auth.signInWithPassword({email:email,password:pass}).catch(function(e){return{error:e}});
            if(signInFix&&!signInFix.error&&signInFix.data&&signInFix.data.session){
              var recoverUser={id:sp.id||'u'+DB.nextUserId++,name:sp.name||email.split('@')[0],email:email,pass:'__supabase__',role:sp.stage||'student',tier:sp.tier||'free',isTrial:sp.is_trial||false,trialEnd:sp.trial_end||null,institution:'',usage:{ai:0,credits:TIERS[sp.tier]?.credits||0,month:new Date().getMonth()}};
              DB.users.push(recoverUser);saveDB();
              U=recoverUser;localStorage.setItem('hw_session',JSON.stringify(U));
              if(sp.session_data){var sd=typeof sp.session_data==='string'?JSON.parse(sp.session_data):sp.session_data;if(sd.careerProfile)U.careerProfile=sd.careerProfile;if(sd.toolHistory)U.toolHistory=sd.toolHistory;if(sd.scoreHistory)U.scoreHistory=sd.scoreHistory;if(sd.milestones)U.milestones=sd.milestones;if(sd.toolInputs)U.toolInputs=sd.toolInputs;if(sd.readMsgIds&&Array.isArray(sd.readMsgIds)){_addLocalReadIdsQuiet(sd.readMsgIds)}localStorage.setItem('hw_session',JSON.stringify(U))}
              if(loginBtn){loginBtn.disabled=false;loginBtn.textContent=loginBtn.dataset.orig||'Sign In'}
              enterApp();notify('Welcome back! Your account has been recovered.');
              return;
            }
          }
          // Auth account exists with a DIFFERENT password — user forgot or mistyped
          notify('We found your account but the password doesn\'t match. Try a different password, or use "Forgot your password?" below to reset it.',1);
          if(loginBtn){loginBtn.disabled=false;loginBtn.textContent=loginBtn.dataset.orig||'Sign In'}
          return;
        }
      }catch(fbErr){console.warn('Profile fallback:',fbErr)}
    }
    notify('Invalid email or password',1);if(loginBtn){loginBtn.disabled=false;loginBtn.textContent=loginBtn.dataset.orig||'Sign In'}return
  }
  if(_supaClient){_supaClient.auth.signUp({email,password:pass,options:{data:{name:user.name}}}).catch(()=>{})}
  // Ensure admin tier
  if(email===AE.toLowerCase()&&user.tier!=='admin'){user.tier='admin';user.role='admin';saveDB()}
  U=user;if(!U.usage)U.usage={ai:0,credits:TIERS[U.tier]?.credits||0,month:new Date().getMonth()};
  localStorage.setItem('hw_session',JSON.stringify(U));
  // Try restoring session from Supabase
  loadFromSupabase(email,function(profile){
    if(profile&&profile.session_data){
      var sd=typeof profile.session_data==='string'?JSON.parse(profile.session_data):profile.session_data;
      if(sd.careerProfile&&sd.careerProfile.lastUpdated){
        var localDate=U.careerProfile&&U.careerProfile.lastUpdated?new Date(U.careerProfile.lastUpdated):new Date(0);
        var remoteDate=new Date(sd.careerProfile.lastUpdated);
        if(remoteDate>=localDate)U.careerProfile=sd.careerProfile;
      }
      if(sd.toolHistory&&sd.toolHistory.length>0){
        var localLen=(U.toolHistory||[]).length;
        if(sd.toolHistory.length>=localLen)U.toolHistory=sd.toolHistory;
      }
      if(sd.scoreHistory&&sd.scoreHistory.length>0){
        var localSLen=(U.scoreHistory||[]).length;
        if(sd.scoreHistory.length>=localSLen)U.scoreHistory=sd.scoreHistory;
      }
      if(sd.milestones&&sd.milestones.length>0&&(!U.milestones||sd.milestones.length>=U.milestones.length)){U.milestones=sd.milestones}
      if(sd.loginDays&&sd.loginDays.length>0){U.loginDays=sd.loginDays}
      if(sd.toolInputs){U.toolInputs=Object.assign(U.toolInputs||{},sd.toolInputs)}
      if(sd.weeklyGoals&&sd.weeklyGoals.length>0){U.weeklyGoals=sd.weeklyGoals}
      if(sd.checkins&&sd.checkins.length>0){U.checkins=sd.checkins}
      if(sd.achievements&&sd.achievements.length>0){U.achievements=sd.achievements}
      if(sd.lastCheckin){U.lastCheckin=sd.lastCheckin}
      if(sd.compIntel){U.compIntel=sd.compIntel}
      if(sd.outcomes&&sd.outcomes.length>0){U.outcomes=sd.outcomes}
      if(sd.readMsgIds&&Array.isArray(sd.readMsgIds)){_addLocalReadIdsQuiet(sd.readMsgIds)}
      localStorage.setItem('hw_session',JSON.stringify(U));
      var udb=DB.users.find(function(u){return u.id===U.id});
      if(udb){udb.careerProfile=U.careerProfile;udb.scoreHistory=U.scoreHistory;udb.toolHistory=U.toolHistory;udb.milestones=U.milestones;saveDB()}
      renderHome();
    }
  });
  if(!localStorage.getItem('hw_disc_'+U.id)){if(loginBtn){loginBtn.disabled=false;loginBtn.textContent=loginBtn.dataset.orig||'Sign In'}enterApp();showDisc()}else{if(loginBtn){loginBtn.disabled=false;loginBtn.textContent=loginBtn.dataset.orig||'Sign In'}enterApp()}
}

function doSignup(e){
  e.preventDefault();
  const name=document.getElementById('s-name').value.trim();
  const email=document.getElementById('s-email').value.trim().toLowerCase();
  const pass=document.getElementById('s-pass').value;
  const role=document.getElementById('s-role').value;
  const inst=document.getElementById('s-inst').value.trim();
  if(DB.users.find(u=>u.email.toLowerCase()===email)){notify('Email already registered',1);return}
  const user={id:'u'+DB.nextUserId++,name,email,pass,role,tier:'free',institution:inst,usage:{ai:0,credits:0,month:new Date().getMonth()},emailVerified:false};
  DB.users.push(user);saveDB();
  // Send verification email via Supabase
  if(_supaClient){
    _supaClient.auth.signUp({email,password:pass,options:{data:{name},emailRedirectTo:window.location.origin+window.location.pathname}}).then(function(res){
      if(res.data&&res.data.user&&!res.data.session){
        // Supabase requires email confirmation — show verification prompt
        user.emailVerified=false;saveDB();
      }else if(res.data&&res.data.session){
        // Email confirmation disabled in Supabase — mark verified
        user.emailVerified=true;saveDB();
      }
    }).catch(function(){});
  }
  U=user;localStorage.setItem('hw_session',JSON.stringify(U));
  if(loginBtn){loginBtn.disabled=false;loginBtn.textContent=loginBtn.dataset.orig||'Sign In'}enterApp();showDisc();
  // Show verification reminder
  if(!user.emailVerified){
    setTimeout(function(){notify('Check your email to verify your account',0)},2000);
  }
}

function doLogout(){
  if(_supaClient){_supaClient.auth.signOut().catch(()=>{})}
  U=null;localStorage.removeItem('hw_session');document.body.classList.remove('in-app');go('pg-landing');
}

function confirmDeleteAccount(){
  if(!U)return;
  var h='<div style="padding:24px;max-width:400px;margin:0 auto;text-align:center">';
  h+='<div style="font-size:36px;margin-bottom:12px">⚠️</div>';
  h+='<div style="font-size:18px;font-weight:600;color:var(--text);font-family:var(--font-serif);margin-bottom:8px">Delete Your Account?</div>';
  h+='<div style="font-size:13px;color:var(--text2);line-height:1.6;margin-bottom:20px">This will permanently delete your account and all associated data: career profile, tool history, saved scenarios, progress tracking, and decisions. This action cannot be undone.</div>';
  h+='<div style="font-size:11px;color:var(--text3);margin-bottom:20px">Type <strong>DELETE</strong> to confirm:</div>';
  h+='<input type="text" id="delete-confirm-input" placeholder="Type DELETE" style="width:100%;padding:10px;border:1px solid var(--border);border-radius:8px;background:var(--bg);color:var(--text);font-size:13px;text-align:center;margin-bottom:16px">';
  h+='<div style="display:flex;gap:8px">';
  h+='<button onclick="closeModal(\'modal-q\')" style="flex:1;padding:12px;background:var(--bg2);color:var(--text);border:1px solid var(--border);border-radius:8px;font-size:13px;font-weight:600;cursor:pointer">Cancel</button>';
  h+='<button onclick="executeDeleteAccount()" style="flex:1;padding:12px;background:var(--red);color:#fff;border:none;border-radius:8px;font-size:13px;font-weight:600;cursor:pointer">Delete Forever</button>';
  h+='</div></div>';
  document.getElementById('modal-q-content').innerHTML=h;
  document.getElementById('modal-q').classList.remove('hidden');
}

async function executeDeleteAccount(){
  var input=document.getElementById('delete-confirm-input');
  if(!input||input.value.trim()!=='DELETE'){notify('Type DELETE to confirm.',1);return}
  try{
    // Delete from Supabase profiles
    if(_supaClient&&U.email){
      await _supaClient.from('profiles').delete().eq('email',U.email);
      await _supaClient.from('questions').delete().eq('user_email',U.email);
      await _supaClient.from('messages').delete().eq('user_email',U.email);
    }
    // Clear local storage
    localStorage.clear();
    // Sign out
    if(_supaClient){await _supaClient.auth.signOut().catch(function(){})}
    U=null;
    closeModal('modal-q');
    notify('Account deleted. We are sorry to see you go.');
    setTimeout(function(){go('pg-landing')},1500);
  }catch(e){
    console.error('Delete account error:',e);
    notify('Error deleting account. Please contact support.',1);
  }
}

async function doForgotPassword(e){
  e.preventDefault();
  const email=document.getElementById('r-email').value.trim().toLowerCase();
  if(!_supaClient){notify('Password reset is temporarily unavailable.',1);return}
  const siteUrl=window.location.origin+window.location.pathname;
  const{error}=await _supaClient.auth.resetPasswordForEmail(email,{redirectTo:siteUrl});
  if(error){notify('Error sending reset email. Please try again.',1);return}
  document.getElementById('reset-sent').classList.remove('hidden');
  notify('Reset link sent! Check your inbox and spam/junk folder. The email comes from Supabase (noreply@mail.app.supabase.io) on behalf of HeartWise.');
}

async function doNewPassword(e){
  e.preventDefault();
  const pass=document.getElementById('rp-pass').value;
  const pass2=document.getElementById('rp-pass2').value;
  if(pass!==pass2){notify('Passwords do not match',1);return}
  if(pass.length<8){notify('Password must be at least 8 characters',1);return}
  if(!_supaClient){notify('Password reset is temporarily unavailable.',1);return}
  const{error}=await _supaClient.auth.updateUser({password:pass});
  if(error){notify('Error updating password. Link may have expired.',1);return}
  try{
    const{data:{user}}=await _supaClient.auth.getUser();
    if(user){
      const local=DB.users.find(u=>u.email.toLowerCase()===user.email.toLowerCase());
      if(local){local.pass=pass;saveDB()}
    }
  }catch(ex){}
  notify('Password updated! You can now sign in.');
  go('pg-login');
}

function enterApp(){
  go('main-app');
  document.body.classList.add('in-app');
  if(!U.usage)U.usage={ai:0,credits:TIERS[U.tier]?.credits||0,month:new Date().getMonth()};
  if(U.usage.month!==new Date().getMonth()){U.usage.ai=0;U.usage.month=new Date().getMonth()}
  // Check trial expiration
  if(U.isTrial&&U.trialEnd){
    const now=new Date();const end=new Date(U.trialEnd);
    if(now>=end){
      U.tier='free';U.isTrial=false;
      const u=DB.users.find(u=>u.id===U.id);if(u){u.tier='free';u.isTrial=false}
      saveDB();localStorage.setItem('hw_session',JSON.stringify(U));
      if(typeof _supaClient!=='undefined'&&_supaClient){
        _supaClient.from('profiles').update({tier:'free',is_trial:false}).eq('email',U.email).then(function(){});
      }
      setTimeout(function(){showTrialExpiredTeaser()},800);
    }
  }
  // Also show teaser for previously expired trial users returning
  if(!U.isTrial&&U.trialEnd&&U.tier==='free'){
    var shownKey='hw_teaser_'+U.id+'_'+new Date().toDateString();
    if(!sessionStorage.getItem(shownKey)){
      sessionStorage.setItem(shownKey,'1');
      setTimeout(function(){showTrialExpiredTeaser()},800);
    }
  }
  const b=document.getElementById('user-badge');
  const bc={free:'b-free',student:'b-student',core:'b-core',elite:'b-pro',admin:'b-admin'};
  b.className='badge '+(bc[U.tier]||'b-free');
  b.textContent=U.tier==='admin'?'MENTOR':TIERS[U.tier]?.name?.toUpperCase()||'FREE';
  var welcomeEl=document.getElementById('welcome-msg');
  if(welcomeEl)welcomeEl.textContent='Welcome, Dr. '+U.name.split(' ').pop();
  document.getElementById('nav-admin').style.display=(U.tier==='admin'||window._adminBackup)?'':'none';
  var navAsk=document.getElementById('nav-ask');if(navAsk)navAsk.style.display=(U.tier==='elite'||U.tier==='admin')?'':'none';
  var topUpgrade=document.getElementById('topbar-upgrade');
  if(topUpgrade){
    if(U.tier==='free'||U.isTrial){topUpgrade.style.display='';topUpgrade.textContent='Subscribe';topUpgrade.onclick=function(){navTo('scr-profile');showUpgrade()}}
    else if(U.tier==='student'){topUpgrade.style.display='';topUpgrade.textContent='Upgrade to Core';topUpgrade.onclick=function(){navTo('scr-profile');showUpgrade()}}
    else if(U.tier==='core'){topUpgrade.style.display='';topUpgrade.textContent='Upgrade to Mentorship';topUpgrade.onclick=function(){navTo('scr-profile');showUpgrade()}}
    else{topUpgrade.style.display='none'}
  }
  // Show leverage upsell for core users only
  // leverage-upsell removed from home screen layout
  // Check for pending plan from landing page
  const pendingPlan=sessionStorage.getItem('hw_pending_plan');
  if(pendingPlan){
    sessionStorage.removeItem('hw_pending_plan');
    setTimeout(()=>subPlan(pendingPlan),500);
  }
  // Start trial countdown if active
  if(U.isTrial&&U.trialEnd)startTrialCountdown();
  renderHome();
  navTo('scr-home');
  // Handle deep links (?tool=v14, ?page=pricing, etc.)
  _handleDeepLink();
  // Check for unread notifications
  checkNotifBadge();
  // Check achievements on app entry
  try{checkAchievements()}catch(e){console.error('Achievements:',e)}
  // Check weekly coaching reminders
  try{checkWeeklyCoaching()}catch(e){console.error('WeeklyCoaching:',e)}
  // Request notification permission (non-blocking)
  try{requestNotifPermission()}catch(e){}
  // Check for delivered assessments from Dr. Faroqui
  try{checkPendingAssessments()}catch(e){console.error('AssessmentCheck:',e)}
  // Show upgrade elements based on tier
  showUpgradeElements();
  // Start onboarding tour for new users (after a short delay for rendering)
  if(shouldShowTour())setTimeout(startTour,800);
}

// ===== UPGRADE ELEMENTS =====
function showUpgradeElements(){
  var stickyBar=document.getElementById('upgrade-sticky-bar');
  if(!stickyBar)return;

  if(U.tier==='free'){
    stickyBar.classList.remove('hidden');
    document.body.classList.add('has-upgrade-bar');
    document.getElementById('upgrade-bar-sub').textContent='Unlock unlimited career intelligence tools — from $9/mo';
  } else {
    stickyBar.classList.add('hidden');
    document.body.classList.remove('has-upgrade-bar');
  }
}

// Blur gate: wraps tool results for free users with a blurred preview + CTA overlay
function applyBlurGate(resultsEl){
  if(!U||U.tier!=='free')return false;
  if(!resultsEl||!resultsEl.innerHTML)return false;

  var content=resultsEl.innerHTML;
  resultsEl.innerHTML='<div class="hw-blur-gate">'
    +'<div class="hw-blur-content">'+content+'</div>'
    +'<div class="hw-blur-overlay">'
    +'<div class="hw-blur-icon">\ud83d\udd12</div>'
    +'<div class="hw-blur-title">Your analysis is ready</div>'
    +'<div class="hw-blur-sub">Upgrade to Core to see your full results, recommendations, and action plan.</div>'
    +'<button class="hw-blur-cta" onclick="navTo(\'scr-profile\');showUpgrade();closeModal(\'modal-q\')">Unlock Full Results \u2014 from $9/mo</button>'
    +'</div></div>';
  return true;
}

// Gate the "What to do next" / Attending Note section for trial users
// Trial users see results but must subscribe to see the action plan
// Paid users: queue the full assessment for delayed physician review delivery
var _hwAssessmentContext=null; // Set by tools before calling hwGatePathway
function hwSetAssessmentContext(toolName,toolId,keyInsights,score,outlook){
  _hwAssessmentContext={toolName:toolName,toolId:toolId,keyInsights:keyInsights||[],score:score||'',outlook:outlook||''};
}

function hwGatePathway(pathwayHtml){
  // Paid users & admins: queue for delayed delivery (except admin who sees instant)
  if(U&&U.tier&&U.tier!=='free'&&!U.isTrial){
    // Admin always sees everything instantly
    if(U.role==='admin'||U.tier==='admin')return pathwayHtml;
    
    // Paid users: show instant preview, queue full assessment
    if(_hwAssessmentContext){
      var ctx=_hwAssessmentContext;
      _hwAssessmentContext=null; // reset
      var previewHtml=hwInstantPreview(ctx.toolName,ctx.keyInsights,ctx.score,ctx.outlook);
      hwQueueAssessment(ctx.toolName,ctx.toolId,previewHtml,pathwayHtml,ctx.keyInsights?ctx.keyInsights.join(' | '):'');
      return previewHtml;
    }
    // No context set — fall through to show full (backward compat)
    return pathwayHtml;
  }
  // Free users: already gated by applyBlurGate, but in case it leaks
  if(!U||U.tier==='free')return pathwayHtml;
  // Trial users: gate the pathway
  if(U.isTrial){
    return '<div style="position:relative;margin-top:20px">'
      +'<div style="filter:blur(6px);pointer-events:none;user-select:none;opacity:.5">'+pathwayHtml+'</div>'
      +'<div style="position:absolute;inset:0;display:flex;flex-direction:column;align-items:center;justify-content:center;text-align:center;padding:24px;background:rgba(28,26,23,.85);border-radius:12px;border:1px solid rgba(198,168,94,.2)">'
      +'<div style="font-size:24px;margin-bottom:8px">\ud83d\udd13</div>'
      +'<div style="font-size:14px;font-weight:600;color:var(--accent);margin-bottom:6px">Your Action Plan Is Ready</div>'
      +'<div style="font-size:12px;color:var(--text3);line-height:1.6;margin-bottom:14px;max-width:320px">Subscribe to unlock your personalized next steps, prioritized actions, and specific recommendations.</div>'
      +'<button onclick="navTo(\'scr-profile\');showUpgrade()" style="font-size:13px;font-weight:600;padding:12px 28px;background:var(--accent);color:#1C1A17;border:none;border-radius:8px;cursor:pointer">Subscribe to Unlock \u2014 from $9/mo</button>'
      +'<div style="font-size:10px;color:var(--text3);margin-top:8px">Cancel anytime</div>'
      +'</div></div>';
  }
  return pathwayHtml;
}

// ===== PHYSICIAN REVIEW QUEUE SYSTEM =====
// Splits tool results into instant preview + delayed full assessment
// Full assessment delivered 18-24h later by Dr. Faroqui

var _pendingAssessments=[];
var _assessmentNotifShown=false;

// Generate instant preview from tool results (2-3 key insights, no Attending Note)
function hwInstantPreview(toolName,keyInsights,score,outlook){
  var h='<div style="margin-top:20px;padding:20px;background:linear-gradient(160deg,var(--bg2),rgba(200,168,124,.03));border:1px solid var(--border2);border-radius:12px">';
  h+='<div style="font-size:10px;font-weight:600;color:var(--accent);text-transform:uppercase;letter-spacing:1.2px;margin-bottom:14px">Initial Analysis</div>';
  
  // Score/outlook if available
  if(score||outlook){
    h+='<div style="display:flex;gap:12px;margin-bottom:16px;flex-wrap:wrap">';
    if(score)h+='<div style="padding:8px 14px;background:var(--bg3);border-radius:8px;font-size:13px;color:var(--text)"><span style="color:var(--text3);font-size:10px;display:block;margin-bottom:2px">Score</span><strong>'+score+'</strong></div>';
    if(outlook)h+='<div style="padding:8px 14px;background:var(--bg3);border-radius:8px;font-size:13px;color:var(--text)"><span style="color:var(--text3);font-size:10px;display:block;margin-bottom:2px">Assessment</span><strong>'+outlook+'</strong></div>';
    h+='</div>';
  }
  
  // Key insights (2-3 bullet points, human tone)
  if(keyInsights&&keyInsights.length){
    keyInsights.forEach(function(ins){
      h+='<div style="font-size:13px;color:var(--text);line-height:1.7;margin-bottom:10px;padding-left:14px;border-left:2px solid rgba(200,168,124,.25);font-family:var(--font-serif)">'+ins+'</div>';
    });
  }
  
  // Handoff message
  h+='<div style="margin-top:18px;padding:16px;background:rgba(198,168,94,.06);border:1px solid rgba(198,168,94,.15);border-radius:10px">';
  h+='<div style="display:flex;align-items:flex-start;gap:12px">';
  h+='<div style="font-size:20px;flex-shrink:0;margin-top:2px">📋</div>';
  h+='<div>';
  h+='<div style="font-size:13px;font-weight:600;color:var(--text);margin-bottom:4px">Dr. Faroqui will review your full case</div>';
  h+='<div style="font-size:12px;color:var(--text2);line-height:1.6">Your detailed assessment with personalized recommendations, action steps, and strategic guidance will be delivered within 24 hours. You\u2019ll receive an email when it\u2019s ready.</div>';
  h+='</div></div></div>';
  
  h+='</div>';
  return h;
}

// Queue the full assessment for delayed delivery
function hwQueueAssessment(toolName,toolId,previewHtml,fullPathwayHtml,keyInsightsText){
  if(!U||!U.email)return;
  
  // Save to Supabase via edge function
  fetch(SUPABASE_URL+'/functions/v1/deliver-assessment',{
    method:'POST',
    headers:{'Content-Type':'application/json','apikey':SUPABASE_KEY},
    body:JSON.stringify({
      action:'queue',
      user_email:U.email,
      user_name:U.name||'',
      tool_name:toolName,
      tool_id:toolId||'',
      preview_html:previewHtml,
      preview_text:keyInsightsText||'',
      full_html:fullPathwayHtml,
      full_text:''
    })
  }).then(function(r){return r.json()}).then(function(d){
    if(d.error)console.warn('Assessment queue error:',d.error);
    else console.log('Assessment queued, delivers at:',d.deliver_at);
  }).catch(function(e){console.warn('Assessment queue failed:',e)});
}

// (hwQueuedPathway removed — assessment queue now handled inside hwGatePathway via hwSetAssessmentContext)

// Split full tool results for paid users: show hero only, queue rest
// Call this INSTEAD of setting innerHTML directly
function hwRenderWithQueue(targetEl,fullHtml,toolName,toolId,keyInsights,score,outlook){
  var el=typeof targetEl==='string'?document.getElementById(targetEl):targetEl;
  if(!el)return;
  
  // Admin, free, trial: show everything as-is
  if(!U||U.tier==='free'||U.tier==='admin'||U.role==='admin'||U.isTrial){
    el.innerHTML=fullHtml;
    return;
  }
  
  // Paid non-admin user: split at marker
  var parts=fullHtml.split('<!-- HW_SPLIT -->');
  if(parts.length<2){
    // No split marker — show everything (backward compat)
    el.innerHTML=fullHtml;
    return;
  }
  
  var heroHtml=parts[0];
  var detailHtml=parts.slice(1).join('');
  
  // Show hero + handoff message
  var handoff='<div style="margin-top:18px;padding:20px;background:linear-gradient(160deg,var(--bg2),rgba(200,168,124,.03));border:1px solid var(--border2);border-radius:12px">';
  handoff+='<div style="display:flex;align-items:flex-start;gap:14px">';
  handoff+='<div style="font-size:28px;flex-shrink:0">📋</div>';
  handoff+='<div>';
  handoff+='<div style="font-size:14px;font-weight:600;color:var(--text);margin-bottom:6px">Dr. Faroqui is reviewing your full case</div>';
  handoff+='<div style="font-size:13px;color:var(--text2);line-height:1.7;font-family:var(--font-serif)">I\u2019ve received your information and I\u2019m putting together a detailed assessment with personalized recommendations for your situation. You\u2019ll receive an email when your full analysis is ready.</div>';
  handoff+='<div style="margin-top:12px;display:flex;align-items:center;gap:8px">';
  handoff+='<div style="width:8px;height:8px;border-radius:50%;background:var(--accent);animation:pulse 2s infinite"></div>';
  handoff+='<span style="font-size:11px;color:var(--text3)">Assessment in progress</span>';
  handoff+='</div>';
  handoff+='</div></div></div>';
  
  el.innerHTML=heroHtml+handoff;
  
  // Queue the full results for delayed delivery
  hwQueueAssessment(
    toolName||'Assessment',
    toolId||'',
    heroHtml+handoff,
    detailHtml,
    (keyInsights||[]).join(' | ')
  );
}

// Check for delivered assessments on login/page load
function checkPendingAssessments(){
  if(!U||!U.email)return;
  
  fetch(SUPABASE_URL+'/functions/v1/deliver-assessment',{
    method:'POST',
    headers:{'Content-Type':'application/json','apikey':SUPABASE_KEY},
    body:JSON.stringify({action:'check',email:U.email})
  }).then(function(r){return r.json()}).then(function(d){
    if(!d.assessments||!d.assessments.length){
      _pendingAssessments=[];
      renderMyAssessmentsCard();
      return;
    }
    _pendingAssessments=d.assessments;
    
    // Count delivered but not yet viewed
    var ready=d.assessments.filter(function(a){return a.status==='delivered'});
    if(ready.length>0&&!_assessmentNotifShown){
      _assessmentNotifShown=true;
      showAssessmentNotification(ready.length);
    }
    
    // Update profile card + badge
    renderMyAssessmentsCard();
  }).catch(function(e){console.warn('Assessment check failed:',e)});
}

// Render the "My Assessments" card on profile
function renderMyAssessmentsCard(){
  var card=document.getElementById('my-assessments-card');
  if(!card)return;
  
  var total=_pendingAssessments.length;
  var ready=_pendingAssessments.filter(function(a){return a.status==='delivered'}).length;
  var pending=_pendingAssessments.filter(function(a){return a.status==='pending'}).length;
  
  if(total===0){card.style.display='none';return}
  
  card.style.display='';
  var badge=document.getElementById('assessment-badge');
  if(badge){
    if(ready>0){badge.style.display='flex';badge.textContent=ready}
    else{badge.style.display='none'}
  }
}

// Show notification banner for delivered assessments
function showAssessmentNotification(count){
  var existing=document.getElementById('hw-assessment-notif');
  if(existing)existing.remove();
  
  var notif=document.createElement('div');
  notif.id='hw-assessment-notif';
  notif.style.cssText='position:fixed;top:0;left:0;right:0;z-index:10000;padding:14px 20px;background:linear-gradient(135deg,#1a1620,#2a2230);border-bottom:2px solid var(--accent);display:flex;align-items:center;justify-content:space-between;animation:slideDown .4s ease';
  notif.innerHTML='<div style="display:flex;align-items:center;gap:12px">'
    +'<div style="font-size:20px">📋</div>'
    +'<div><div style="font-size:13px;font-weight:600;color:var(--accent)">Assessment'+(count>1?'s':'')+' Ready</div>'
    +'<div style="font-size:12px;color:var(--text2)">Dr. Faroqui has reviewed your case'+(count>1?' ('+count+' assessments)':'')+'</div></div></div>'
    +'<div style="display:flex;gap:8px">'
    +'<button onclick="viewDeliveredAssessments()" style="padding:8px 16px;font-size:12px;font-weight:600;background:var(--accent);color:#1C1A17;border:none;border-radius:6px;cursor:pointer">View Now</button>'
    +'<button onclick="this.parentElement.parentElement.remove()" style="padding:8px 12px;font-size:12px;background:none;border:1px solid var(--border);color:var(--text3);border-radius:6px;cursor:pointer">\u2715</button>'
    +'</div>';
  document.body.appendChild(notif);
  
  setTimeout(function(){var el=document.getElementById('hw-assessment-notif');if(el)el.remove()},15000);
}

// View delivered assessments — shows in a modal
function viewDeliveredAssessments(){
  var notif=document.getElementById('hw-assessment-notif');
  if(notif)notif.remove();
  
  // Always fetch fresh data when user clicks
  if(!U||!U.email){notify('Please log in first.',1);return}
  
  // Show loading in modal immediately
  var modal=document.getElementById('modal-q');
  if(modal){
    document.getElementById('modal-q-title').textContent='Assessments from Dr. Faroqui';
    document.getElementById('modal-q-content').innerHTML='<div style="text-align:center;padding:40px;color:var(--text3)">Loading your assessments...</div>';
    modal.style.display='flex';
  }
  
  fetch(SUPABASE_URL+'/functions/v1/deliver-assessment',{
    method:'POST',
    headers:{'Content-Type':'application/json','apikey':SUPABASE_KEY},
    body:JSON.stringify({action:'check',email:U.email})
  }).then(function(r){return r.json()}).then(function(d){
    _pendingAssessments=d.assessments||[];
    
    if(!_pendingAssessments.length){
      document.getElementById('modal-q-content').innerHTML='<div style="text-align:center;padding:40px;color:var(--text3)">No assessments yet. Run a tool to get started.</div>';
      return;
    }
    
    var all=_pendingAssessments;
    var h='<div style="padding:4px 0">';
    all.forEach(function(a){
    var date=new Date(a.created_at).toLocaleDateString('en-US',{month:'short',day:'numeric'});
    var isPending=a.status==='pending';
    var isReady=a.status==='delivered';
    var isViewed=a.status==='viewed';
    
    h+='<div style="margin-bottom:16px;border:1px solid var(--border);border-radius:12px;overflow:hidden'+(isPending?';opacity:.7':'')+'">';
    h+='<div style="padding:14px 16px;background:var(--bg2);border-bottom:1px solid var(--border);display:flex;justify-content:space-between;align-items:center">';
    h+='<div><div style="font-size:13px;font-weight:600;color:var(--text)">'+a.tool_name+'</div>';
    h+='<div style="font-size:10px;color:var(--text3);margin-top:2px">Submitted '+date+'</div></div>';
    
    if(isPending){
      h+='<span style="font-size:9px;padding:3px 8px;background:rgba(198,168,94,.1);color:var(--accent);border-radius:4px;font-weight:600">IN REVIEW</span>';
    }else if(isReady){
      h+='<span style="font-size:9px;padding:3px 8px;background:rgba(106,191,75,.1);color:#6abf4b;border-radius:4px;font-weight:600">NEW</span>';
    }else{
      h+='<span style="font-size:9px;padding:3px 8px;background:var(--bg3);color:var(--text3);border-radius:4px;font-weight:600">REVIEWED</span>';
    }
    h+='</div>';
    
    if(isPending){
      h+='<div style="padding:16px;text-align:center;color:var(--text3);font-size:12px"><div style="display:flex;align-items:center;justify-content:center;gap:8px"><div style="width:8px;height:8px;border-radius:50%;background:var(--accent);animation:pulse 2s infinite"></div>Dr. Faroqui is reviewing your case</div></div>';
    }else{
      h+='<div style="padding:16px">'+a.full_html+'</div>';
      
      // Mark as viewed
      if(isReady){
        fetch(SUPABASE_URL+'/functions/v1/deliver-assessment',{
          method:'POST',
          headers:{'Content-Type':'application/json','apikey':SUPABASE_KEY},
          body:JSON.stringify({action:'viewed',assessment_id:a.id})
        }).catch(function(){});
        a.status='viewed';
      }
    }
    h+='</div>';
  });
  h+='</div>';
  
    document.getElementById('modal-q-content').innerHTML=h;
    renderMyAssessmentsCard();
    _assessmentNotifShown=false;
  }).catch(function(e){
    document.getElementById('modal-q-content').innerHTML='<div style="text-align:center;padding:40px;color:var(--red)">Failed to load assessments. Please try again.</div>';
  });
}

// Admin: Render assessments queue tab
var _admAssessments=null;
function admRenderAssessments(c){
  var h='<div style="font-size:14px;font-weight:600;color:var(--text);margin-bottom:12px">Physician Review Queue</div>';
  h+='<div id="adm-assessments-list"><div style="text-align:center;padding:20px;color:var(--text3)">Loading...</div></div>';
  c.innerHTML=h;
  
  fetch(SUPABASE_URL+'/functions/v1/deliver-assessment',{
    method:'POST',
    headers:{'Content-Type':'application/json','apikey':SUPABASE_KEY},
    body:JSON.stringify({action:'list',admin_email:U.email})
  }).then(function(r){return r.json()}).then(function(d){
    var list=document.getElementById('adm-assessments-list');
    if(!list)return;
    _admAssessments=d.assessments||[];
    if(!_admAssessments.length){
      list.innerHTML='<div class="adm-card" style="text-align:center;color:var(--text3)">No assessments in queue</div>';
      return;
    }
    
    var ah='';
    var pending=_admAssessments.filter(function(a){return a.status==='pending'});
    var delivered=_admAssessments.filter(function(a){return a.status==='delivered'||a.status==='viewed'});
    
    if(pending.length){
      ah+='<div style="font-size:12px;font-weight:600;color:var(--accent);margin-bottom:8px">Awaiting Delivery ('+pending.length+')</div>';
      pending.forEach(function(a,i){
        var created=new Date(a.created_at).toLocaleString('en-US',{month:'short',day:'numeric',hour:'numeric',minute:'2-digit'});
        var deliverAt=new Date(a.deliver_at).toLocaleString('en-US',{month:'short',day:'numeric',hour:'numeric',minute:'2-digit'});
        var timeLeft=Math.max(0,Math.round((new Date(a.deliver_at)-new Date())/(1000*60*60)));
        ah+='<div class="adm-card" style="border-left:3px solid var(--accent)">';
        ah+='<div style="display:flex;justify-content:space-between;align-items:flex-start;margin-bottom:8px">';
        ah+='<div><div style="font-size:13px;font-weight:600;color:var(--text)">'+a.tool_name+'</div>';
        ah+='<div style="font-size:11px;color:var(--text3)">'+(a.user_name||a.user_email)+'</div></div>';
        ah+='<div style="text-align:right"><div style="font-size:10px;color:var(--text3)">Submitted '+created+'</div>';
        ah+='<div style="font-size:10px;color:var(--accent)">Auto-delivers '+deliverAt+' (~'+timeLeft+'h)</div></div></div>';
        
        // Inline preview toggle
        ah+='<div id="adm-preview-'+i+'" style="display:none;margin:8px 0;padding:12px;background:var(--bg);border:1px solid var(--border);border-radius:8px;max-height:400px;overflow-y:auto;font-size:12px">';
        ah+='<div style="margin-bottom:12px"><div style="font-size:10px;font-weight:600;color:var(--accent);text-transform:uppercase;margin-bottom:6px">What User Sees Now</div>'+( a.preview_html||'<em>No preview</em>')+'</div>';
        ah+='<div style="border-top:2px solid var(--accent);padding-top:12px"><div style="font-size:10px;font-weight:600;color:var(--green);text-transform:uppercase;margin-bottom:6px">Full Assessment (will be delivered)</div>'+(a.full_html||'<em>No content</em>')+'</div>';
        ah+='</div>';
        
        ah+='<div style="display:flex;gap:8px">';
        ah+='<button onclick="admDeliverAssessment(\''+a.id+'\')" style="padding:6px 14px;font-size:11px;font-weight:600;background:var(--accent);color:#1C1A17;border:none;border-radius:6px;cursor:pointer">Deliver Now</button>';
        ah+='<button onclick="var p=document.getElementById(\'adm-preview-'+i+'\');p.style.display=p.style.display===\'none\'?\'\':\'none\'" style="padding:6px 14px;font-size:11px;background:none;border:1px solid var(--border);color:var(--text2);border-radius:6px;cursor:pointer">Preview</button>';
        ah+='</div></div>';
      });
    }
    
    if(delivered.length){
      ah+='<div style="font-size:12px;font-weight:600;color:var(--green);margin:16px 0 8px">Delivered ('+delivered.length+')</div>';
      delivered.forEach(function(a){
        var deliveredDate=a.delivered_at?new Date(a.delivered_at).toLocaleString('en-US',{month:'short',day:'numeric',hour:'numeric',minute:'2-digit'}):'\u2014';
        ah+='<div class="adm-card" style="border-left:3px solid var(--green);opacity:.7">';
        ah+='<div style="display:flex;justify-content:space-between;align-items:center">';
        ah+='<div><span style="font-size:12px;color:var(--text)">'+a.tool_name+'</span> <span style="font-size:11px;color:var(--text3)">\u2014 '+(a.user_name||a.user_email)+'</span></div>';
        ah+='<div style="font-size:10px;color:var(--text3)">'+deliveredDate+(a.admin_delivered?' (manual)':' (auto)')+(a.status==='viewed'?' \u00b7 <span style="color:var(--green)">Viewed</span>':'')+'</div>';
        ah+='</div></div>';
      });
    }
    
    list.innerHTML=ah;
  }).catch(function(e){
    var list=document.getElementById('adm-assessments-list');
    if(list)list.innerHTML='<div class="adm-card" style="color:var(--red)">Failed to load: '+e.message+'</div>';
  });
}

// Admin: deliver assessment manually
function admDeliverAssessment(assessmentId){
  if(!confirm('Deliver this assessment to the user now? They will receive an email.'))return;
  
  fetch(SUPABASE_URL+'/functions/v1/deliver-assessment',{
    method:'POST',
    headers:{'Content-Type':'application/json','apikey':SUPABASE_KEY},
    body:JSON.stringify({action:'deliver',assessment_id:assessmentId,admin_email:U.email})
  }).then(function(r){return r.json()}).then(function(d){
    if(d.error){notify('Error: '+d.error,1);return}
    notify('Assessment delivered! User will receive an email. \u2705');
    admRenderAssessments(document.getElementById('admin-content'));
  }).catch(function(e){notify('Delivery failed: '+e.message,1)});
}

