// ===== DYNAMIC ENGAGEMENT SECTIONS =====

// 1. This Week's Focus — single personalized action item
function renderWeeklyFocus(){
  var el=document.getElementById('weekly-focus');
  if(!el||!U)return;
  var cp=U.careerProfile||{};
  var stage=cp.stage||'student';
  var goal=cp.goal||'';
  var toolsUsed=(U.toolHistory||[]).map(function(t){return t.tool});

  var focus=null;
  var now=new Date();
  var month=now.getMonth(); // 0-indexed

  // Stage + goal based focus
  if(stage==='student'||stage==='applicant'||stage==='resident'){
    if(goal==='match'||goal==='fellowship'){
      if(month>=4&&month<=6&&toolsUsed.indexOf('Match Probability Calculator')<0)
        focus={icon:'🏆',title:'Run the Match Probability Calculator',sub:'ERAS opens soon. Know exactly where you stand before you apply.',tool:'v14',urgency:'high'};
      else if(toolsUsed.indexOf('Research Impact Calculator')<0)
        focus={icon:'🔬',title:'Calculate your Research Impact',sub:'Find out which research activities will move the needle most for your application.',tool:'v7',urgency:'medium'};
      else if(toolsUsed.indexOf('Interview Practice Tool')<0)
        focus={icon:'🎤',title:'Practice with the Interview Practice Tool',sub:'Most applicants walk into interviews cold. Don\'t be one of them.',tool:'v16',urgency:'medium'};
      else
        focus={icon:'📊',title:'Update your career profile',sub:'Your scores may have changed — new pubs, rotations, or letters can shift your competitiveness.',action:'profile',urgency:'low'};
    } else if(goal==='specialty'){
      if(toolsUsed.indexOf('Specialty Fit Assessment')<0)
        focus={icon:'🧬',title:'Take the Specialty Fit Assessment',sub:'Data-driven specialty matching based on your personality, priorities, and lifestyle goals.',tool:'v13',urgency:'high'};
      else
        focus={icon:'🔮',title:'Compare financial trajectories by specialty',sub:'See how your specialty choice impacts lifetime earnings and net worth.',tool:'v11',urgency:'medium'};
    }
  } else if(stage==='fellow'){
    if(toolsUsed.indexOf('Contract Review Tool')<0)
      focus={icon:'📝',title:'Score your upcoming contract offer',sub:'You\'re approaching job offers. Know if the terms are competitive before you sign.',tool:'v12',urgency:'high'};
    else if(toolsUsed.indexOf('Financial Planner')<0)
      focus={icon:'💰',title:'Model your 30-year financial trajectory',sub:'Training is almost over. See how different paths impact your long-term wealth.',tool:'v11',urgency:'medium'};
  } else if(stage==='attending'){
    if(toolsUsed.indexOf('Contract Review Tool')<0)
      focus={icon:'📝',title:'Analyze your current contract',sub:'Most physicians leave $50K+ on the table. Find out if you\'re one of them.',tool:'v12',urgency:'high'};
    else if(goal==='direction')
      focus={icon:'⚡',title:'Run the Specialty & Career Fit tool',sub:'Explore whether a change makes sense — with data, not just gut feeling.',tool:'v13',urgency:'medium'};
    else
      focus={icon:'💰',title:'Update your financial trajectory',sub:'Market conditions change. Re-run your projections with current data.',tool:'v11',urgency:'low'};
  }

  // Nudge to complete profile if stage/goal missing
  if(!stage||stage==='student'&&!goal){
    if(!focus) focus={icon:'📊',title:'Complete your career profile',sub:'The more you tell us, the better your experience. Set your stage, specialty, and goals to unlock personalized deadlines, weekly focus, and smarter tool recommendations.',action:'profile',urgency:'high'};
  }

  // Fallback
  if(!focus){
    var unused=VAULT_ITEMS.filter(function(v){return toolsUsed.indexOf(v.title)<0});
    if(unused.length>0){
      var pick=unused[0];
      focus={icon:pick.icon,title:'Try: '+pick.title,sub:pick.desc,tool:pick.id,urgency:'medium'};
    }
  }

  if(!focus){el.style.display='none';return}

  var urgColor=focus.urgency==='high'?'#ef4444':focus.urgency==='medium'?'var(--accent)':'var(--text3)';
  var urgLabel=focus.urgency==='high'?'⚡ Do this now':focus.urgency==='medium'?'📌 This week':'💡 When you have time';
  var onclick=focus.tool?'openFramework(\''+focus.tool+'\')':focus.action==='profile'?'showUpdateProfile()':'';

  el.style.display='';
  el.innerHTML='<div onclick="'+onclick+'" style="padding:18px;background:linear-gradient(160deg,rgba(198,168,94,.08),rgba(200,168,124,.02));border:1.5px solid rgba(198,168,94,.20);border-radius:12px;cursor:pointer;transition:border-color .2s">'
    +'<div style="display:flex;align-items:center;gap:6px;margin-bottom:8px"><span style="font-size:10px;font-weight:700;color:'+urgColor+';text-transform:uppercase;letter-spacing:1px">'+urgLabel+'</span></div>'
    +'<div style="display:flex;align-items:flex-start;gap:12px">'
    +'<span style="font-size:28px;flex-shrink:0">'+focus.icon+'</span>'
    +'<div><div style="font-size:15px;font-weight:700;color:var(--text);margin-bottom:4px;font-family:var(--font-serif)">'+focus.title+'</div>'
    +'<div style="font-size:12px;color:var(--text3);line-height:1.5">'+focus.sub+'</div></div>'
    +'</div></div>';
}

// 2. Tool Progress Tracker
function renderToolProgress(){
  var el=document.getElementById('tool-progress');
  if(!el||!U)return;
  if(U.tier==='free'&&!U.isTrial){el.style.display='none';return}
  var cp=U.careerProfile||{};

  var toolsUsed=[];
  (U.toolHistory||[]).forEach(function(t){
    if(toolsUsed.indexOf(t.tool)<0) toolsUsed.push(t.tool);
  });
  var total=VAULT_ITEMS.length;
  var used=0;
  var nextTool=null;
  VAULT_ITEMS.forEach(function(v){
    var found=toolsUsed.some(function(t){return t===v.title});
    if(found) used++;
    else if(!nextTool) nextTool=v;
  });

  if(used===0){
    el.style.display='';
    var h='<div style="background:#fff;border:1px solid #E8E1D8;border-radius:14px;padding:16px;box-shadow:0 2px 6px rgba(0,0,0,.04)">';
    h+='<div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:8px">';
    h+='<span style="font-size:11px;font-weight:600;color:#C6A85E;text-transform:uppercase;letter-spacing:1px">🧭 Tool Progress</span>';
    h+='<span style="display:flex;align-items:center;gap:8px"><span style="font-size:12px;font-weight:700;color:#8A8278">0 / '+total+'</span><span onclick="navTo(\'scr-vault\')" style="font-size:10px;color:#C6A85E;font-weight:600;cursor:pointer;text-decoration:underline">Career Tools →</span></span>';
    h+='</div>';
    h+='<div style="height:8px;background:#EAE6E0;border-radius:4px;overflow:hidden;margin-bottom:10px"><div style="height:100%;width:0%;background:linear-gradient(90deg,#C6A85E,#B89543);border-radius:4px"></div></div>';
    h+='<div style="font-size:12px;color:#5C564F;line-height:1.5;margin-bottom:8px">You haven\'t used any tools yet. <strong>The more tools you run, the sharper your strategy gets.</strong> Each one builds on the last.</div>';
    if(!cp.stage||!cp.goal) h+='<div style="font-size:11px;color:#C6A85E;font-weight:500">💡 Tip: <span onclick="showUpdateProfile()" style="cursor:pointer;text-decoration:underline">Complete your profile</span> first — we\'ll recommend the right tools for your stage.</div>';
    h+='</div>';
    el.innerHTML=h;
    return;
  }

  var pct=Math.round(used/total*100);
  el.style.display='';
  var h='<div style="background:#fff;border:1px solid #E8E1D8;border-radius:14px;padding:16px;box-shadow:0 2px 6px rgba(0,0,0,.04)">';
  h+='<div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:8px">';
  h+='<span style="font-size:11px;font-weight:600;color:#C6A85E;text-transform:uppercase;letter-spacing:1px">🧭 Tool Progress</span>';
  h+='<span style="display:flex;align-items:center;gap:8px"><span style="font-size:12px;font-weight:700;color:#C6A85E">'+used+' / '+total+'</span><span onclick="navTo(\'scr-vault\')" style="font-size:10px;color:#C6A85E;font-weight:600;cursor:pointer;text-decoration:underline">Career Tools →</span></span>';
  h+='</div>';
  h+='<div style="height:8px;background:#EAE6E0;border-radius:4px;overflow:hidden;margin-bottom:10px"><div style="height:100%;width:'+pct+'%;background:linear-gradient(90deg,#C6A85E,#B89543);border-radius:4px;transition:width .5s"></div></div>';
  if(nextTool){
    h+='<div onclick="openFramework(\''+nextTool.id+'\')" style="display:flex;align-items:center;gap:10px;padding:10px;background:#F8F5F0;border-radius:10px;cursor:pointer;transition:background .2s">';
    h+='<span style="font-size:16px">'+nextTool.icon+'</span>';
    h+='<div style="flex:1"><div style="font-size:12px;font-weight:600;color:#1C1A17">Next: '+nextTool.title+'</div>';
    h+='<div style="font-size:10px;color:#8A8278">'+nextTool.desc.substring(0,60)+'…</div></div>';
    h+='<span style="font-size:12px;color:#C6A85E">→</span></div>';
  }
  h+=renderCommunitySignal();
  h+='</div>';
  el.innerHTML=h;
}

// 3. Upcoming Deadlines
function renderUpcomingDeadlines(){
  var el=document.getElementById('upcoming-deadlines');
  if(!el||!U)return;
  var cp=U.careerProfile||{};
  var stage=cp.stage||'student';
  var now=new Date();
  var month=now.getMonth();
  var year=now.getFullYear();

  var deadlines=[];
  // Universal deadlines based on academic calendar
  if(stage==='student'||stage==='applicant'||stage==='resident'){
    if(month<=5) deadlines.push({date:'Jul '+year,label:'ERAS Opens — fellowship/residency applications',icon:'📋',months:6-month});
    if(month<=7) deadlines.push({date:'Sep '+year,label:'ERAS Submission Window — submit Day 1',icon:'🚀',months:8-month});
    if(month>=8||month<=1) deadlines.push({date:'Mar '+(month>=8?year+1:year),label:'Match Day',icon:'🎉',months:month>=8?(14-month):(2-month)});
    if(month<=3) deadlines.push({date:'Apr '+year,label:'SOAP / Scramble period',icon:'⚡',months:3-month});
  }
  if(stage==='student'||stage==='applicant'){
    if(month<=5) deadlines.push({date:'Jun-Aug '+year,label:'Away rotation application period',icon:'🏥',months:Math.max(0,5-month)});
  }
  if(stage==='fellow'||stage==='attending'){
    if(month<=2||month>=10) deadlines.push({date:'Jan-Mar '+(month>=10?year+1:year),label:'Peak contract negotiation season',icon:'📝',months:month>=10?(12-month+2):(2-month)});
  }

  // Filter to upcoming only (next 6 months)
  deadlines=deadlines.filter(function(d){return d.months>=0&&d.months<=6});
  deadlines.sort(function(a,b){return a.months-b.months});

  if(deadlines.length===0){
    // If no deadlines because profile is incomplete, prompt
    if(!cp.stage){
      el.style.display='';
      el.innerHTML='<div class="card" style="padding:14px;cursor:pointer" onclick="showUpdateProfile()">'
        +'<div style="font-size:11px;font-weight:600;color:var(--accent);text-transform:uppercase;letter-spacing:1px;margin-bottom:6px">📅 Upcoming Deadlines</div>'
        +'<div style="font-size:12px;color:var(--text3);line-height:1.5">Set your training stage to see personalized deadlines — ERAS, Match Day, contract season, and more.</div>'
        +'<div style="font-size:11px;color:var(--accent);margin-top:6px;font-weight:500">Update Profile →</div>'
        +'</div>';
    } else {
      el.style.display='none';
    }
    return;
  }

  el.style.display='';
  var h='<div class="card" style="padding:16px">';
  h+='<div style="font-size:11px;font-weight:600;color:var(--accent);text-transform:uppercase;letter-spacing:1px;margin-bottom:10px">📅 Upcoming Deadlines</div>';
  deadlines.forEach(function(d,i){
    var urgColor=d.months<=1?'var(--red)':d.months<=3?'var(--accent)':'var(--text3)';
    var timeLabel=d.months===0?'This month':d.months===1?'Next month':'In '+d.months+' months';
    h+='<div style="display:flex;align-items:center;gap:10px;padding:8px 0;'+(i<deadlines.length-1?'border-bottom:1px solid var(--border)':'')+'">';
    h+='<span style="font-size:16px">'+d.icon+'</span>';
    h+='<div style="flex:1"><div style="font-size:12px;color:var(--text)">'+d.label+'</div>';
    h+='<div style="font-size:10px;color:var(--text3)">'+d.date+'</div></div>';
    h+='<span style="font-size:10px;font-weight:600;color:'+urgColor+';white-space:nowrap">'+timeLabel+'</span>';
    h+='</div>';
  });
  h+='</div>';
  el.innerHTML=h;
}

