  lorStrats.push({step:'Contribute to Their Research',detail:'Ask to help with an ongoing project \u2014 even chart reviews or data entry. Co-authoring with a nationally known faculty member creates a strong bond AND adds to your CV.',icon:'\ud83d\udd2c'});
