    sec+='<div style="flex:1;min-width:70px;padding:10px;background:var(--bg2);border-radius:8px"><div style="font-size:9px;color:var(--text3);margin-bottom:2px">Match Odds</div><div style="font-size:11px;color:var(--text3)">'+matchProb+'%</div><div style="font-size:16px;font-weight:700;color:'+combColor+'">'+comb.matchProb+'%</div>'+(comb.matchDelta>0?'<div style="font-size:10px;color:#6abf4b;font-weight:600">+'+comb.matchDelta+'%</div>':'')+'</div>';
    sec+='<div style="flex:1;min-width:70px;padding:10px;background:var(--bg2);border-radius:8px"><div style="font-size:9px;color:var(--text3);margin-bottom:2px">Outlook</div><div style="font-size:11px;color:var(--text3)">'+outlook+'</div><div style="font-size:13px;font-weight:700;color:'+combColor+'">'+comb.outlook+'</div></div>';
    sec+='<div style="flex:1;min-width:70px;padding:10px;background:var(--bg2);border-radius:8px"><div style="font-size:9px;color:var(--text3);margin-bottom:2px">Timeline</div><div style="font-size:16px;font-weight:700;color:var(--accent)">~'+Math.ceil(comb.timeMonths)+'</div><div style="font-size:10px;color:var(--text3)">months</div></div>';
