    h+='<select id="csb-comp-sat" '+sel+'><option value="">Select...</option>';
    h+='<option value="under">Significantly underpaid for my market</option><option value="below">Somewhat below market</option><option value="fair">Fair — at or near market rate</option><option value="above">Above market — compensation is not the issue</option></select></div>';

    h+='<div '+sec+'><div style="margin-bottom:6px"><strong>What\'s driving this change?</strong></div>';
    h+='<select id="csb-concern" '+sel+'><option value="">Select...</option>';
