function openFramework(id){
  // Merged tool redirects: v1→v14, v2→v12
  if(id==='v1')id='v14';
  if(id==='v2')id='v12';
  if(id==='v3')id='v12';
  if(id==='v5')id='v11';
  if(id==='v6')id='v15';
  if(id==='v8')id='v11';
  if(id==='v10')id='v13';
  if(id==='v18')id='v14';
  // Trial access gating
  if(U&&U.isTrial&&U.tier!=='admin'){
    var access=getTrialAccess(id);
    if(access==='locked'){showTrialLockedOverlay(id);return}
  }
  const content=VAULT_CONTENT[id];
  if(!content){notify('Framework content loading...',1);return}
  // Save current tool state before switching
  if(_lastToolId&&_lastToolId!==id){
    _saveToolState(_lastToolId);
  }
  // Try to restore cached state if going back to a previously opened tool
  var restored=false;
  if(_toolStateCache[id]){
    restored=_restoreToolState(id);
    delete _toolStateCache[id]; // Clear after restoring so it's fresh next time
  }
  if(!restored){
    document.getElementById('modal-q-content').innerHTML=content;
  }
  document.getElementById('modal-q').classList.remove('hidden');
  // Track tool navigation for back button
  if(_lastToolId&&_lastToolId!==id){
    var prevId=_lastToolId;
    var backBtn=document.createElement('div');
    backBtn.id='tool-back-btn';
    backBtn.innerHTML='<button onclick="openFramework(\''+prevId+'\')" style="display:inline-flex;align-items:center;gap:6px;padding:8px 14px;background:var(--bg3);border:1px solid var(--border);border-radius:8px;font-size:12px;color:var(--text2);cursor:pointer;margin-bottom:12px">← Back to previous tool</button>';
    var contentEl=document.getElementById('modal-q-content');
    if(contentEl&&contentEl.firstChild)contentEl.insertBefore(backBtn,contentEl.firstChild);
  }
  _lastToolId=id;
  // Scroll modal to top
  var modalInner=document.querySelector('#modal-q .modal');
  if(modalInner)modalInner.scrollTop=0;
  if(id==='v1')setTimeout(function(){frcUpdate();_frcRestoreCoachingState()},50);
  if(id==='v4')setTimeout(function(){rvuModelChange();rvuUpdate()},50);
  if(id==='v7')setTimeout(roiUpdate,50);
  if(id==='v11')setTimeout(ftInit,50);
  if(id==='v12')setTimeout(ciInit,50);
  if(id==='v16')setTimeout(misInit,50);
  if(id==='v17')setTimeout(obsInit,50);
  // Auto-fill tool intakes from career baseline
  setTimeout(function(){autoFillToolFromProfile(id)},60);
  // Inject partial-access banner for trial users
  if(U&&U.isTrial&&U.tier!=='admin'&&getTrialAccess(id)==='partial'){
    injectPartialOverlay(id);
  }
}

// Auto-fill tool inputs from the user's saved career baseline profile
function autoFillToolFromProfile(toolId){
  if(!U||!U.careerProfile)return;
  var cp=U.careerProfile;
  var ti=U.toolInputs||{}; // Also pull from cross-tool captured inputs
  function setVal(elId,val){var el=document.getElementById(elId);if(el&&!el.value&&val){el.value=val}}
  // Specialty alias map — profile free-text → possible select values
  var _specAlias={
    'cardiology':['cardiology','cards','gc','im','interventional','ic'],
    'interventional cardiology':['ic','interventional','cardiology','cards'],
    'electrophysiology':['ep','electrophys','electrophysiology'],
    'gastroenterology':['gi','gastroenterology'],
    'pulmonology':['pulm','pulm_crit','pulmonology'],
    'hematology':['hemonc','hematology'],
    'oncology':['hemonc','oncology'],
    'rheumatology':['rheum','rheumatology'],
    'endocrinology':['endo','endocrinology'],
    'nephrology':['neph','nephrology'],
    'infectious disease':['id','infectious'],
    'dermatology':['derm','dermatology'],
    'radiology':['rad','rads','radiology'],
    'anesthesiology':['anes','anesthesiology'],
    'emergency medicine':['em','er','emergency'],
    'family medicine':['fm','family'],
    'internal medicine':['im','internal'],
    'psychiatry':['psych','psychiatry'],
    'neurology':['neuro','neurology'],
    'surgery':['gen_surg','surgery'],
    'orthopedics':['ortho','orthopedic'],
    'urology':['uro','urology'],
    'pediatrics':['peds','pediatrics'],
    'pathology':['path','pathology'],
    'ophthalmology':['ophtho','ophthalmology'],
    'neurosurgery':['nsurg','neurosurgery'],
    'ob/gyn':['obgyn'],
    'obgyn':['obgyn'],
    'pm&r':['pm_r','pmr'],
    'ent':['ent'],
    'obesity medicine':['obesity','obesity_med'],
    'obesity':['obesity','obesity_med']
  };
  function setSelect(elId,val){
    var el=document.getElementById(elId);if(!el||!val)return;
    // Skip if user has already manually selected a non-default value
    if(el.value&&el.value!==''&&el.selectedIndex>0)return;
    var opts=el.options;
    var valStr=String(val).toLowerCase().trim();
    // Pass 1: exact match on value or text
    for(var i=0;i<opts.length;i++){
      if(opts[i].value===val||opts[i].value===valStr||opts[i].text.toLowerCase()===valStr){el.value=opts[i].value;return}
    }
    // Pass 2: check aliases
    var aliases=_specAlias[valStr]||[];
    for(var i=0;i<opts.length;i++){
      if(aliases.indexOf(opts[i].value)>=0){el.value=opts[i].value;return}
    }
    // Pass 3: partial text match (e.g. "cardiology" matches "General Cardiology")
    for(var i=0;i<opts.length;i++){
      if(opts[i].text.toLowerCase().indexOf(valStr)>=0||valStr.indexOf(opts[i].text.toLowerCase())>=0){el.value=opts[i].value;return}
    }
    // Pass 4: partial value match
    for(var i=0;i<opts.length;i++){
      if(opts[i].value&&(opts[i].value.indexOf(valStr)>=0||valStr.indexOf(opts[i].value)>=0)){el.value=opts[i].value;return}
    }
  }
  function setRange(elId,mapping){
    // mapping: {fieldName: rangeValue}
    var el=document.getElementById(elId);if(!el)return;
    for(var key in mapping){
      if(cp[key]!==undefined&&cp[key]!==''&&cp[key]!==null){
        var v=parseInt(cp[key]);if(!isNaN(v)){el.value=Math.min(mapping[key](v),parseInt(el.max)||5);return}
      }
    }
  }

  // Match Competitiveness Calculator (v14) — residency + fellowship fields
  if(toolId==='v14'){
    setSelect('mcc-spec',cp.specialty);
    setVal('mcc-step2',cp.step2);
    setVal('mcc-programs',cp.programs);
    if(cp.step1)setVal('mcc-step2',cp.step2); // step2 is the key score
    if(cp.step3)setSelect('mcc-step3',cp.step3);
    // Publications mapping — select values are 0,1,2,3,4 (tiers)
    var pubs=parseInt(cp.pubs)||0;
    if(pubs===0)setSelect('mcc-pubs','0');
    else if(pubs<=2)setSelect('mcc-pubs','1');
    else if(pubs<=5)setSelect('mcc-pubs','2');
    else if(pubs<=10)setSelect('mcc-pubs','3');
    else setSelect('mcc-pubs','4');
    // LORs mapping — select values: avg, strong, notable
    if(cp.lorStrength==='strong')setSelect('mcc-lors','strong');
    else if(cp.lorStrength==='moderate')setSelect('mcc-lors','avg');
    else if(cp.lorStrength==='weak')setSelect('mcc-lors','avg');
    // Leadership — select values: none, some, significant
    var lead=parseInt(cp.leadership)||0;
    if(lead===0)setSelect('mcc-leadership','none');
    else if(lead<=2)setSelect('mcc-leadership','some');
    else setSelect('mcc-leadership','significant');
    // Aways — select values are 0,1,2,3
    var aways=parseInt(cp.aways)||0;
    if(aways===0)setSelect('mcc-aways','0');
    else if(aways===1)setSelect('mcc-aways','1');
    else if(aways===2)setSelect('mcc-aways','2');
    else setSelect('mcc-aways','3');
    // AOA/Honors — select values: aoa, honors, pass
    if(cp.honors==='aoa'||cp.honors==='both')setSelect('mcc-aoa','aoa');
    else if(cp.honors==='ghhs')setSelect('mcc-aoa','honors');
    else if(cp.honors==='none')setSelect('mcc-aoa','pass');
    // School type (IMG detection)
    if(ti.img)setSelect('mcc-school',ti.img);
    // Fellowship-specific fields
    setSelect('mcc-fel-spec',cp.specialty||cp.fellowship);
    if(cp.firstauthor)setVal('mcc-fel-firstauthor',cp.firstauthor);
    if(cp.pgy){
      var resYearMap={PGY1:'1',PGY2:'2',PGY3:'3',PGY4:'4',PGY5:'5'};
      if(resYearMap[cp.pgy])setSelect('mcc-fel-resyear',resYearMap[cp.pgy]);
    }
  }

  // Contract Risk Scanner (v2) — comp model, non-compete, practice
  if(toolId==='v2'){
    if(cp.comp){var compNum=String(cp.comp).replace(/[^0-9]/g,'');if(parseInt(compNum)>10000)setVal('crs-comp-base',compNum)}
    if(cp.noncompete==='yes'){setSelect('crs-nc-term','yes')}
    if(cp.practice)setSelect('crs-scope',cp.practice);
  }

  // Fellowship Readiness Calculator (v1) — sliders from profile data
  if(toolId==='v1'){
    var pubVal=parseInt(cp.pubs)||0;
    var r1=document.getElementById('frc-r1');
    if(r1){
      if(pubVal>=5)r1.value=5;else if(pubVal>=4)r1.value=4;else if(pubVal>=2)r1.value=3;else if(pubVal>=1)r1.value=2;else r1.value=0;
    }
    var lorMap={strong:4,moderate:3,weak:1};
    var r2=document.getElementById('frc-r2');if(r2&&cp.lorStrength)r2.value=lorMap[cp.lorStrength]||0;
    var leadVal=parseInt(cp.leadership)||0;
    var r5=document.getElementById('frc-r5');
    if(r5){if(leadVal>=4)r5.value=5;else if(leadVal>=2)r5.value=4;else if(leadVal>=1)r5.value=3;else r5.value=0}
    var awayVal=parseInt(cp.aways)||0;
    var r6=document.getElementById('frc-r6');
    if(r6){if(awayVal>=2)r6.value=4;else if(awayVal>=1)r6.value=3;else r6.value=0}
    setTimeout(frcUpdate,10);
  }

  // Financial Planner (v11) — specialty
  if(toolId==='v11'){
    setSelect('ft-spec1',cp.specialty);
    if(cp.practice)setSelect('ft-setting1',cp.practice);
    if(cp.stage){
      var stageMap={student:'student',resident:'resident',fellow:'fellow',attending:'attending'};
      setSelect('ft-stage1',stageMap[cp.stage]||'');
    }
  }

  // Contract Review Tool (v12) — specialty and comp
  if(toolId==='v12'){
    setSelect('ci-spec',cp.specialty);
    if(cp.comp){var compNum=String(cp.comp).replace(/[^0-9]/g,'');var compK=Math.round(parseInt(compNum)/1000);if(compK>10)setVal('ci-salary',compK)}
  }

  // RVU Compensation Modeler (v4) — specialty
  if(toolId==='v4'){
    setSelect('rvu-spec',ti.specialty||cp.specialty);
  }

  // Career Roadmap (v15) — stage, specialty, research
  if(toolId==='v15'){
    setSelect('csb-spec',ti.specialty||cp.specialty);
    if(cp.stage){
      var csbStage={student:'ms1',MS1:'ms1',MS2:'ms2',MS3:'ms3',MS4:'ms3',resident:'resident',PGY1:'intern',PGY2:'resident',PGY3:'resident',PGY4:'senior',fellow:'fellow',attending:'attending'};
      setSelect('csb-stage',csbStage[cp.pgy]||csbStage[cp.stage]||'');
    }
    if(ti.firstAuthor!==undefined)setVal('csb-first-auth',ti.firstAuthor);
    if(cp.pubs)setVal('csb-pubs',cp.pubs);
    if(cp.lorStrength)setSelect('csb-lors',cp.lorStrength);
  }

  // Research Impact Calculator (v7) — specialty, publication counts
  if(toolId==='v7'){
    setSelect('roi-spec',ti.specialty||cp.specialty);
    if(ti.firstAuthor){var r=document.getElementById('roi-first');if(r&&!parseInt(r.value)){r.value=ti.firstAuthor;var v=document.getElementById('roi-first-v');if(v)v.textContent=ti.firstAuthor}}
    if(ti.caseReports){var r=document.getElementById('roi-case');if(r&&!parseInt(r.value)){r.value=ti.caseReports;var v=document.getElementById('roi-case-v');if(v)v.textContent=ti.caseReports}}
    if(ti.abstracts){var r=document.getElementById('roi-abstract');if(r&&!parseInt(r.value)){r.value=ti.abstracts;var v=document.getElementById('roi-abstract-v');if(v)v.textContent=ti.abstracts}}
  }

  // Specialty Fit Assessment (v13) — no direct overlap, preferences-based

  // Observership Database (v17) — IMG status, specialty
  if(toolId==='v17'){
    setSelect('obs-spec',ti.specialty||cp.specialty);
    if(ti.img)setSelect('obs-img',ti.img);
  }

  // Financial Planner (v5) — salary, debt
  // Financial Planner (v11, merged v5 + v8) — salary, debt, employer
  if(toolId==='v11'){
    if(ti.salary||cp.comp){
      var sal=ti.salary||parseInt(String(cp.comp).replace(/[^0-9]/g,''))||0;
      if(sal>10000){setVal('fyp-salary',sal);setVal('ilp-salary',sal);}
    }
    if(ti.debt||cp.debt){
      var debt=ti.debt||parseInt(String(cp.debt).replace(/[^0-9]/g,''))||0;
      if(debt>0){setVal('fyp-debt',debt);setVal('ilp-debt',debt);}
    }
    if(ti.employer)setSelect('ilp-employer',ti.employer);
    if(ti.disability)setSelect('ilp-disability',ti.disability);
  }

  // Contract & Offer Analyzer (v12, merged v3) — salary, specialty
  if(toolId==='v12'){
    if(ti.specialty||cp.specialty)setSelect('ocm-spec',ti.specialty||cp.specialty);
    // Pre-fill first offer salary from profile comp
    if(cp.comp){var compNum=parseInt(String(cp.comp).replace(/[^0-9]/g,''))||0;if(compNum>10000)setVal('ocm-a-salary',compNum)}
  }

  // Career Roadmap (v15, merged v6) — specialty
  if(toolId==='v15'){
    setSelect('fpr-spec',ti.specialty||cp.specialty);
  }

  // Interview Practice (v16) — specialty
  if(toolId==='v16'){
    if(ti.specialty||cp.specialty)setSelect('mis-spec',ti.specialty||cp.specialty);
  }

  // Specialty & Career Fit (v13, merged v10) — stage, practice, satisfaction
  if(toolId==='v13'){
    if(cp.satisfaction)setVal('ctp-satisfaction',cp.satisfaction);
    if(cp.practice)setSelect('ctp-setting',cp.practice);
    if(cp.comp){var compNum=parseInt(String(cp.comp).replace(/[^0-9]/g,''))||0;if(compNum>10000)setVal('ctp-salary',compNum)}
  }
}

