function rvuFillBenchmark(){
  var spec=document.getElementById('rvu-spec');
  if(!spec)return;
  var key=spec.value;
  var b=_rvuBenchmarks[key];
  if(b){
    document.getElementById('rvu-vol').value=b.wrvu;
    document.getElementById('rvu-rate').value=b.rate;
  }
}

function rvuModelChange(){
  var model=document.getElementById('rvu-model');
  var baseFields=document.getElementById('rvu-base-fields');
  if(!model||!baseFields)return;
  baseFields.style.display=(model.value==='base_bonus')?'grid':'none';
}

function rvuUpdate(){
  var modelEl=document.getElementById('rvu-model');
  if(!modelEl)return;
  rvuModelChange();
  var model=modelEl.value;
  var vol=parseFloat(document.getElementById('rvu-vol').value)||0;
  var rate=parseFloat(document.getElementById('rvu-rate').value)||0;
  var base=parseFloat(document.getElementById('rvu-base').value)||0;
  var thresh=parseFloat(document.getElementById('rvu-thresh').value)||0;
  var total=0;
  var breakdown='';

  if(model==='production'){
    total=vol*rate;
    breakdown='<strong>'+vol.toLocaleString()+'</strong> wRVUs × <strong>$'+rate+'</strong>/wRVU';
  }else if(model==='base_bonus'){
    var bonus=Math.max(0,vol-thresh)*rate;
    total=base+bonus;
    breakdown='Base: <strong>$'+base.toLocaleString()+'</strong>';
    if(vol>thresh){
      breakdown+=' + Bonus: <strong>$'+Math.round(bonus).toLocaleString()+'</strong>';
      breakdown+='<br><span style="font-size:11px;color:var(--text3)">('+(vol-thresh).toLocaleString()+' wRVUs above threshold × $'+rate+')</span>';
    }else{
      breakdown+='<br><span style="font-size:11px;color:var(--text3)">Below bonus threshold by '+(thresh-vol).toLocaleString()+' wRVUs</span>';
    }
  }else{
    total=base||vol*rate;
    breakdown='Guaranteed salary (volume-independent year 1)';
  }

  document.getElementById('rvu-total-comp').textContent='$'+Math.round(total).toLocaleString();
  document.getElementById('rvu-breakdown').innerHTML=breakdown;

  // Compare to MGMA
  var specKey=document.getElementById('rvu-spec').value;
  var b=_rvuBenchmarks[specKey];
  var mgmaHtml='';
  if(b&&total>0){
    var diff=total-b.comp;
    var pct=Math.round((diff/b.comp)*100);
    var color=diff>=0?'var(--green)':'var(--red)';
    var arrow=diff>=0?'↑':'↓';
    mgmaHtml='<span style="color:'+color+';font-weight:600">'+arrow+' $'+Math.abs(Math.round(diff)).toLocaleString()+' ('+Math.abs(pct)+'%) '+(diff>=0?'above':'below')+'</span> MGMA median for '+b.name;
    if(vol>0&&b.wrvu>0){
      var volDiff=vol-b.wrvu;
      var volColor=volDiff>=0?'var(--green)':'var(--red)';
      mgmaHtml+='<br><span style="font-size:11px;color:'+volColor+'">Your volume: '+vol.toLocaleString()+' vs median '+b.wrvu.toLocaleString()+' wRVUs</span>';
    }
  }
  document.getElementById('rvu-vs-mgma').innerHTML=mgmaHtml;

  // Practice model interpretation
  var modelAdvice='';
  if(model==='production')modelAdvice='<div style="margin-top:10px;padding:10px;background:var(--bg3);border-radius:6px;font-size:11px;color:var(--text2);line-height:1.6"><strong>Production model</strong> favors high-volume private practice. You eat what you kill \u2014 no floor, no ceiling. Best for: productive proceduralists, efficient clinicians, and physicians comfortable with income variability. <strong style="color:var(--red)">Risk:</strong> Income drops if volume drops (parental leave, illness, ramp-up year).</div>';
  else if(model==='base_bonus')modelAdvice='<div style="margin-top:10px;padding:10px;background:var(--bg3);border-radius:6px;font-size:11px;color:var(--text2);line-height:1.6"><strong>Base + bonus model</strong> favors hospital-employed positions. You get a floor with upside potential. Best for: physicians who want stability while building volume. <strong style="color:var(--accent)">Watch:</strong> Is the threshold achievable? If it\u2019s set above median wRVU, the bonus is effectively unreachable.</div>';
  else modelAdvice='<div style="margin-top:10px;padding:10px;background:var(--bg3);border-radius:6px;font-size:11px;color:var(--text2);line-height:1.6"><strong>Guaranteed salary</strong> favors academic or new-hire positions. Predictable income, no production pressure. Best for: early career, research-heavy roles, or positions where volume is hard to control. <strong style="color:var(--accent)">Watch:</strong> After the guarantee period (usually 1-2 years), you\u2019ll likely shift to production or base+bonus.</div>';
  document.getElementById('rvu-vs-mgma').insertAdjacentHTML('afterend', modelAdvice);

  // Scenarios
  if(vol>0&&rate>0){
    var scenarios='';
    var pcts=[0.75,0.9,1.0,1.1,1.25];
    var labels=['75% volume','90% volume','Current','110% volume','125% volume'];
    pcts.forEach(function(p,i){
      var sv=Math.round(vol*p);
      var sc;
      if(model==='production')sc=sv*rate;
      else if(model==='base_bonus')sc=base+Math.max(0,sv-thresh)*rate;
      else sc=total;
      var isCurrent=p===1.0;
      scenarios+='<div style="display:flex;justify-content:space-between;padding:4px 0;'+(isCurrent?'font-weight:600;color:var(--accent)':'')+'"><span>'+labels[i]+' ('+sv.toLocaleString()+' wRVUs)</span><span>$'+Math.round(sc).toLocaleString()+'</span></div>';
    });
    document.getElementById('rvu-scenarios').innerHTML=scenarios;

    // Your Negotiation Move
    if(b&&total>0){
      var diffFromMgma=total-b.comp;
      var negotiateHtml='<div style="margin-top:14px;padding:16px;background:var(--bg2);border-left:3px solid '+(diffFromMgma>=0?'var(--green)':'var(--red)')+';border-radius:0 10px 10px 0">';
      negotiateHtml+='<div style="font-size:11px;font-weight:600;color:var(--accent);text-transform:uppercase;letter-spacing:1px;margin-bottom:10px">Your negotiation play</div>';
      if(diffFromMgma<-20000){
        negotiateHtml+='<div style="font-size:13px;color:var(--text);line-height:1.8;margin-bottom:8px"><strong style="color:var(--red)">You\u2019re significantly below market.</strong> At $'+Math.round(total).toLocaleString()+', you\u2019re leaving $'+Math.abs(Math.round(diffFromMgma)).toLocaleString()+'/year on the table compared to MGMA median for '+b.name+'. Over 5 years, that\u2019s <strong>$'+Math.round(Math.abs(diffFromMgma)*5/1000)+'K</strong> in lost income.</div>';
        negotiateHtml+='<div style="font-size:12px;color:var(--text2);line-height:1.7"><strong>What to say:</strong> \u201cI\u2019ve reviewed MGMA data for '+b.name+' and the median total compensation is $'+b.comp.toLocaleString()+'. My offer is $'+Math.abs(Math.round(diffFromMgma)).toLocaleString()+' below that benchmark. I\u2019d like to discuss either a higher per-wRVU rate or an adjusted base to bring this in line with market.\u201d</div>';
      } else if(diffFromMgma<0){
        negotiateHtml+='<div style="font-size:13px;color:var(--text);line-height:1.8;margin-bottom:8px"><strong>You\u2019re slightly below MGMA median.</strong> The gap is $'+Math.abs(Math.round(diffFromMgma)).toLocaleString()+'/year. This is negotiable \u2014 most employers expect a counteroffer.</div>';
        negotiateHtml+='<div style="font-size:12px;color:var(--text2);line-height:1.7"><strong>Your lever:</strong> Ask for a higher per-wRVU rate ($'+(rate+3)+'-$'+(rate+5)+' range) rather than a higher base. It shows you\u2019re willing to earn it through volume, which employers prefer.</div>';
      } else {
        negotiateHtml+='<div style="font-size:13px;color:var(--text);line-height:1.8;margin-bottom:8px"><strong style="color:var(--green)">You\u2019re above MGMA median</strong> by $'+Math.round(diffFromMgma).toLocaleString()+'. The compensation is strong. Shift your negotiation focus to non-compete terms, tail coverage, call schedule, and partnership track \u2014 these are where the real money is long-term.</div>';
      }
      negotiateHtml+='</div>';
      document.getElementById('rvu-scenarios').insertAdjacentHTML('afterend', negotiateHtml);

      // Pathway
      hwSetAssessmentContext('RVU Compensation Calculator','v4',['Your estimated total compensation is <strong>$'+Math.round(total).toLocaleString()+'</strong>.',(diffFromMgma<-20000?'This is significantly below the MGMA median for your specialty. There is room to negotiate.':diffFromMgma<0?'You are below the MGMA median by $'+Math.abs(Math.round(diffFromMgma)).toLocaleString()+'. This gap is negotiable.':'You are above the MGMA median. Compensation is strong.')],null,diffFromMgma<0?'Below MGMA':'Above MGMA');
      var rvuPw=hwGatePathway(hwPathway(diffFromMgma<-20000?'You\u2019re significantly underpaid. Negotiate before signing.':diffFromMgma<0?'Below market \u2014 negotiable.':'Compensation is strong. Focus on contract terms.',[{text:diffFromMgma<0?'Counter with a specific per-wRVU rate increase.':'Review non-compete, tail coverage, and call terms.',when:'this week'},{text:'Pull MGMA data for your exact specialty and region.',when:'this week'},{text:'Run the full contract through Contract Review.',when:'before signing'}],diffFromMgma<0?{id:'v12',icon:'\u2696\ufe0f',title:'Contract & Offer Analyzer',why:'Compare against other offers to strengthen your position.'}:{id:'v12',icon:'\ud83d\udcdd',title:'Contract Review Tool',why:'Comp looks good \u2014 make sure the contract terms don\u2019t have hidden costs.'}));
      document.getElementById('rvu-scenarios').insertAdjacentHTML('afterend', rvuPw);
      // Lifetime Impact
      if(diffFromMgma!==0&&typeof hwLifetimeImpact==='function'){
        var rvuAlts=[];
        if(diffFromMgma<0){
          rvuAlts.push({action:'Counter with a specific per-wRVU rate increase. Say: "Based on MGMA data, I\'d like to discuss $'+(rate+Math.ceil(Math.abs(diffFromMgma)/vol))+'/wRVU."',impact:'Recovers '+fmt2(Math.abs(diffFromMgma))+'/year',tool:{id:'v12',name:'Contract Review'}});
          rvuAlts.push({action:'Negotiate a higher productivity bonus threshold or lower base with uncapped upside.',impact:'Could exceed market by '+fmt2(Math.abs(diffFromMgma)*0.5)+'+/year'});
          rvuAlts.push({action:'If they won\'t move on comp, negotiate non-compete radius, tail coverage, or signing bonus.',impact:'$20K-$80K in risk reduction'});
          rvuAlts.push({action:'Get a competing offer. Nothing moves an employer like a real alternative.',impact:'Average counter-offer increase: $30K-$50K',tool:{id:'v12',name:'Contract & Offer Analyzer'}});
        } else {
          rvuAlts.push({action:'Comp is strong — shift focus to contract terms. Non-compete, tail coverage, and call schedule are where hidden costs live.',impact:'Protects $400K+ in risk exposure',tool:{id:'v12',name:'Contract Review'}});
          rvuAlts.push({action:'Max out tax-advantaged accounts (401k + backdoor Roth + HSA) with the surplus.',impact:fmt2(Math.min(diffFromMgma,70000))+'/year invested = '+fmt2(Math.min(diffFromMgma,70000)*15)+'+ by retirement'});
        }
        var rvuImpact=hwLifetimeImpact({
          annual:diffFromMgma,
          type:diffFromMgma<0?'gap':'gain',
          description:diffFromMgma<0?'Your compensation is '+fmt2(Math.abs(diffFromMgma))+'/year below MGMA median for '+b.name+'. This gap compounds every year you don\'t address it.':'You\'re earning '+fmt2(diffFromMgma)+'/year above MGMA median. Smart move — now protect it with strong contract terms.',
          delayPerMonth:diffFromMgma<0?Math.round(Math.abs(diffFromMgma)/12):null,
          comparison:diffFromMgma<0?'The average physician who doesn\'t negotiate their first contract loses $300K+ over their career. Physicians who negotiate earn 10-15% more on average.':'Only 35% of physicians earn above MGMA median. You\'re in a strong position — don\'t give it back on bad contract terms.',
          alternatives:rvuAlts
        });
        document.getElementById('rvu-scenarios').insertAdjacentHTML('afterend', rvuImpact);
      }
    }
  }
  // Record with resultData for saved scenarios
  if(total>0){
    var specKey=document.getElementById('rvu-spec').value;
    var b=_rvuBenchmarks[specKey];
    var rvuInputs={Specialty:b?b.name:specKey,Model:model,Volume:vol.toLocaleString()+' wRVUs',Rate:'$'+rate+'/wRVU'};
    if(model==='base_bonus'){rvuInputs['Base Salary']='$'+base.toLocaleString();rvuInputs['Threshold']=thresh.toLocaleString()+' wRVUs'}
    var rvuHL=['Total Compensation: $'+Math.round(total).toLocaleString()];
    if(b){var diff=total-b.comp;rvuHL.push((diff>=0?'Above':'Below')+' MGMA median by $'+Math.abs(Math.round(diff)).toLocaleString())}
    recordToolUse('RVU Compensation Calculator','$'+Math.round(total).toLocaleString(),'$'+Math.round(total/1000)+'K '+model,{inputs:rvuInputs,highlights:rvuHL});
  }
}

// ===== 3-YEAR FINANCIAL LEVERAGE PLANNER (v5) =====
function fypCalculate(){
  var salary=parseFloat(document.getElementById('fyp-salary').value)||0;
  var debt=parseFloat(document.getElementById('fyp-debt').value)||0;
  var rate=(parseFloat(document.getElementById('fyp-rate').value)||6.5)/100;
  var expenses=parseFloat(document.getElementById('fyp-expenses').value)||0;
  var inflate=(parseFloat(document.getElementById('fyp-inflate').value)||10)/100;
  var matchPct=(parseFloat(document.getElementById('fyp-match').value)||0)/100;
  var pslf=document.getElementById('fyp-pslf').value;
  var dependents=document.getElementById('fyp-dependents').value;
  if(!salary){notify('Enter your expected salary',1);return}
  if(!expenses){expenses=Math.round(salary*0.3)}
  var effectiveTax=salary>400000?0.35:salary>300000?0.32:salary>200000?0.28:0.24;
  var netSalary=Math.round(salary*(1-effectiveTax));
  var max401k=23500,maxRoth=7000,maxHSA=4150;
  var matchAmt=Math.round(Math.min(salary*matchPct,max401k*0.5));
  var totalTaxAdv=max401k+maxRoth+maxHSA;
  var standardPayment=debt>0?Math.round(debt*(rate/12)*Math.pow(1+rate/12,120)/(Math.pow(1+rate/12,120)-1)):0;
  var refinanceRate=Math.max(0.04,rate-0.015);
  var refiPayment=debt>0?Math.round(debt*(refinanceRate/12)*Math.pow(1+refinanceRate/12,60)/(Math.pow(1+refinanceRate/12,60)-1)):0;
  var idrPayment=debt>0?Math.round(Math.max(0,(salary*0.9-22500)*0.10/12)):0;
  var years=[],cumInvested=0,remainDebt=debt;
  for(var yr=1;yr<=3;yr++){
    var yrSalary=Math.round(salary*Math.pow(1.03,yr-1));
    var yrNet=Math.round(yrSalary*(1-effectiveTax));
    var yrExp=Math.round(expenses*Math.pow(1+inflate,yr-1));
    var yrMatch=Math.round(yrSalary*matchPct);
    var monthlyLoan=0;
    if(remainDebt>0){monthlyLoan=pslf==='yes'?idrPayment:refiPayment}
    var yrLoan=monthlyLoan*12;
    var interest=Math.round(remainDebt*rate);
    var principal=Math.max(0,yrLoan-interest);
    remainDebt=Math.max(0,remainDebt-principal);
    var yrInvestable=Math.max(0,yrNet-yrExp-yrLoan);
    cumInvested+=totalTaxAdv+yrMatch+yrInvestable;
    var growth=Math.round(cumInvested*0.08*(yr*0.5));
    var netWealth=cumInvested+growth-remainDebt;
    var cashFlow=yrNet-yrExp-yrLoan;
    years.push({year:yr,salary:yrSalary,net:yrNet,exp:yrExp,loan:yrLoan,taxAdv:totalTaxAdv,match:yrMatch,investable:yrInvestable,cumInvested:cumInvested,growth:growth,remainDebt:remainDebt,netWealth:netWealth,cashFlow:cashFlow});
  }
  var y3=years[2],yr1Save=years[0].net>0?Math.round(((years[0].taxAdv+years[0].investable)/years[0].net)*100):0;
  var h='';
  h+='<div style="display:grid;grid-template-columns:1fr 1fr 1fr;gap:10px;margin-bottom:20px">';
  h+='<div style="padding:16px;background:var(--bg2);border:1px solid var(--border);border-radius:10px;text-align:center"><div style="font-size:10px;text-transform:uppercase;letter-spacing:1px;color:var(--text3);margin-bottom:4px">Year 3 Net Wealth</div><div style="font-size:26px;font-weight:700;color:'+(y3.netWealth>=0?'var(--green)':'var(--red)')+';font-family:var(--font-serif)">$'+Math.round(y3.netWealth/1000)+'K</div></div>';
  h+='<div style="padding:16px;background:var(--bg2);border:1px solid var(--border);border-radius:10px;text-align:center"><div style="font-size:10px;text-transform:uppercase;letter-spacing:1px;color:var(--text3);margin-bottom:4px">Total Invested</div><div style="font-size:26px;font-weight:700;color:var(--accent);font-family:var(--font-serif)">$'+Math.round(y3.cumInvested/1000)+'K</div></div>';
  h+='<div style="padding:16px;background:var(--bg2);border:1px solid var(--border);border-radius:10px;text-align:center"><div style="font-size:10px;text-transform:uppercase;letter-spacing:1px;color:var(--text3);margin-bottom:4px">Remaining Debt</div><div style="font-size:26px;font-weight:700;color:'+(y3.remainDebt>0?'var(--red)':'var(--green)')+';font-family:var(--font-serif)">'+(y3.remainDebt>0?'$'+Math.round(y3.remainDebt/1000)+'K':'$0')+'</div></div>';
  h+='</div>';
  h+='<div style="font-size:11px;font-weight:600;color:var(--accent);text-transform:uppercase;letter-spacing:1px;margin-bottom:12px">Year-by-Year Breakdown</div>';
  years.forEach(function(y){
    var cfColor=y.cashFlow>=0?'var(--green)':'var(--red)';
    h+='<div style="padding:16px;background:var(--bg2);border:1px solid var(--border);border-radius:10px;margin-bottom:10px">';
    h+='<div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:10px"><div style="font-size:14px;font-weight:700;color:var(--accent);font-family:var(--font-serif)">Year '+y.year+'</div><div style="font-size:11px;color:var(--text3)">Salary: $'+Math.round(y.salary/1000)+'K</div></div>';
    h+='<div style="display:grid;grid-template-columns:1fr 1fr;gap:6px;font-size:12px">';
    h+='<div style="display:flex;justify-content:space-between;padding:5px 0;border-bottom:1px solid var(--border)"><span style="color:var(--text3)">Take-Home</span><span style="font-weight:600">$'+Math.round(y.net/1000)+'K</span></div>';
    h+='<div style="display:flex;justify-content:space-between;padding:5px 0;border-bottom:1px solid var(--border)"><span style="color:var(--text3)">Expenses</span><span style="font-weight:600">-$'+Math.round(y.exp/1000)+'K</span></div>';
    if(y.loan>0) h+='<div style="display:flex;justify-content:space-between;padding:5px 0;border-bottom:1px solid var(--border)"><span style="color:var(--text3)">Loan Payments</span><span style="color:var(--red);font-weight:600">-$'+Math.round(y.loan/1000)+'K</span></div>';
    h+='<div style="display:flex;justify-content:space-between;padding:5px 0;border-bottom:1px solid var(--border)"><span style="color:var(--text3)">Tax-Advantaged</span><span style="color:var(--green);font-weight:600">$'+Math.round(y.taxAdv/1000)+'K</span></div>';
    if(y.match>0) h+='<div style="display:flex;justify-content:space-between;padding:5px 0;border-bottom:1px solid var(--border)"><span style="color:var(--text3)">Employer Match</span><span style="color:var(--green);font-weight:600">+$'+Math.round(y.match/1000)+'K</span></div>';
    h+='<div style="display:flex;justify-content:space-between;padding:5px 0"><span style="color:var(--text3)">Monthly Cash Flow</span><span style="color:'+cfColor+';font-weight:700">$'+Math.round(y.cashFlow/12).toLocaleString()+'/mo</span></div>';
    h+='</div>';
    var wPct=Math.min(100,Math.max(0,Math.round((y.cumInvested/(salary*3))*100)));
    h+='<div style="margin-top:8px"><div style="display:flex;justify-content:space-between;font-size:10px;color:var(--text3);margin-bottom:3px"><span>Cumulative Invested</span><span>$'+Math.round(y.cumInvested/1000)+'K</span></div>';
    h+='<div style="height:5px;background:var(--bg3);border-radius:3px;overflow:hidden"><div style="height:100%;width:'+wPct+'%;background:var(--accent);border-radius:3px"></div></div></div>';
    h+='</div>';
  });
  if(debt>0){
    h+='<div style="padding:16px;background:var(--bg2);border-left:3px solid var(--accent);border-radius:0 10px 10px 0;margin-bottom:14px">';
    h+='<div style="font-size:11px;font-weight:600;color:var(--accent);text-transform:uppercase;letter-spacing:1px;margin-bottom:8px">Loan Strategy</div>';
    if(pslf==='yes'){
      h+='<div style="font-size:13px;font-weight:600;margin-bottom:4px">PSLF Path</div>';
      h+='<div style="font-size:12px;color:var(--text2);line-height:1.7">IDR: <strong>$'+idrPayment.toLocaleString()+'/mo</strong> vs standard: <strong>$'+standardPayment.toLocaleString()+'/mo</strong>. Forgiveness: <strong style="color:var(--green)">$'+Math.round(Math.max(0,debt-idrPayment*120)/1000)+'K</strong>. Do NOT refinance.</div>';
    }else{
      h+='<div style="font-size:13px;font-weight:600;margin-bottom:4px">Aggressive Payoff</div>';
      h+='<div style="font-size:12px;color:var(--text2);line-height:1.7">Refinanced: <strong>$'+refiPayment.toLocaleString()+'/mo</strong> × 5yr. Extra $1K/mo saves ~$'+Math.round(debt*rate/12000)+'K interest.</div>';
    }
    h+='</div>';
  }
  h+='<div style="padding:16px;background:var(--bg2);border-radius:10px;margin-bottom:14px">';
  h+='<div style="font-size:11px;font-weight:600;color:var(--accent);text-transform:uppercase;letter-spacing:1px;margin-bottom:10px">Key Insights</div>';
  var ins=[];
  ins.push('Year 1 savings rate: <strong>'+yr1Save+'%</strong>'+(yr1Save>=30?' — excellent':yr1Save>=20?' — solid, push toward 30%':' — hold expenses flat'));
  if(inflate>0.15) ins.push('<span style="color:var(--red)">'+Math.round(inflate*100)+'% lifestyle inflation is high.</span> Expenses: $'+Math.round(expenses*Math.pow(1+inflate,2)/1000)+'K by Year 3.');
  if(matchPct>0) ins.push('Employer match 3yr value: <strong style="color:var(--green)">$'+Math.round(matchAmt*3/1000)+'K</strong>.');
  if(y3.netWealth>0) ins.push('<strong style="color:var(--green)">Positive net worth by Year 3</strong> — ahead of most physicians.');
  else ins.push('Negative net worth at Year 3 — hold expenses flat years 4-5.');
  ins.forEach(function(i){h+='<div style="font-size:12px;color:var(--text2);line-height:1.7;margin-bottom:6px;padding-left:10px;border-left:2px solid var(--border)">'+i+'</div>'});
  h+='</div>';
  h+='<div style="padding:16px;background:var(--bg2);border-radius:10px">';
  h+='<div style="font-size:11px;font-weight:600;color:var(--accent);text-transform:uppercase;letter-spacing:1px;margin-bottom:8px">Annual Tax-Advantaged Checklist</div>';
  h+='<div style="font-size:12px;color:var(--text2);line-height:2">';
  h+='<div>1. 401k/403b — <strong>$'+max401k.toLocaleString()+'</strong>'+(matchPct>0?' (+ $'+matchAmt.toLocaleString()+' match)':'')+'</div>';
  h+='<div>2. Backdoor Roth IRA — <strong>$'+maxRoth.toLocaleString()+'</strong></div>';
  h+='<div>3. HSA (if HDHP) — <strong>$'+maxHSA.toLocaleString()+'</strong></div>';
  h+='<div style="color:var(--text3);font-size:11px;margin-top:4px">Total: $'+totalTaxAdv.toLocaleString()+'/yr</div>';
  h+='</div></div>';

  // Your Next Move — direct action plan
  h+='<div style="padding:16px;background:var(--bg2);border-left:3px solid var(--accent);border-radius:0 10px 10px 0;margin-top:14px">';
  h+='<div style="font-size:11px;font-weight:600;color:var(--accent);text-transform:uppercase;letter-spacing:1px;margin-bottom:10px">Your first 30 days</div>';
  h+='<div style="display:flex;flex-direction:column;gap:6px;font-size:12px;color:var(--text2);line-height:1.6">';
  h+='<div style="padding:8px 10px;background:var(--bg3);border-radius:6px;border-left:3px solid var(--green)"><strong>Week 1:</strong> Set up 401k/403b at your employer\u2019s max ($'+max401k.toLocaleString()+'). If there\u2019s a match, you\u2019re leaving free money on the table every paycheck you wait.</div>';
  h+='<div style="padding:8px 10px;background:var(--bg3);border-radius:6px;border-left:3px solid var(--green)"><strong>Week 2:</strong> Open a backdoor Roth IRA. This takes 30 minutes and saves you six figures in taxes over your career. Do it before you talk yourself out of it.</div>';
  if(debt>0){
    if(pslf==='yes'){
      h+='<div style="padding:8px 10px;background:var(--bg3);border-radius:6px;border-left:3px solid var(--accent)"><strong>Week 3:</strong> Certify your employment for PSLF immediately. Make IDR payments ($'+idrPayment.toLocaleString()+'/mo) and <strong>do not refinance</strong>. Refinancing disqualifies you from forgiveness of $'+Math.round(Math.max(0,debt-idrPayment*120)/1000)+'K.</div>';
    } else {
      h+='<div style="padding:8px 10px;background:var(--bg3);border-radius:6px;border-left:3px solid var(--accent)"><strong>Week 3:</strong> Refinance your loans. At $'+debt.toLocaleString()+', dropping from '+(rate*100).toFixed(1)+'% to '+(refinanceRate*100).toFixed(1)+'% saves you roughly $'+Math.round((standardPayment-refiPayment)*60/1000)+'K over 5 years. Then add $1K/mo extra toward principal.</div>';
    }
  }
  h+='<div style="padding:8px 10px;background:var(--bg3);border-radius:6px;border-left:3px solid var(--accent)"><strong>Week 4:</strong> Set your lifestyle budget at $'+Math.round(expenses/1000)+'K/yr and automate everything. The physicians who build wealth aren\u2019t the ones making the most \u2014 they\u2019re the ones who automated their savings before lifestyle creep took over.</div>';
  h+='</div>';
  if(yr1Save<20){
    h+='<div style="font-size:12px;color:var(--red);margin-top:10px;line-height:1.6"><strong>Reality check:</strong> Your Year 1 savings rate is '+yr1Save+'%. That\u2019s below where it needs to be. Either cut $'+Math.round((0.20*years[0].net-years[0].taxAdv-years[0].investable)/12).toLocaleString()+'/mo from expenses or find $'+Math.round((0.20*years[0].net-years[0].taxAdv-years[0].investable)/12).toLocaleString()+'/mo in additional income (moonlighting, locums weekends).</div>';
  }
  h+='</div>';

  // Earning power critical decision
  var criticalDecision='';
  if(debt>200000&&pslf!=='yes')criticalDecision='<div style="padding:14px;background:rgba(239,68,68,.04);border:1px solid rgba(239,68,68,.10);border-radius:10px;margin-top:14px"><div style="font-size:11px;font-weight:600;color:var(--red);margin-bottom:6px">The Decision That Defines Your First 5 Years</div><div style="font-size:12px;color:var(--text2);line-height:1.7">With $'+Math.round(debt/1000)+'K in debt and no PSLF eligibility, <strong>your debt payoff strategy is the single biggest financial decision of your early career.</strong> Every month at '+(rate*100).toFixed(1)+'% interest costs you $'+Math.round(debt*rate/12).toLocaleString()+'. Aggressively paying this down saves you <strong>$'+Math.round(debt*rate*2.5/1000)+'K+</strong> in interest over 5 years.</div></div>';
  else if(debt>200000&&pslf==='yes')criticalDecision='<div style="padding:14px;background:rgba(106,191,75,.04);border:1px solid rgba(106,191,75,.10);border-radius:10px;margin-top:14px"><div style="font-size:11px;font-weight:600;color:var(--green);margin-bottom:6px">\ud83d\udca1 Your PSLF Decision Is Worth $'+Math.round(Math.max(0,debt-idrPayment*120)/1000)+'K</div><div style="font-size:12px;color:var(--text2);line-height:1.7"><strong>Staying at a qualifying employer for 10 years is the highest-leverage financial decision you can make.</strong> Every time you\u2019re tempted by a private practice offer, calculate whether the salary bump exceeds $'+Math.round(Math.max(0,debt-idrPayment*120)/10000)+'K/year in forgiven value.</div></div>';
  else if(yr1Save<15)criticalDecision='<div style="padding:14px;background:rgba(239,68,68,.04);border:1px solid rgba(239,68,68,.10);border-radius:10px;margin-top:14px"><div style="font-size:11px;font-weight:600;color:var(--red);margin-bottom:6px">Your Earning Power Depends on This</div><div style="font-size:12px;color:var(--text2);line-height:1.7"><strong>Your savings rate in years 1-3 defines your wealth trajectory for the next 30 years.</strong> At '+yr1Save+'%, you\u2019re building slowly. The lifestyle you set in year 1 is the lifestyle you\u2019ll be stuck with. Push to 25% now — not later.</div></div>';
  else if(matchPct===0)criticalDecision='<div style="padding:14px;background:rgba(200,168,124,.04);border:1px solid rgba(198,168,94,.10);border-radius:10px;margin-top:14px"><div style="font-size:11px;font-weight:600;color:var(--accent);margin-bottom:6px">\ud83d\udca1 No Employer Match = Missing Free Money</div><div style="font-size:12px;color:var(--text2);line-height:1.7">A 4% match on $'+Math.round(salary/1000)+'K is $'+Math.round(salary*0.04/1000)+'K/year of free money. Factor this into any job comparison.</div></div>';
  h+=criticalDecision;

  // Pathway
  hwSetAssessmentContext('3-Year Financial Projection','v11',[(y3.netWealth>=0?'Projected <strong>positive net worth by Year 3</strong>. You\u2019re ahead of most physicians at this stage.':'Still in the red at Year 3 with $'+Math.round(debt/1000)+'K debt. This is normal, but keep expenses flat.'),'Projected Year 3 net wealth: <strong>$'+Math.round(y3.netWealth/1000)+'K</strong>. Savings rate: '+yr1Save+'%.'],null,y3.netWealth>=0?'Positive by Year 3':'Building');
  h+=hwGatePathway(hwPathway(y3.netWealth>=0?'Positive net worth by Year 3 \u2014 ahead of most physicians.':'Still in the red at Year 3 \u2014 normal with $'+Math.round(debt/1000)+'K debt. Hold expenses flat.',[{text:'Set up 401k + backdoor Roth this week.',when:'this week'},{text:(pslf==='yes'?'Certify PSLF employment.':'Refinance your loans.')+' Free money.',when:'this week'},{text:'Automate savings at '+yr1Save+'%'+(yr1Save<20?' (push to 20%)':'')+' before lifestyle creep.',when:'this month'}],{id:'v11',icon:'\ud83d\udcb5',title:'Financial Planner',why:'Get a full financial health score \u2014 disability, tax strategy, advisor quality.'}));

  document.getElementById('fyp-results').innerHTML=h;

  // Lifetime Impact — savings rate gap
  if(typeof hwLifetimeImpact==='function'&&yr1Save<20){
    var savingsGap=salary*(0.20-yr1Save/100);
    var fypAlts=[];
    fypAlts.push({action:'Increase savings from '+yr1Save+'% to 20% by cutting lifestyle spending. The first 3 attending years set the pattern for the next 25.',impact:'+'+fmt2(savingsGap)+'/year invested'});
    fypAlts.push({action:'Max 401k ($23.5K) + backdoor Roth ($7K) + HSA ($4.2K) = $34.7K/year in tax-advantaged space.',impact:'$34.7K/year shielded from taxes'});
    if(debt>100000&&pslf!=='yes')fypAlts.push({action:'Refinance student loans from '+(rate*100).toFixed(1)+'% to current market rates. Every 1% reduction saves '+fmt2(debt*0.01)+'/year.',impact:fmt2(debt*0.02)+'/year in interest savings'});
    if(pslf==='yes')fypAlts.push({action:'Certify PSLF employment annually and stay on income-driven repayment. Forgiveness could be worth '+fmt2(debt)+' tax-free.',impact:'Up to '+fmt2(debt)+' in forgiveness'});
    fypAlts.push({action:'Get own-occupation disability insurance now. Premiums increase 2-4% per year of age.',impact:'Protects '+fmt2(salary*25)+' in career earnings',tool:{id:'v11',name:'Financial Planner'}});

    document.getElementById('fyp-results').innerHTML+=hwLifetimeImpact({
      annual:savingsGap,
      type:'gap',
      description:'You\'re saving '+yr1Save+'% of income. Increasing to 20% means investing an additional '+fmt2(savingsGap)+'/year. That difference compounds dramatically.',
      delayPerMonth:Math.round(savingsGap/12),
      comparison:'Physicians who save 20%+ in their first 3 attending years accumulate $2M+ more by retirement than those who save 10%. The savings rate gap in early years is almost impossible to close later.',
      alternatives:fypAlts
    });
  }

  recordToolUse('Financial Planner',null,'Y3 Wealth: $'+Math.round(y3.netWealth/1000)+'K | Invested: $'+Math.round(y3.cumInvested/1000)+'K',{inputs:{Salary:'$'+salary.toLocaleString(),Debt:'$'+debt.toLocaleString(),Rate:(rate*100).toFixed(1)+'%',Expenses:'$'+expenses.toLocaleString(),PSLF:pslf||'N/A'},highlights:['Year 3 Net Wealth: $'+Math.round(y3.netWealth/1000)+'K','Total Invested: $'+Math.round(y3.cumInvested/1000)+'K','Remaining Debt: $'+Math.round(y3.remainDebt/1000)+'K']});
}

// ===== INCOME LEVERAGE PLAYBOOK (v8) =====
function ilpCalculate(){
  var salary=parseFloat(document.getElementById('ilp-salary').value)||0;
  var debt=parseFloat(document.getElementById('ilp-debt').value)||0;
  var loanRate=(parseFloat(document.getElementById('ilp-rate').value)||6.5)/100;
  var employer=document.getElementById('ilp-employer').value;
  var disability=document.getElementById('ilp-disability').value;
  var spending=parseFloat(document.getElementById('ilp-spending').value)||0;
  var has401k=document.getElementById('ilp-401k').value;
  var hasAdvisor=document.getElementById('ilp-advisor').value;
  if(!salary){notify('Enter your salary',1);return}
  if(!spending) spending=Math.round(salary*0.5);
  var effectiveTax=salary>400000?0.35:salary>300000?0.32:salary>200000?0.28:0.24;
  var netSalary=Math.round(salary*(1-effectiveTax));
  var h='',score=0,maxScore=50,flags=[],wins=[];
  // 1. PSLF vs Refinance
  h+='<div style="padding:16px;background:var(--bg2);border:1px solid var(--border);border-radius:10px;margin-bottom:10px">';
  h+='<div style="font-size:13px;font-weight:700;color:var(--accent);margin-bottom:8px">1. PSLF vs. Refinance</div>';
  var idr=0,refi5=0,std10=0,pslfForgive=0;
  if(debt>0){
    idr=Math.round(Math.max(0,(salary*0.9-22500)*0.10/12));
    var refiRate=Math.max(0.04,loanRate-0.015);
    refi5=Math.round(debt*(refiRate/12)*Math.pow(1+refiRate/12,60)/(Math.pow(1+refiRate/12,60)-1));
    std10=Math.round(debt*(loanRate/12)*Math.pow(1+loanRate/12,120)/(Math.pow(1+loanRate/12,120)-1));
    pslfForgive=Math.max(0,debt-idr*120);
    if(employer==='nonprofit'||employer==='government'){
      score+=10;wins.push('PSLF-eligible employer');
      h+='<div style="padding:10px;background:rgba(139,184,160,.1);border-radius:8px;margin-bottom:8px"><span style="color:var(--green);font-weight:600">PSLF RECOMMENDED</span> — IDR: <strong>$'+idr.toLocaleString()+'/mo</strong>. Forgiveness: ~<strong>$'+Math.round(pslfForgive/1000)+'K</strong>.</div>';
      h+='<div style="font-size:11px;color:var(--red);font-weight:600">Do NOT refinance federal loans.</div>';
    }else{
      score+=6;
      h+='<div style="padding:10px;background:rgba(200,168,124,.08);border-radius:8px;margin-bottom:8px"><span style="color:var(--accent);font-weight:600">REFINANCE</span> — $'+refi5.toLocaleString()+'/mo x 5yr. Saves ~$'+Math.round((std10*120-refi5*60)/1000)+'K vs standard.</div>';
    }
    h+='<div style="display:grid;grid-template-columns:1fr 1fr;gap:8px;font-size:11px;margin-top:8px">';
    h+='<div style="padding:8px;background:var(--bg3);border-radius:6px;text-align:center"><div style="color:var(--text3)">PSLF</div><div style="font-weight:600">$'+idr.toLocaleString()+'/mo</div><div style="color:var(--green);font-size:10px">Forgiven: $'+Math.round(pslfForgive/1000)+'K</div></div>';
    h+='<div style="padding:8px;background:var(--bg3);border-radius:6px;text-align:center"><div style="color:var(--text3)">Refi 5yr</div><div style="font-weight:600">$'+refi5.toLocaleString()+'/mo</div><div style="color:var(--accent);font-size:10px">Total: $'+Math.round(refi5*60/1000)+'K</div></div>';
    h+='</div>';
  }else{score+=10;wins.push('No student debt');h+='<div style="color:var(--green);font-weight:600">No debt — skip to wealth building.</div>'}
  h+='</div>';
  // 2. Disability Insurance
  h+='<div style="padding:16px;background:var(--bg2);border:1px solid var(--border);border-radius:10px;margin-bottom:10px">';
  h+='<div style="font-size:13px;font-weight:700;color:var(--accent);margin-bottom:8px">2. Disability Insurance</div>';
  var monthBenefit=Math.round(salary*0.6/12);
  if(disability==='own_occ'){score+=10;wins.push('Own-occupation disability');h+='<div style="padding:10px;background:rgba(139,184,160,.1);border-radius:8px"><span style="color:var(--green);font-weight:600">Own-Occupation — Optimal.</span> Benefit: ~$'+monthBenefit.toLocaleString()+'/mo.</div>'}
  else if(disability==='any_occ'){score+=4;flags.push('Upgrade to own-occupation');h+='<div style="padding:10px;background:rgba(200,168,124,.1);border-radius:8px"><span style="color:var(--accent);font-weight:600">Any-Occupation — Upgrade.</span> Won\'t pay if you can work ANY job.</div>'}
  else{flags.push('No disability insurance');h+='<div style="padding:10px;background:rgba(196,77,86,.1);border-radius:8px"><span style="color:var(--red);font-weight:600">No Coverage — Critical Gap.</span> 25% chance of 90+ day disability before 65. Cost: ~$'+Math.round(salary*0.025/1000)+'K/yr for $'+monthBenefit.toLocaleString()+'/mo protection.</div>'}
  h+='</div>';
  // 3. Lifestyle
  h+='<div style="padding:16px;background:var(--bg2);border:1px solid var(--border);border-radius:10px;margin-bottom:10px">';
  h+='<div style="font-size:13px;font-weight:700;color:var(--accent);margin-bottom:8px">3. Lifestyle vs. Wealth</div>';
  var spendPct=Math.round((spending/netSalary)*100);
  var loanPmt=debt>0?((employer==='nonprofit'||employer==='government')?idr*12:refi5*12):0;
  var investable=Math.max(0,netSalary-spending-loanPmt);
  var wealth3=Math.round(investable*3*1.24);
  var altSpend=Math.round(netSalary*0.4);
  var altInvestable=Math.max(0,netSalary-altSpend-loanPmt);
  var altWealth3=Math.round(altInvestable*3*1.24);
  if(spendPct<=40){score+=10;wins.push('Disciplined spending')}else if(spendPct<=60){score+=6;flags.push('Room to reduce spending')}else{score+=2;flags.push('High spending ('+spendPct+'%)')}
  h+='<div style="font-size:12px;color:var(--text2);margin-bottom:10px">Spending <strong>$'+Math.round(spending/1000)+'K/yr</strong> ('+spendPct+'% of take-home). Investable: <strong>$'+Math.round(investable/1000)+'K/yr</strong>.</div>';
  h+='<div style="display:grid;grid-template-columns:1fr 1fr;gap:8px;font-size:11px">';
  h+='<div style="padding:10px;background:var(--bg3);border-radius:6px;text-align:center"><div style="color:var(--text3)">Your Plan</div><div style="font-weight:600">Spend $'+Math.round(spending/1000)+'K</div><div style="color:var(--accent);font-size:10px">3yr: $'+Math.round(wealth3/1000)+'K</div></div>';
  h+='<div style="padding:10px;background:var(--bg3);border-radius:6px;text-align:center"><div style="color:var(--text3)">40% Rule</div><div style="font-weight:600">Spend $'+Math.round(altSpend/1000)+'K</div><div style="color:var(--green);font-size:10px">3yr: $'+Math.round(altWealth3/1000)+'K</div></div>';
  h+='</div>';
  var wDiff=altWealth3-wealth3;
  if(wDiff>10000) h+='<div style="font-size:11px;color:var(--accent);margin-top:8px;font-weight:600">Gap: $'+Math.round(wDiff/1000)+'K over 3 years.</div>';
  h+='</div>';
  // 4. Tax-Advantaged
  h+='<div style="padding:16px;background:var(--bg2);border:1px solid var(--border);border-radius:10px;margin-bottom:10px">';
  h+='<div style="font-size:13px;font-weight:700;color:var(--accent);margin-bottom:8px">4. Tax-Advantaged Accounts</div>';
  if(has401k==='maxed'){score+=10;wins.push('Maxing tax-advantaged');h+='<div style="padding:10px;background:rgba(139,184,160,.1);border-radius:8px"><span style="color:var(--green);font-weight:600">Maxing Out — Saving ~$'+Math.round(34650*effectiveTax/1000)+'K/yr in taxes.</span></div>'}
  else if(has401k==='match'){score+=5;flags.push('Only employer match');h+='<div style="padding:10px;background:rgba(200,168,124,.1);border-radius:8px"><span style="color:var(--accent);font-weight:600">Match Only — Leaving tax savings on the table.</span></div>'}
  else{flags.push('Not contributing');h+='<div style="padding:10px;background:rgba(196,77,86,.1);border-radius:8px"><span style="color:var(--red);font-weight:600">Not Contributing — Missing ~$'+Math.round(34650*effectiveTax/1000)+'K/yr tax savings.</span></div>'}
  h+='<div style="font-size:12px;color:var(--text2);line-height:1.8;margin-top:8px">Priority: Employer match → Backdoor Roth ($7K) → Max 401k ($23.5K) → HSA ($4,150)</div></div>';
  // 5. Advisor
  h+='<div style="padding:16px;background:var(--bg2);border:1px solid var(--border);border-radius:10px;margin-bottom:10px">';
  h+='<div style="font-size:13px;font-weight:700;color:var(--accent);margin-bottom:8px">5. Financial Advisor</div>';
  if(hasAdvisor==='feeonly'){score+=10;wins.push('Fee-only fiduciary');h+='<div style="padding:10px;background:rgba(139,184,160,.1);border-radius:8px"><span style="color:var(--green);font-weight:600">Fee-Only Fiduciary — Gold standard.</span></div>'}
  else if(hasAdvisor==='feebased'){score+=3;flags.push('Fee-based may have conflicts');h+='<div style="padding:10px;background:rgba(200,168,124,.1);border-radius:8px"><span style="color:var(--accent);font-weight:600">Fee-Based — Can earn commissions. Verify fiduciary or switch (NAPFA.org).</span></div>'}
  else if(hasAdvisor==='none'){score+=4;h+='<div style="padding:10px;background:var(--bg3);border-radius:8px"><span style="font-weight:600">No advisor</span> — Fine if disciplined. Consider fee-only at $250K+ assets.</div>'}
  else{flags.push('Commission-based advisor');h+='<div style="padding:10px;background:rgba(196,77,86,.1);border-radius:8px"><span style="color:var(--red);font-weight:600">Commission-Based — They profit from selling you products. Switch to fee-only (NAPFA.org).</span></div>'}
  h+='</div>';
  // Score
  var scorePct=Math.round((score/maxScore)*100);
  var grade=scorePct>=80?'Excellent':scorePct>=60?'Good':scorePct>=40?'Needs Work':'Critical Gaps';
  var gradeColor=scorePct>=80?'var(--green)':scorePct>=60?'var(--accent)':scorePct>=40?'var(--amber,orange)':'var(--red)';
  h+='<div style="padding:20px;background:var(--bg2);border:1px solid var(--border);border-radius:12px;margin-bottom:14px;text-align:center">';
  h+='<div style="font-size:10px;text-transform:uppercase;letter-spacing:1px;color:var(--text3);margin-bottom:6px">Financial Leverage Score</div>';
  h+='<div style="font-size:48px;font-weight:700;color:'+gradeColor+';font-family:var(--font-serif)">'+score+'<span style="font-size:20px;color:var(--text3)">/'+maxScore+'</span></div>';
  h+='<div style="font-size:14px;font-weight:600;color:'+gradeColor+';margin-top:4px">'+grade+'</div>';
  h+='<div style="height:6px;background:var(--bg3);border-radius:3px;overflow:hidden;margin-top:12px"><div style="height:100%;width:'+scorePct+'%;background:'+gradeColor+';border-radius:3px"></div></div>';
  h+='</div>';
  if(wins.length){
    h+='<div style="padding:14px;background:rgba(139,184,160,.06);border-radius:10px;margin-bottom:10px">';
    h+='<div style="font-size:11px;font-weight:600;color:var(--green);text-transform:uppercase;letter-spacing:1px;margin-bottom:8px">What You\'re Doing Right</div>';
    wins.forEach(function(w){h+='<div style="font-size:12px;color:var(--text2);margin-bottom:4px">✓ '+w+'</div>'});
    h+='</div>';
  }
  if(flags.length){
    h+='<div style="padding:14px;background:rgba(196,77,86,.06);border-radius:10px;margin-bottom:10px">';
    h+='<div style="font-size:11px;font-weight:600;color:var(--red);text-transform:uppercase;letter-spacing:1px;margin-bottom:8px">Action Items</div>';
    flags.forEach(function(f){h+='<div style="font-size:12px;color:var(--text2);margin-bottom:4px">→ '+f+'</div>'});
    h+='</div>';
  }

  // Your Next Move — priority action plan
  h+='<div style="padding:16px;background:var(--bg2);border-left:3px solid var(--accent);border-radius:0 10px 10px 0;margin-bottom:14px">';
  h+='<div style="font-size:11px;font-weight:600;color:var(--accent);text-transform:uppercase;letter-spacing:1px;margin-bottom:10px">What to fix first</div>';
  h+='<div style="display:flex;flex-direction:column;gap:6px;font-size:12px;color:var(--text2);line-height:1.6">';
  var moveNum=1;
  if(disability!=='own_occ'){
    h+='<div style="padding:8px 10px;background:var(--bg3);border-radius:6px;border-left:3px solid var(--red)"><strong>'+moveNum+'. Get own-occupation disability insurance this week.</strong> Not next month. This week. You are an uninsured $'+Math.round(salary/1000)+'K/yr asset right now. One injury ends your career without this. Cost: ~$'+Math.round(salary*0.025/12).toLocaleString()+'/mo. Non-negotiable.</div>';
    moveNum++;
  }
  if(has401k!=='maxed'){
    h+='<div style="padding:8px 10px;background:var(--bg3);border-radius:6px;border-left:3px solid var(--green)"><strong>'+moveNum+'. Max your 401k/403b contributions immediately.</strong> Every paycheck without max contributions is money you\u2019re handing to the IRS. At your tax bracket, that\u2019s ~$'+Math.round(23500*effectiveTax).toLocaleString()+'/yr in tax savings alone.</div>';
    moveNum++;
  }
  if(hasAdvisor==='commission'||hasAdvisor==='feebased'){
    h+='<div style="padding:8px 10px;background:var(--bg3);border-radius:6px;border-left:3px solid var(--accent)"><strong>'+moveNum+'. Fire your commission-based advisor.</strong> Find a fee-only fiduciary at NAPFA.org. Commission advisors cost physicians an average of $100-200K over a career in unnecessary product fees. This is the single biggest financial leak most physicians have.</div>';
    moveNum++;
  }
  if(debt>0&&(employer==='nonprofit'||employer==='government')){
    h+='<div style="padding:8px 10px;background:var(--bg3);border-radius:6px;border-left:3px solid var(--green)"><strong>'+moveNum+'. Certify your employment for PSLF today.</strong> You\u2019re at a qualifying employer. Every month you delay is a qualifying payment you lose. IDR payments at $'+idr.toLocaleString()+'/mo with $'+Math.round(Math.max(0,debt-idr*120)/1000)+'K in forgiveness is life-changing money.</div>';
    moveNum++;
  } else if(debt>100000){
    h+='<div style="padding:8px 10px;background:var(--bg3);border-radius:6px;border-left:3px solid var(--accent)"><strong>'+moveNum+'. Refinance your student loans.</strong> At $'+debt.toLocaleString()+', dropping your rate saves real money. Then attack it with extra principal payments. Every extra $1K/mo toward principal saves you ~$'+Math.round(debt*loanRate/12000)+'K in interest.</div>';
    moveNum++;
  }
  if(spendPct>60){
    h+='<div style="padding:8px 10px;background:var(--bg3);border-radius:6px;border-left:3px solid var(--red)"><strong>'+moveNum+'. Your spending is '+spendPct+'% of take-home. That\u2019s too high.</strong> Cut to 40-50% and you\u2019ll build $'+Math.round((altWealth3-wealth3)/1000)+'K more over just 3 years. Automate your savings first, then spend what\u2019s left \u2014 not the other way around.</div>';
    moveNum++;
  }
  h+='</div>';
  h+='<div style="font-size:11px;color:var(--text3);margin-top:10px;line-height:1.6">The physicians who build real wealth aren\u2019t the highest earners \u2014 they\u2019re the ones who got the fundamentals right in their first 3 years as an attending. Every month you delay these moves costs you real money.</div>';
  h+='</div>';

  // Bottom line: ONE strategy recommendation
  var topPriority='';var avoid='';
  if(disability!=='own_occ'){topPriority='Get own-occupation disability insurance. Everything else is secondary.';avoid='Do NOT delay this. Every day uninsured is a bet against your career.'}
  else if(debt>100000&&(employer==='nonprofit'||employer==='government')){topPriority='Maximize PSLF. Stay on IDR payments, certify employment annually, and do NOT refinance your federal loans.';avoid='Refinancing kills your PSLF eligibility. Some refinance companies market aggressively to physicians — don\u2019t fall for it.'}
  else if(debt>100000){topPriority='Aggressively refinance and pay down debt. Target a 3-5 year payoff.';avoid='Don\u2019t invest in taxable accounts while carrying 6%+ student loans. The guaranteed return on debt payoff beats market uncertainty.'}
  else if(has401k!=='maxed'){topPriority='Max your tax-advantaged accounts immediately. This is free money.';avoid='Don\u2019t buy a house, upgrade your car, or inflate your lifestyle before maxing retirement contributions.'}
  else if(spendPct>60){topPriority='Cut spending to 40-50% of take-home. Automate savings first, spend what\u2019s left.';avoid='Don\u2019t match your lifestyle to your salary. The residents-to-attending spending jump is the #1 wealth destroyer for physicians.'}
  else{topPriority='You\u2019re doing the fundamentals right. Focus on tax-loss harvesting, backdoor Roth, and optimizing your investment allocation.';avoid='Don\u2019t get complacent. Revisit your strategy annually and increase savings rate with every salary bump.'}
  h+='<div style="padding:14px;background:linear-gradient(160deg,rgba(200,168,124,.08),rgba(200,168,124,.02));border:1px solid rgba(198,168,94,.15);border-radius:10px;margin-bottom:14px">';
  h+='<div style="font-size:11px;font-weight:600;color:var(--accent);text-transform:uppercase;letter-spacing:1px;margin-bottom:8px">The bottom line</div>';
  h+='<div style="font-size:13px;color:var(--text);line-height:1.8;margin-bottom:8px"><strong>Do this:</strong> '+topPriority+'</div>';
  h+='<div style="font-size:12px;color:var(--red);line-height:1.6"><strong>Avoid:</strong> '+avoid+'</div>';
  h+='</div>';

  // hwPathway
  var fhGrade=scorePct>=80?'Strong':scorePct>=60?'Moderate':'Needs Attention';
  hwSetAssessmentContext('Financial Health Score','v11',['Your financial health score is <strong>'+scorePct+'%</strong> ('+fhGrade+').',topPriority.split('.').slice(0,2).join('.')+'.'],scorePct+'%',fhGrade);
  h+=hwGatePathway(hwPathway(scorePct>=80?'I\u2019ve seen what separates physicians who build wealth from those who don\u2019t. Your financial fundamentals are strong. Shift focus to optimizing, not just saving.':scorePct>=60?'Solid start but you have gaps. Fix the top action item above before anything else.':'This is one of those situations where acting now versus next quarter makes a real difference. Critical financial gaps. The priority moves above are in order. Do them this month, not next quarter.',
    [{text:topPriority.split('.')[0]+'.',when:'this week'},
     {text:debt>0?'Run a 30-year projection to see how debt payoff timing affects your net worth.':'Run a 30-year projection comparing your current savings rate vs 5% higher.',when:'this month'},
     {text:'Set a calendar reminder for quarterly financial review.',when:'this month'}],
    {id:'v11',icon:'\ud83d\udcc8',title:'Financial Planner',why:'See how today\u2019s decisions compound over 30 years. Small changes now become millions.'}));
  document.getElementById('ilp-results').innerHTML=h;

  // Lifetime Impact — financial gaps
  if(typeof hwLifetimeImpact==='function'&&scorePct<80){
    var ilpAlts=[];
    var ilpAnnualGap=0;
    if(disability==='no'||disability==='any'){
      var premiumCost=salary>200000?2400:1500;
      ilpAnnualGap+=premiumCost;
      ilpAlts.push({action:'Get own-occupation disability insurance immediately. 1 in 4 physicians becomes disabled before 65. "Any occupation" policies are nearly worthless for physicians.',impact:'Protects '+fmt2(salary*20)+' in career earnings for '+fmt2(premiumCost)+'/year premium'});
    }
    if(!has401k||has401k==='no'){
      ilpAnnualGap+=23500;
      ilpAlts.push({action:'Start maxing your 401k ($23,500/year). If your employer matches, that\'s free money you\'re burning.',impact:'+'+fmt2(23500)+'/year tax-deferred. At 7% return, that\'s $1.4M over 25 years.'});
    }
    if(debt>200000&&pslf!=='yes'){
      var refiSavings=Math.round(debt*0.02);
      ilpAnnualGap+=refiSavings;
      ilpAlts.push({action:'Refinance '+fmt2(debt)+' in student loans. Current rates may save you 2%+ on interest.',impact:fmt2(refiSavings)+'/year in interest savings'});
    }
    if(spending>salary*0.5){
      var spendGap=spending-Math.round(salary*0.4);
      ilpAnnualGap+=spendGap;
      ilpAlts.push({action:'Your spending is '+Math.round(spending/salary*100)+'% of gross income. Physicians who keep spending under 40% build wealth 3x faster.',impact:'Redirecting '+fmt2(spendGap)+'/year to investments'});
    }
    if(ilpAnnualGap>5000){
      document.getElementById('ilp-results').innerHTML+=hwLifetimeImpact({
        annual:-ilpAnnualGap,
        type:'gap',
        description:'Your financial gaps are costing you approximately '+fmt2(ilpAnnualGap)+'/year in missed savings, excess interest, and unprotected risk.',
        delayPerMonth:Math.round(ilpAnnualGap/12),
        comparison:'The median physician retires with $3.2M. Physicians who optimize disability + 401k + debt strategy in their first 3 years retire with $5M+. The gap is almost entirely explained by early decisions.',
        alternatives:ilpAlts
      });
    }
  }

  applyBlurGate(document.getElementById('ilp-results'));
  recordToolUse('Financial Planner',score+'/'+maxScore,grade+' ('+scorePct+'%)',{inputs:{Salary:'$'+salary.toLocaleString(),Debt:'$'+debt.toLocaleString(),Employer:employer,Disability:disability,Spending:'$'+spending.toLocaleString(),'Tax-Advantaged':has401k,Advisor:hasAdvisor},highlights:['Score: '+score+'/'+maxScore+' ('+grade+')'].concat(wins).concat(flags)});
  setTimeout(function(){injectCoachingOptin('Financial Planner')},100);
}
// ===== RESEARCH ROI CALCULATOR =====
function roiUpdate(){
  var first=parseInt(document.getElementById('roi-first').value)||0;
  var cases=parseInt(document.getElementById('roi-case').value)||0;
  var abstracts=parseInt(document.getElementById('roi-abstract').value)||0;
  var reviews=parseInt(document.getElementById('roi-review').value)||0;
  var middle=parseInt(document.getElementById('roi-middle').value)||0;
  var qi=parseInt(document.getElementById('roi-qi').value)||0;

  // Update value displays
  document.getElementById('roi-first-v').textContent=first;
  document.getElementById('roi-case-v').textContent=cases;
  document.getElementById('roi-abstract-v').textContent=abstracts;
  document.getElementById('roi-review-v').textContent=reviews;
  document.getElementById('roi-middle-v').textContent=middle;
  document.getElementById('roi-qi-v').textContent=qi;

  // Specialty selector and timeline
  var specEl=document.getElementById('roi-spec');
  var monthsEl=document.getElementById('roi-months');
  var spec=specEl?specEl.value:'';
  var months=monthsEl?parseInt(monthsEl.value)||0:0;

  // Point values per item
  var pts={first:15,cases:8,abstracts:5,reviews:6,middle:3,qi:2};
  var userScore=first*pts.first+cases*pts.cases+abstracts*pts.abstracts+reviews*pts.reviews+middle*pts.middle+qi*pts.qi;

  // Specialty-specific optimal benchmarks
  var specBenchmarks={derm:120,ortho:100,nsurg:110,plastics:100,ent:80,ophtho:80,uro:80,cards:90,gi:90,hemeonc:90,rads:60,gs:55,em:45,anes:45,neuro:45,im:30,fm:30,peds:30,psych:30,pulmcrit:50,other:53};
  var specNames={'':'Default',im:'Internal Medicine',fm:'Family Medicine',peds:'Pediatrics',em:'Emergency Medicine',psych:'Psychiatry',neuro:'Neurology',rads:'Radiology',anes:'Anesthesiology',gs:'General Surgery',ortho:'Orthopedic Surgery',nsurg:'Neurosurgery',derm:'Dermatology',ent:'ENT',uro:'Urology',ophtho:'Ophthalmology',plastics:'Plastic Surgery',cards:'Cardiology',gi:'GI',hemeonc:'Heme/Onc',pulmcrit:'Pulm/Crit',other:'Other'};
  var optimalScore=spec&&specBenchmarks[spec]?specBenchmarks[spec]:53;
  var pct=Math.min(100,Math.round((userScore/optimalScore)*100));

  // Grade
  var grade,gradeColor;
  if(pct>=90){grade='Excellent — Exceeds Optimal';gradeColor='var(--green)'}
  else if(pct>=70){grade='Strong — Competitive Portfolio';gradeColor='var(--green)'}
  else if(pct>=50){grade='Building — On Track';gradeColor='var(--accent)'}
  else if(pct>=25){grade='Early — Needs More High-Impact Work';gradeColor='var(--accent)'}
  else if(pct>0){grade='Just Starting — Focus on Quick Wins';gradeColor='var(--red)'}
  else{grade='Add your research to begin';gradeColor='var(--text3)'}

  document.getElementById('roi-score').textContent=pct+'%';
  document.getElementById('roi-score').style.color=gradeColor;
  document.getElementById('roi-grade').textContent=grade;
  document.getElementById('roi-grade').style.color=gradeColor;
  document.getElementById('roi-bar').style.width=pct+'%';

  // Breakdown
  var totalItems=first+cases+abstracts+reviews+middle+qi;
  var bd='';
  if(totalItems>0){
    bd+='<div style="display:flex;justify-content:space-between;padding:4px 0;border-bottom:1px solid var(--border)"><span>Total Items</span><strong>'+totalItems+'</strong></div>';
    bd+='<div style="display:flex;justify-content:space-between;padding:4px 0;border-bottom:1px solid var(--border)"><span>Portfolio Score</span><strong>'+userScore+' pts</strong></div>';
    bd+='<div style="display:flex;justify-content:space-between;padding:4px 0;border-bottom:1px solid var(--border)"><span>Optimal Benchmark'+(spec?' ('+specNames[spec]+')':'')+'</span><strong>'+optimalScore+' pts</strong></div>';

    // Weighted contribution breakdown
    var contribs=[];
    if(first)contribs.push({name:'First-Author',pts:first*pts.first,color:'var(--green)'});
    if(cases)contribs.push({name:'Case Reports',pts:cases*pts.cases,color:'var(--green)'});
    if(abstracts)contribs.push({name:'Abstracts',pts:abstracts*pts.abstracts,color:'var(--accent)'});
    if(reviews)contribs.push({name:'Reviews',pts:reviews*pts.reviews,color:'var(--accent)'});
    if(middle)contribs.push({name:'Middle-Author',pts:middle*pts.middle,color:'var(--text3)'});
    if(qi)contribs.push({name:'QI Projects',pts:qi*pts.qi,color:'var(--text3)'});
    contribs.sort(function(a,b){return b.pts-a.pts});

    bd+='<div style="margin-top:10px;font-size:11px;font-weight:600;color:var(--text3);text-transform:uppercase;letter-spacing:.5px;margin-bottom:6px">Contribution by Type</div>';
    contribs.forEach(function(c){
      var w=Math.round((c.pts/userScore)*100);
      bd+='<div style="margin-bottom:6px"><div style="display:flex;justify-content:space-between;margin-bottom:2px"><span>'+c.name+'</span><span style="color:'+c.color+'">'+c.pts+' pts ('+w+'%)</span></div>';
      bd+='<div style="height:3px;background:var(--bg);border-radius:2px;overflow:hidden"><div style="height:100%;width:'+w+'%;background:'+c.color+';border-radius:2px"></div></div></div>';
    });
  }
  document.getElementById('roi-breakdown').innerHTML=bd;

  // 3-Dimension Research Grading: Relevance, Authorship, Impact
  var dimHtml='';
  if(totalItems>0){
    // Authorship Quality (first-author dominance)
    var authScore=first>0?Math.min(100,Math.round((first*pts.first/(userScore||1))*100)):0;
    var authGrade=authScore>=60?'Strong':authScore>=30?'Mixed':'Weak';
    var authColor=authScore>=60?'var(--green)':authScore>=30?'var(--accent)':'var(--red)';
    var authExplain=authScore>=60?'First-author work dominates your portfolio. PDs see you as someone who drives research, not just participates.'
      :authScore>=30?'Mix of first and middle-author work. Shift toward first-author projects — they carry 3-5x the weight in applications.'
      :first===0?'No first-author work yet. This is your biggest research gap. Middle-author papers fill a CV but don\u2019t differentiate you.'
      :'Your portfolio is mostly middle-author. PDs will question whether you can lead a project independently.';

    // Relevance (specialty alignment — uses spec selection)
    var relScore=spec?Math.min(100,Math.round((userScore/optimalScore)*100)):Math.min(100,Math.round((userScore/53)*100));
    var relGrade=relScore>=80?'Aligned':relScore>=50?'Partial':'Misaligned';
    var relColor=relScore>=80?'var(--green)':relScore>=50?'var(--accent)':'var(--red)';
    var relExplain=spec?(relScore>=80?'Your output meets or exceeds the benchmark for '+specNames[spec]+'. You\u2019re publishing at the rate competitive applicants publish.'
      :relScore>=50?'Building toward the '+specNames[spec]+' benchmark ('+optimalScore+' pts). You need '+Math.max(0,optimalScore-userScore)+' more points to reach competitive.'
      :'Significantly below the '+specNames[spec]+' benchmark. You need '+(optimalScore-userScore)+' more points. At current pace, consider whether your timeline is realistic.')
      :'Select a specialty above for a specialty-specific relevance grade.';

    // Impact (weighted by publication type hierarchy)
    var highImpact=(first*pts.first+cases*pts.cases);
    var lowImpact=(middle*pts.middle+qi*pts.qi);
    var impactRatio=userScore>0?Math.round((highImpact/userScore)*100):0;
    var impactGrade=impactRatio>=70?'High':impactRatio>=40?'Moderate':'Low';
    var impactColor=impactRatio>=70?'var(--green)':impactRatio>=40?'var(--accent)':'var(--red)';
    var impactExplain=impactRatio>=70?'High-impact items (first-author + case reports) make up '+impactRatio+'% of your portfolio. Quality over quantity.'
      :impactRatio>=40?'Moderate impact mix. '+Math.round(100-impactRatio)+'% of your points come from lower-impact items (middle-author, QI). Shift toward first-author work.'
      :'Low-impact portfolio. '+Math.round(100-impactRatio)+'% of your points come from middle-author or QI work. PDs weigh first-author and case reports far more heavily.';

    dimHtml+='<div style="padding:14px;background:var(--bg2);border-radius:10px;border:1px solid var(--border);margin-bottom:14px">';
    dimHtml+='<div style="font-size:11px;font-weight:600;color:var(--accent);text-transform:uppercase;letter-spacing:1px;margin-bottom:12px">How your research actually stacks up</div>';

    // Authorship
    dimHtml+='<div style="margin-bottom:12px"><div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:4px"><span style="font-size:12px;font-weight:600;color:var(--text)">Authorship Quality</span><span style="font-size:11px;font-weight:700;color:'+authColor+'">'+authGrade.toUpperCase()+'</span></div>';
    dimHtml+='<div style="height:4px;background:var(--bg3);border-radius:2px;margin-bottom:4px"><div style="height:100%;width:'+authScore+'%;background:'+authColor+';border-radius:2px"></div></div>';
    dimHtml+='<div style="font-size:11px;color:var(--text3);line-height:1.5">'+authExplain+'</div></div>';

    // Relevance
    dimHtml+='<div style="margin-bottom:12px"><div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:4px"><span style="font-size:12px;font-weight:600;color:var(--text)">Specialty Relevance</span><span style="font-size:11px;font-weight:700;color:'+relColor+'">'+relGrade.toUpperCase()+'</span></div>';
    dimHtml+='<div style="height:4px;background:var(--bg3);border-radius:2px;margin-bottom:4px"><div style="height:100%;width:'+relScore+'%;background:'+relColor+';border-radius:2px"></div></div>';
    dimHtml+='<div style="font-size:11px;color:var(--text3);line-height:1.5">'+relExplain+'</div></div>';

    // Impact
    dimHtml+='<div><div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:4px"><span style="font-size:12px;font-weight:600;color:var(--text)">Portfolio Impact</span><span style="font-size:11px;font-weight:700;color:'+impactColor+'">'+impactGrade.toUpperCase()+'</span></div>';
    dimHtml+='<div style="height:4px;background:var(--bg3);border-radius:2px;margin-bottom:4px"><div style="height:100%;width:'+impactRatio+'%;background:'+impactColor+';border-radius:2px"></div></div>';
    dimHtml+='<div style="font-size:11px;color:var(--text3);line-height:1.5">'+impactExplain+'</div></div>';

    // "Your research is not helping you match because __"
    var weakestDim=authScore<=relScore&&authScore<=impactRatio?'authorship':relScore<=impactRatio?'relevance':'impact';
    var notHelpingBecause='';
    if(pct<70){
      if(weakestDim==='authorship')notHelpingBecause='<strong style="color:var(--red)">Your research is not helping you match because</strong> you don\u2019t have enough first-author work. PDs see middle-author papers as participation, not leadership. One first-author paper changes the narrative.';
      else if(weakestDim==='relevance')notHelpingBecause='<strong style="color:var(--red)">Your research is not helping you match because</strong> your output is below the competitive benchmark for '+(spec?specNames[spec]:'your target specialty')+'. You need '+(optimalScore-userScore)+' more points to reach competitive range.';
      else notHelpingBecause='<strong style="color:var(--red)">Your research is not helping you match because</strong> too much of your portfolio is low-impact work (middle-author, QI). PDs weight first-author and case reports far more heavily. Redirect your effort.';
      dimHtml+='<div style="margin-top:12px;padding:10px;background:rgba(239,68,68,.04);border-left:3px solid var(--red);border-radius:0 6px 6px 0;font-size:12px;color:var(--text2);line-height:1.6">'+notHelpingBecause+'</div>';
    }
    dimHtml+='</div>';
  }
  var dimEl=document.getElementById('roi-breakdown');
  if(dimEl&&dimHtml)dimEl.insertAdjacentHTML('afterend',dimHtml);

  // Efficiency chart — points per month of effort
  var effHtml='';
  if(totalItems>0){
    var effData=[
      {name:'Case Report',ppm:2.67,color:'var(--green)'},
      {name:'Abstract',ppm:2.50,color:'var(--green)'},
      {name:'First-Author',ppm:1.50,color:'var(--accent)'},
      {name:'Review Article',ppm:1.33,color:'var(--accent)'},
      {name:'Middle-Author',ppm:1.00,color:'var(--text3)'},
      {name:'QI Project',ppm:0.80,color:'var(--text3)'}
    ];
    var maxPpm=effData[0].ppm;
    effHtml+='<div style="font-size:11px;font-weight:600;color:var(--text3);text-transform:uppercase;letter-spacing:.5px;margin-bottom:10px">Efficiency: Points Per Month of Effort</div>';
    effData.forEach(function(e){
      var barW=Math.round((e.ppm/maxPpm)*100);
      effHtml+='<div style="margin-bottom:8px"><div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:3px"><span style="font-size:12px">'+e.name+'</span><span style="font-size:11px;font-weight:600;color:'+e.color+'">'+e.ppm.toFixed(2)+' pts/mo</span></div>';
      effHtml+='<div style="height:6px;background:var(--bg);border-radius:3px;overflow:hidden"><div style="height:100%;width:'+barW+'%;background:'+e.color+';border-radius:3px;transition:width .3s ease"></div></div></div>';
    });
  }
  var effEl=document.getElementById('roi-efficiency');
  if(effEl){
    if(effHtml){
      effEl.innerHTML='<div style="padding:14px;background:var(--bg2);border-radius:8px;border:1px solid var(--border)">'+effHtml+'</div>';
    }else{
      effEl.innerHTML='';
    }
  }

  // Advice
  var advice='';
  if(totalItems===0){
    advice='Start with a case report — it\'s the fastest path to your first publication (2-4 months). Then pursue a first-author original research project.';
  }else if(first===0&&pct<50){
    advice='Your most impactful next move: start a first-author original research project. One first-author paper outweighs 5 middle-author papers on your application.';
  }else if(first===1&&abstracts<2){
    advice='Good foundation with your first-author paper. Now submit 2-3 conference abstracts (ACC, AHA, or your specialty meeting) to build visibility with program directors.';
  }else if(first>=2&&cases===0){
    advice='Strong first-author output. Add a case report for portfolio diversity — it shows clinical observation skills and is a quick win (2-4 months).';
  }else if(pct>=70&&pct<90){
    advice='Competitive portfolio. To push to excellent: aim for one more first-author paper or target a higher-impact journal for your next submission.';
  }else if(pct>=90){
    advice='Outstanding research portfolio. You exceed the optimal benchmark. Focus your energy on strong letters of recommendation and interview preparation.';
  }else if(middle>first*2){
    advice='You have more middle-author than first-author papers. PDs weigh first-author work much more heavily. Prioritize driving your own project over contributing to others.';
  }else{
    advice='Keep building. Prioritize first-author work and conference abstracts — these have the highest ROI for your time investment.';
  }
  document.getElementById('roi-next').textContent=advice;

  // Next Best Move section
  var movesHtml='';
  if(totalItems>0){
    var activities=[
      {name:'First-Author Original',addPts:pts.first,minMo:8,maxMo:12,avgMo:10},
      {name:'Case Report',addPts:pts.cases,minMo:2,maxMo:4,avgMo:3},
      {name:'Conference Abstract',addPts:pts.abstracts,minMo:1,maxMo:3,avgMo:2},
      {name:'Review Article',addPts:pts.reviews,minMo:3,maxMo:6,avgMo:4.5},
      {name:'Middle-Author Paper',addPts:pts.middle,minMo:2,maxMo:4,avgMo:3},
      {name:'QI Project',addPts:pts.qi,minMo:2,maxMo:3,avgMo:2.5}
    ];
    activities.forEach(function(a){a.ppm=a.addPts/a.avgMo});
    activities.sort(function(a,b){return b.ppm-a.ppm});
    var topMoves=activities.slice(0,3);

    movesHtml+='<div style="font-size:11px;font-weight:600;color:var(--text3);text-transform:uppercase;letter-spacing:.5px;margin-bottom:10px">Next best moves, ranked by efficiency</div>';
    topMoves.forEach(function(m,i){
      var achievable=true;
      var warn='';
      if(months>0&&m.minMo>months){
        achievable=false;
        warn='<div style="font-size:10px;color:var(--red);margin-top:6px">May not finish within '+months+' months (needs '+m.minMo+'-'+m.maxMo+' mo)</div>';
      }else if(months>0&&m.avgMo<=months){
        warn='<div style="font-size:10px;color:var(--green);margin-top:6px">✓ Achievable within your timeline</div>';
      }else if(months>0){
        warn='<div style="font-size:10px;color:var(--accent);margin-top:6px">⚡ Tight — possible if started now ('+m.minMo+'-'+m.maxMo+' mo)</div>';
      }
      var newScore=userScore+m.addPts;
      var newPct=Math.min(100,Math.round((newScore/optimalScore)*100));
      movesHtml+='<div style="padding:12px;background:var(--bg2);border-radius:8px;border:1px solid var(--border);margin-bottom:8px'+((!achievable&&months>0)?';opacity:.7':'')+'">'+
        '<div style="display:flex;justify-content:space-between;align-items:center"><span style="font-weight:600;font-size:13px;color:var(--text)">#'+(i+1)+' '+m.name+'</span><span style="font-size:11px;font-weight:600;color:var(--accent)">+'+m.addPts+' pts</span></div>'+
        '<div style="display:flex;gap:16px;margin-top:6px;font-size:11px;color:var(--text2)">'+
        '<span>⏱ '+m.minMo+'-'+m.maxMo+' months</span>'+
        '<span>'+m.ppm.toFixed(2)+' pts/mo</span>'+
        '<span>→ '+newPct+'% of optimal</span>'+
        '</div>'+warn+'</div>';
    });
  }
  var movesEl=document.getElementById('roi-next-moves');
  if(movesEl)movesEl.innerHTML=movesHtml;

  // ───── WHAT MOVES THE NEEDLE (Research Simulation) ─────
  var needleHtml='';
  if(totalItems>0&&optimalScore>0){
    var sims=[
      {name:'Add 1 First-Author Paper',addPts:pts.first,minMo:6,maxMo:12,avgMo:9,tag:'HIGHEST IMPACT'},
      {name:'Add 1 Case Report',addPts:pts.cases,minMo:2,maxMo:4,avgMo:3,tag:'QUICK WIN'},
      {name:'Add 2 Conference Abstracts',addPts:pts.abstracts*2,minMo:2,maxMo:4,avgMo:3,tag:'FAST VISIBILITY'},
      {name:'Add 1 Review Article',addPts:pts.reviews,minMo:3,maxMo:6,avgMo:4,tag:null},
      {name:'Add 2 Middle-Author Papers',addPts:pts.middle*2,minMo:3,maxMo:6,avgMo:4,tag:null},
      {name:'Add 1 QI Project',addPts:pts.qi,minMo:2,maxMo:3,avgMo:2.5,tag:null}
    ];
    // Calculate ROI and new scores
    sims.forEach(function(s){
      s.newScore=userScore+s.addPts;
      s.newPct=Math.min(100,Math.round((s.newScore/optimalScore)*100));
      s.deltaPct=s.newPct-pct;
      s.roi=s.addPts/s.avgMo;
    });
    // Sort by ROI
    sims.sort(function(a,b){return b.roi-a.roi});
    // Best ROI tag
    if(sims[0])sims[0].tag='BEST ROI';

    // Filter to achievable if months specified
    var filteredSims=sims;
    if(months>0){
      filteredSims=sims.filter(function(s){return s.minMo<=months});
      if(filteredSims.length<3)filteredSims=sims.slice(0,4); // fallback
    }
    filteredSims=filteredSims.slice(0,5); // max 5

    needleHtml+='<div style="font-size:11px;font-weight:600;color:var(--accent);text-transform:uppercase;letter-spacing:1px;margin-bottom:4px">\ud83c\udfaf What Moves the Needle</div>';
    needleHtml+='<div style="font-size:11px;color:var(--text3);margin-bottom:14px">Each simulation shows the impact of one realistic action on your research portfolio score.</div>';

    filteredSims.forEach(function(s,i){
      var barWidth=Math.max(5,Math.min(100,s.deltaPct*5)); // visual scale
      needleHtml+='<div style="padding:12px 14px;background:var(--bg2);border:1px solid var(--border);border-radius:10px;margin-bottom:8px">';
      needleHtml+='<div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:6px">';
      needleHtml+='<div style="display:flex;align-items:center;gap:8px">';
      needleHtml+='<span style="font-size:12px;font-weight:600;color:var(--text)">'+(i+1)+'. '+s.name+'</span>';
      if(s.tag)needleHtml+='<span style="font-size:8px;padding:2px 6px;border-radius:100px;background:'+(s.tag==='BEST ROI'?'var(--accent-dim)':s.tag==='QUICK WIN'?'rgba(139,184,160,.12)':'rgba(139,173,196,.12)')+';color:'+(s.tag==='BEST ROI'?'var(--accent)':s.tag==='QUICK WIN'?'var(--green)':'var(--blue,#8badc4)')+';font-weight:600;letter-spacing:.3px">'+s.tag+'</span>';
      needleHtml+='</div>';
      needleHtml+='<span style="font-size:13px;font-weight:700;color:var(--green)">+'+s.deltaPct+'%</span>';
      needleHtml+='</div>';
      // Progress bar showing current → new
      needleHtml+='<div style="display:flex;align-items:center;gap:8px;margin-bottom:6px">';
      needleHtml+='<span style="font-size:10px;color:var(--text3);min-width:28px">'+pct+'%</span>';
      needleHtml+='<div style="flex:1;height:6px;background:var(--bg3);border-radius:3px;overflow:hidden;position:relative">';
      needleHtml+='<div style="position:absolute;height:100%;width:'+pct+'%;background:var(--accent);border-radius:3px;opacity:.4"></div>';
      needleHtml+='<div style="position:absolute;height:100%;width:'+s.newPct+'%;background:var(--green);border-radius:3px"></div>';
      needleHtml+='</div>';
      needleHtml+='<span style="font-size:10px;font-weight:600;color:var(--green);min-width:28px">'+s.newPct+'%</span>';
      needleHtml+='</div>';
      needleHtml+='<div style="display:flex;gap:16px;font-size:10px;color:var(--text3)">';
      needleHtml+='<span>\u23f1 '+s.minMo+'-'+s.maxMo+' months</span>';
      needleHtml+='<span>'+s.roi.toFixed(1)+' pts/mo ROI</span>';
      needleHtml+='<span>+'+s.addPts+' pts \u2192 '+s.newScore+' total</span>';
      needleHtml+='</div>';
      needleHtml+='</div>';
    });

    // Combined projection: top 3
    var top3=filteredSims.slice(0,3);
    var combinedAdd=0;top3.forEach(function(s){combinedAdd+=s.addPts});
    var combinedScore=userScore+combinedAdd;
    var combinedPct=Math.min(100,Math.round((combinedScore/optimalScore)*100));
    var combinedMaxMo=0;top3.forEach(function(s){if(s.maxMo>combinedMaxMo)combinedMaxMo=s.maxMo});

    needleHtml+='<div style="padding:14px;background:linear-gradient(160deg,rgba(200,168,124,.08),rgba(139,184,160,.06));border:1px solid rgba(198,168,94,.15);border-radius:10px;margin-top:10px">';
    needleHtml+='<div style="font-size:10px;font-weight:600;color:var(--accent);text-transform:uppercase;letter-spacing:.5px;margin-bottom:6px">COMBINED PROJECTION \u2014 Do All Top 3</div>';
    needleHtml+='<div style="display:flex;align-items:baseline;gap:8px;margin-bottom:4px">';
    needleHtml+='<span style="font-size:20px;font-weight:700;color:var(--text);font-family:var(--font-serif)">'+combinedPct+'%</span>';
    needleHtml+='<span style="font-size:12px;color:var(--green);font-weight:600">of optimal</span>';
    needleHtml+='<span style="font-size:11px;color:var(--text3)">(from '+pct+'%)</span>';
    needleHtml+='</div>';
    needleHtml+='<div style="font-size:11px;color:var(--text2);line-height:1.5">'+combinedAdd+' additional points in ~'+combinedMaxMo+' months. ';
    if(combinedPct>=90)needleHtml+='This would put you at excellent and above most applicants.';
    else if(combinedPct>=70)needleHtml+='This puts you in competitive range for '+(spec?specNames[spec]:'your target')+'.';
    else needleHtml+='Significant improvement, but you would still need more to be fully competitive.';
    needleHtml+='</div></div>';
  }
  var needleEl=document.getElementById('roi-needle');
  if(needleEl)needleEl.innerHTML=needleHtml;

  // Update benchmark text with specialty context
  var benchEl=document.getElementById('roi-benchmark-text');
  if(benchEl){
    if(spec&&specNames[spec]){
      benchEl.textContent='Optimal benchmark for '+specNames[spec]+': '+optimalScore+' pts. Based on NRMP Charting Outcomes data and specialty-specific competitiveness.';
    }else{
      benchEl.textContent='1-2 first-author papers + 2-3 abstracts + 1 case report = competitive applicant. Based on NRMP Charting Outcomes data for subspecialty fellowship matching.';
    }
  }

  // Pathway: position + prioritized actions + connect forward
  var linkEl=document.getElementById('roi-match-link');
  if(linkEl){
    if(totalItems>0){
      var roiPos=pct>=90?'Your research portfolio exceeds the benchmark for '+(spec?specNames[spec]:'your specialty')+'. Research is no longer your bottleneck — shift your energy to interview prep and letters.'
        :pct>=70?'Competitive portfolio for '+(spec?specNames[spec]:'your target')+'. You\'re in the fight. One more strategic publication pushes you to excellent.'
        :pct>=50?'You\'re building, but not competitive yet for '+(spec?specNames[spec]:'competitive specialties')+'. The next 2-3 months of focused effort will define your application.'
        :pct>=25?'Honest assessment: your research is below where it needs to be. But this is fixable if you start the right project today — not next month, today.'
        :'You\'re starting from zero. That\'s not fatal — some of the strongest applicants started late. But you need to move fast and pick high-ROI activities.';
      var roiActs=[];
      if(pct<50&&first===0)roiActs.push({text:'Start a case report this week. Fastest path to first publication (2-4 months). Pick a case you\'ve already seen.',when:'this week'});
      else if(pct<70&&first<2)roiActs.push({text:'Begin a first-author project. One first-author paper outweighs 5 middle-author credits.',when:'this week'});
      else if(pct>=70&&pct<90)roiActs.push({text:'Submit your next manuscript or target a higher-impact journal for maximum portfolio lift.',when:'this month'});
      else roiActs.push({text:'Shift focus to letters of recommendation — lock in 3 specialty-specific writers who know your work.',when:'this week'});
      if(abstracts<2)roiActs.push({text:'Submit 2 conference abstracts (ACC, AHA, or your specialty meeting). Fastest CV lines and PD visibility.',when:'this month'});
      else roiActs.push({text:'Follow up on submitted work — chase revisions, resubmit rejections, push pending manuscripts.',when:'this week'});
      if(pct<90)roiActs.push({text:'Check your actual match competitiveness with current stats — research is one piece of the puzzle.',when:'this month'});
      else roiActs.push({text:'Practice interview answers about your research — PDs will ask. Have a 60-second pitch for each project.',when:'this month'});
      var roiNxt=pct>=80?{id:'v16',icon:'\ud83c\udf99\ufe0f',title:'Interview Practice Tool',why:'Your research is strong — now practice selling it in interviews.'}
        :pct>=50?{id:'v14',icon:'\ud83c\udfc6',title:'Match Probability Calculator',why:'See how this research score combines with your other stats for a real match probability.'}
        :{id:'v14',icon:'\ud83c\udfc6',title:'Match Competitiveness Calculator',why:'Research is one factor. See your full competitiveness score and what moves the needle.'};
      hwSetAssessmentContext('Research Impact Calculator','v7',['Your research profile scores <strong>'+pct+'%</strong>.'+(firstAuthor<1?' No first-author papers detected. This is your highest-impact gap.':''),roiPos.split('.').slice(0,2).join('.')+'.'],pct+'%',pct>=80?'Strong':pct>=50?'Building':'Needs Work');
      linkEl.innerHTML=hwGatePathway(hwPathway(roiPos,roiActs,roiNxt));
    }else{
      linkEl.innerHTML='';
    }
  }

  // Record with resultData for saved scenarios
  if(totalItems>0){
    var roiInputs={'First-Author':first,'Case Reports':cases,'Abstracts':abstracts,'Reviews':reviews,'Middle-Author':middle,'QI Projects':qi};
    if(spec)roiInputs['Specialty']=specNames[spec]||spec;
    if(months)roiInputs['Months to Deadline']=months;
    var roiHL=[grade,'Portfolio Score: '+userScore+'/'+optimalScore+' pts','Total Items: '+totalItems];
    recordToolUse('Research Impact Calculator',pct+'%',grade,{inputs:roiInputs,highlights:roiHL});
    setTimeout(function(){injectCoachingOptin('Research Impact Calculator')},100);
  }
}

// ===== STRATEGIC AUDIT SUBMISSION =====
async function submitAudit(){
  var sections=[
    {title:'Current Position',fields:[
      {id:'audit-1a',label:'Current Position'},
      {id:'audit-1b',label:'Institution Strengths/Limitations'},
      {id:'audit-1c',label:'Financial Situation'},
      {id:'audit-1d',label:'CV Snapshot'},
      {id:'audit-1e',label:'Known For'}
    ]},
    {title:'The Decision',fields:[
      {id:'audit-2a',label:'Decision Facing'},
      {id:'audit-2b',label:'All Options Considered'},
      {id:'audit-2c',label:'Timeline'},
      {id:'audit-2d',label:'Already Tried'},
      {id:'audit-2e',label:'What\'s Holding Back'}
    ]},
    {title:'Values & Priorities',fields:[
      {id:'audit-3a',label:'Non-Negotiables'},
      {id:'audit-3b',label:'Willing to Sacrifice'},
      {id:'audit-3c',label:'Who Else Is Affected'},
      {id:'audit-3d',label:'Success in 1yr / 5yr'},
      {id:'audit-3e',label:'Will Regret Not Doing'}
    ]},
    {title:'Information & Risk',fields:[
      {id:'audit-4a',label:'Information Gaps'},
      {id:'audit-4b',label:'Who They\'ve Consulted'},
      {id:'audit-4c',label:'Worst Possible Outcome'},
      {id:'audit-4d',label:'Best Possible Outcome'},
      {id:'audit-4e',label:'Is It Reversible?'}
    ]}
  ];

  var filled=0;
  sections.forEach(function(s){s.fields.forEach(function(f){
    var el=document.getElementById(f.id);
    if(el&&el.value.trim())filled++;
  })});
  if(filled<3){notify('Please fill out at least a few sections before submitting.',1);return}

  var h='<div style="font-family:system-ui,sans-serif">';
  h+='<div style="font-size:16px;font-weight:700;margin-bottom:16px;color:#C6A85E">🎯 Strategic Intensive Report</div>';
  h+='<div style="font-size:11px;color:#7a756e;margin-bottom:16px">'+filled+' of 20 fields completed</div>';

  sections.forEach(function(sec){
    var secFilled=0;
    sec.fields.forEach(function(f){var el=document.getElementById(f.id);if(el&&el.value.trim())secFilled++});
    h+='<div style="margin-bottom:16px;padding:12px;background:rgba(198,168,94,.06);border:1px solid rgba(200,168,124,.1);border-radius:8px">';
    h+='<div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:10px">';
    h+='<div style="font-size:11px;font-weight:700;color:#C6A85E;text-transform:uppercase;letter-spacing:1px">'+sec.title+'</div>';
    h+='<div style="font-size:10px;color:#7a756e">'+secFilled+'/'+sec.fields.length+' answered</div>';
    h+='</div>';
    h+='<table style="width:100%;font-size:12px;border-collapse:collapse">';
    sec.fields.forEach(function(f){
      var el=document.getElementById(f.id);
      var val=el?el.value.trim():'';
      h+='<tr style="border-bottom:1px solid rgba(198,168,94,.06)">';
      h+='<td style="padding:6px 8px;color:#7a756e;width:35%;vertical-align:top;font-size:11px">'+f.label+'</td>';
      h+='<td style="padding:6px 8px">'+(val||'<em style="color:#7a756e;font-size:11px">Not answered</em>')+'</td>';
      h+='</tr>';
    });
    h+='</table></div>';
  });

  // Completion summary
  var pct=Math.round((filled/20)*100);
  var completionColor=pct>=80?'#6abf4b':pct>=50?'#c8a87c':'#ef4444';
  h+='<div style="padding:10px 12px;background:rgba(198,168,94,.04);border-radius:6px;display:flex;align-items:center;gap:10px">';
  h+='<div style="width:36px;height:36px;border-radius:50%;border:3px solid '+completionColor+';display:flex;align-items:center;justify-content:center;font-size:12px;font-weight:700;color:'+completionColor+';flex-shrink:0">'+pct+'%</div>';
  h+='<div><div style="font-size:12px;font-weight:600;color:'+completionColor+'">'+(pct>=80?'Comprehensive submission':pct>=50?'Partially complete':'Minimal detail')+'</div>';
  h+='<div style="font-size:10px;color:#7a756e">The more detail provided, the more actionable the review.</div></div></div>';
  h+='</div>';

  var payload={
    user_name:U?U.name:'Unknown',
    user_email:U?U.email:'Unknown',
    type:'audit',
    message:h,
    date:new Date().toISOString(),
    read:false,
    replies:[]
  };
  if(!DB.messages)DB.messages=[];
  DB.messages.push(payload);
  saveDB();
  if(_supaClient){
    try{await _supaClient.from('messages').insert([payload])}catch(ex){console.warn('Audit sync error',ex)}
  }
  document.getElementById('audit-form').classList.add('hidden');
  document.getElementById('audit-success').classList.remove('hidden');

  // Instant preliminary analysis — make it feel like a personal review
  var auditData={};
  sections.forEach(function(s){s.fields.forEach(function(f){var el=document.getElementById(f.id);auditData[f.id]=el?el.value.trim():''})});
  var position=auditData['audit-1a']||'';
  var cvSnap=auditData['audit-1d']||'';
  var decision=auditData['audit-2a']||'';
  var timeline=auditData['audit-2c']||'';
  var holdingBack=auditData['audit-2e']||'';
  var nonNeg=auditData['audit-3a']||'';
  var regret=auditData['audit-3e']||'';
  var worst=auditData['audit-4c']||'';
  var best=auditData['audit-4d']||'';
  var reversible=auditData['audit-4e']||'';

  // Build preliminary analysis
  var prelim='<div style="text-align:left;margin-top:24px">';
  prelim+='<div style="padding:20px;background:linear-gradient(160deg,rgba(200,168,124,.1),rgba(200,168,124,.03));border:1px solid rgba(198,168,94,.15);border-radius:14px;margin-bottom:16px">';
  prelim+='<div style="font-size:11px;font-weight:600;color:var(--accent);text-transform:uppercase;letter-spacing:1px;margin-bottom:10px">My preliminary read \u2014 Before Dr. Faroqui\u2019s Full Review</div>';
  prelim+='<div style="font-size:12px;color:var(--text2);line-height:1.8">';

  // Overall competitiveness snapshot
  if(cvSnap){
    var hasPubs=cvSnap.match(/\d+\s*(pub|paper|manuscript|article)/i);
    var hasScore=cvSnap.match(/(\d{3})\s*(step|score|board)/i);
    var hasLeadership=cvSnap.match(/chief|lead|director|captain|president/i);
    var compStrengths=[];var compGaps=[];
    if(hasPubs)compStrengths.push('research activity');else compGaps.push('research/publications');
    if(hasScore){var sc=parseInt(hasScore[1]);if(sc>=240)compStrengths.push('strong board scores');else if(sc<230)compGaps.push('board scores below competitive threshold')}
    if(hasLeadership)compStrengths.push('leadership experience');else compGaps.push('leadership roles');
    prelim+='<div style="margin-bottom:12px;padding:10px;background:var(--bg2);border-radius:8px"><strong>Overall Competitiveness:</strong> ';
    if(compStrengths.length>compGaps.length)prelim+='<span style="color:var(--green)">Competitive foundation</span> with strengths in '+compStrengths.join(', ')+'.';
    else if(compGaps.length)prelim+='<span style="color:var(--red)">Gaps identified</span> in '+compGaps.join(', ')+' that need addressing.';
    else prelim+='More detail needed for full assessment.';
    if(compGaps.length)prelim+=' <strong>Fix plan:</strong> '+compGaps[0]+' should be your #1 priority.';
    prelim+='</div>';
  }

  // Red flags from their answers
  prelim+='<div style="margin-bottom:12px"><strong>Potential Red Flags:</strong></div>';
  prelim+='<div style="display:flex;flex-direction:column;gap:6px;margin-bottom:12px">';
  if(holdingBack&&holdingBack.length>10)prelim+='<div style="padding:8px 10px;background:rgba(239,68,68,.04);border-left:3px solid var(--red);border-radius:0 6px 6px 0;font-size:11px;color:var(--text2)"><strong style="color:var(--red)">Indecision paralysis:</strong> You identified what\u2019s holding you back. The biggest risk isn\u2019t making the wrong choice \u2014 it\u2019s making no choice while the window closes.</div>';
  if(filled<10)prelim+='<div style="padding:8px 10px;background:rgba(239,68,68,.04);border-left:3px solid var(--red);border-radius:0 6px 6px 0;font-size:11px;color:var(--text2)"><strong style="color:var(--red)">Incomplete submission ('+filled+'/20):</strong> The gaps in your submission may reflect gaps in your own clarity about this decision. Consider revisiting the unanswered questions.</div>';
  if(worst&&worst.toLowerCase().indexOf('don\'t know')>=0)prelim+='<div style="padding:8px 10px;background:rgba(239,68,68,.04);border-left:3px solid var(--red);border-radius:0 6px 6px 0;font-size:11px;color:var(--text2)"><strong style="color:var(--red)">Undefined downside risk:</strong> You haven\u2019t clearly defined the worst outcome. This suggests you may be avoiding confronting the real stakes.</div>';
  if(!worst&&!best)prelim+='<div style="padding:8px 10px;background:rgba(200,168,124,.06);border-left:3px solid var(--accent);border-radius:0 6px 6px 0;font-size:11px;color:var(--text2)"><strong style="color:var(--accent)">Risk assessment incomplete:</strong> Without defining best and worst outcomes, you\u2019re making this decision with incomplete data.</div>';
  prelim+='</div>';

  // Strengths
  prelim+='<div style="margin-bottom:12px"><strong style="color:var(--green)">What\u2019s Working:</strong></div>';
  prelim+='<div style="display:flex;flex-direction:column;gap:6px;margin-bottom:12px">';
  if(decision&&decision.length>20)prelim+='<div style="padding:8px 10px;background:rgba(106,191,75,.04);border-left:3px solid var(--green);border-radius:0 6px 6px 0;font-size:11px;color:var(--text2)">You\u2019ve clearly articulated the decision. Most people never get this far \u2014 clarity is the first step.</div>';
  if(regret&&regret.length>10)prelim+='<div style="padding:8px 10px;background:rgba(106,191,75,.04);border-left:3px solid var(--green);border-radius:0 6px 6px 0;font-size:11px;color:var(--text2)">You\u2019ve done the regret test. Your answer reveals what actually matters to you \u2014 Dr. Faroqui will use this as a compass.</div>';
  if(nonNeg&&nonNeg.length>10)prelim+='<div style="padding:8px 10px;background:rgba(106,191,75,.04);border-left:3px solid var(--green);border-radius:0 6px 6px 0;font-size:11px;color:var(--text2)">Your non-negotiables are defined. This eliminates options that would make you miserable, even if they look good on paper.</div>';
  if(reversible)prelim+='<div style="padding:8px 10px;background:rgba(106,191,75,.04);border-left:3px solid var(--green);border-radius:0 6px 6px 0;font-size:11px;color:var(--text2)">You\u2019ve considered reversibility. '+(reversible.toLowerCase().indexOf('yes')>=0?'Knowing this is reversible should give you confidence to act.':'Knowing this is irreversible means the analysis matters even more. Dr. Faroqui will weigh this heavily.')+'</div>';
  prelim+='</div>';

  // What's holding you back
  if(holdingBack){
    prelim+='<div style="margin-bottom:12px"><strong>\ud83e\udde0 What\u2019s Holding You Back:</strong></div>';
    prelim+='<div style="padding:10px;background:var(--bg2);border-radius:8px;font-size:12px;color:var(--text2);line-height:1.7;font-style:italic;margin-bottom:12px">\u201c'+holdingBack+'\u201d</div>';
    prelim+='<div style="font-size:11px;color:var(--text2);margin-bottom:12px">Dr. Faroqui will address this directly in the full review. Expect a specific plan to overcome this barrier.</div>';
  }

  // Chances improvement estimate — "from X → Y"
  if(cvSnap){
    var compScore2=(compStrengths.length*30)-((compGaps.length)*20)+40;
    compScore2=Math.max(10,Math.min(90,compScore2));
    var improvedScore2=Math.min(95,compScore2+20+Math.round(filled/20*15));
    prelim+='<div style="margin-bottom:16px;padding:16px;background:linear-gradient(160deg,rgba(200,168,124,.08),rgba(200,168,124,.02));border:1px solid rgba(198,168,94,.15);border-radius:10px">';
    prelim+='<div style="font-size:11px;font-weight:600;color:var(--accent);text-transform:uppercase;letter-spacing:1px;margin-bottom:8px">If You Follow the Plan</div>';
    prelim+='<div style="display:flex;align-items:center;gap:16px;justify-content:center">';
    prelim+='<div style="text-align:center"><div style="font-size:10px;color:var(--text3);margin-bottom:4px">Current Estimate</div><div style="font-size:28px;font-weight:700;color:'+(compScore2>=50?'var(--accent)':'var(--red)')+';font-family:var(--font-serif)">'+compScore2+'%</div></div>';
    prelim+='<div style="font-size:24px;color:var(--accent)">\u2192</div>';
    prelim+='<div style="text-align:center"><div style="font-size:10px;color:var(--text3);margin-bottom:4px">After Fix Plan</div><div style="font-size:28px;font-weight:700;color:var(--green);font-family:var(--font-serif)">'+improvedScore2+'%</div></div>';
    prelim+='</div>';
    prelim+='<div style="font-size:11px;color:var(--text3);text-align:center;margin-top:8px">Based on your CV snapshot'+(compGaps.length?'. Closing gaps in '+compGaps.join(', ')+' drives the biggest improvement.':'. Dr. Faroqui\u2019s full review will refine this estimate.')+'</div>';
    prelim+='</div>';
  }else{
    prelim+='<div style="margin-bottom:16px;padding:12px;background:var(--bg2);border-radius:8px;font-size:12px;color:var(--text3);text-align:center;line-height:1.6">Complete Part 1 (CV snapshot) for a preliminary competitiveness estimate and improvement projection.</div>';
  }

  prelim+='</div></div>';

  // hwPathway
  prelim+=hwGatePathway(hwPathway('Your audit is submitted. While waiting for Dr. Faroqui\u2019s full review, use these tools to build more data for your decision.',[
    {text:'Run the '+(!cvSnap||cvSnap.match(/pub|research/i)?'Match Probability Calculator':' Match Competitiveness Calculator')+' to get an objective competitiveness score.',when:'this week'},
    {text:'Model the financial implications of your top 2 options in the Financial Planner.',when:'this week'},
    {text:'When Dr. Faroqui\u2019s review arrives, build your execution plan in the Career Roadmap Tool.',when:'after review'}
  ],decision&&decision.match(/fellowship|match|apply/i)?{id:'v14',icon:'\ud83d\udcca',title:'Match Competitiveness Calculator',why:'Get your competitiveness score while you wait. Data + expert review = best possible decision.'}
    :decision&&decision.match(/contract|offer|job/i)?{id:'v12',icon:'\ud83d\udcdd',title:'Contract Review Tool',why:'If you have an offer on the table, score it now. Don\u2019t wait for the review to act on time-sensitive terms.'}
    :{id:'v15',icon:'\ud83d\uddfa\ufe0f',title:'Career Roadmap Tool',why:'Build a preliminary timeline while you wait. Dr. Faroqui\u2019s review will refine it.'}));

  prelim+='</div>';
  document.getElementById('audit-success').innerHTML='<div style="font-size:48px;margin-bottom:16px">\u2713</div><h3 class="serif" style="font-size:20px;margin-bottom:8px">Audit Submitted</h3><p style="font-size:13px;color:var(--text2);line-height:1.6;margin-bottom:6px">Your strategic audit has been sent to Dr. Faroqui. Expect a response within 7 business days.</p><p style="font-size:11px;color:var(--text3);margin-bottom:20px">'+filled+'/20 fields completed \u2014 '+(filled>=15?'comprehensive submission':'consider revisiting and adding more detail for a stronger review')+'</p>'+prelim;
  notify('Strategic audit submitted!');
  recordToolUse('Application Review',null,'Application review submitted for review');
  notifyAdmin(payload);
}

// ===== CAREER PIVOT DECISION ENGINE =====
var PIVOT_PROS_CONS={
  specialty:{
    title:'The Specialty Itself',
    pros:['Clear signal that a pivot may be warranted','You\'ve given the field a fair shot and can speak to it honestly','Transferable clinical skills remain valuable in adjacent specialties'],
    cons:['Full pivot is the most expensive and time-consuming option','Sunk cost of training years can create psychological resistance','May need to repeat fellowship or complete additional residency']
  },
  setting:{
    title:'The Practice Setting',
    pros:['Easiest to fix — same skills, different environment','No additional training typically required','Can test quickly (locum tenens, moonlighting, telemedicine)'],
    cons:['Risk of carrying the same patterns to a new setting','May need to relocate or accept different compensation','Cultural issues can exist across settings in the same specialty']
  },
  job:{
    title:'The Specific Job / Employer',
    pros:['Most common and most fixable root cause','Job change within specialty preserves all your training investment','Often leads to significant improvement in satisfaction and compensation'],
    cons:['May take 6-12 months to find the right replacement position','Non-compete clauses can limit local options','Risk of "grass is greener" thinking if the issue is deeper']
  },
  burnout:{
    title:'Burnout',
    pros:['Recognition is the first step — most physicians ignore this for years','Treatable with targeted interventions (therapy, boundaries, time off)','Often improves significantly without any career change'],
    cons:['Burnout distorts all decision-making — high risk of impulsive pivots','Can mask underlying structural misalignment','Recovery timeline is unpredictable (months to years)']
  }
};

var PIVOT_BURNOUT_FEEDBACK={
  burnout:{
    title:'Likely Burned Out',
    msg:'If you used to love this work and now feel exhausted or detached, burnout is the most likely explanation. Before making any career moves: take time off if possible, establish firm boundaries, and consider working with a therapist who understands physician burnout. Decisions made during burnout are often regretted.'
  },
  misaligned:{
    title:'Possible Structural Misalignment',
    msg:'If this field never felt right, the issue is likely structural rather than situational. This is a stronger signal that a pivot may be warranted. Focus on Step 2 to map your options carefully and Step 3 to ensure financial readiness.'
  },
  unsure:{
    title:'Unclear — Needs More Data',
    msg:'This is common and honest. Try this: take 2 weeks of vacation (real vacation, no email). If you dread coming back, it\'s likely misalignment. If you feel recharged and ready, it\'s likely burnout. Don\'t make permanent decisions based on temporary feelings.'
  }
};

function pivotSelect(el,group){
  // Highlight selected option
  var container=document.getElementById(group);
  if(container){
    container.querySelectorAll('label').forEach(function(l){l.style.borderColor='var(--border)';l.style.background='var(--bg2)'});
    el.style.borderColor='var(--accent)';el.style.background='rgba(198,168,94,.08)';
  }
  var val=el.querySelector('input').value;
  var fb=document.getElementById(group+'-feedback');
  if(!fb)return;

  if(group==='pivot-cause'){
    // Show/hide other text field
    var otherBox=document.getElementById('pivot-cause-other');
    if(otherBox){otherBox.classList.toggle('hidden',val!=='other')}
    if(PIVOT_PROS_CONS[val]){
      var data=PIVOT_PROS_CONS[val];
    var h='<div style="padding:14px;background:rgba(198,168,94,.04);border:1px solid rgba(198,168,94,.15);border-radius:8px;animation:fadeIn .3s">';
    h+='<div style="font-size:12px;font-weight:600;color:var(--accent);margin-bottom:10px">'+data.title+'</div>';
    h+='<div style="display:flex;gap:12px;flex-wrap:wrap">';
    h+='<div style="flex:1;min-width:140px"><div style="font-size:10px;font-weight:600;color:var(--green);margin-bottom:6px">PROS</div>';
    data.pros.forEach(function(p){h+='<div style="font-size:11px;color:var(--text2);line-height:1.5;padding:2px 0">+ '+p+'</div>'});
    h+='</div>';
    h+='<div style="flex:1;min-width:140px"><div style="font-size:10px;font-weight:600;color:var(--red);margin-bottom:6px">CONS</div>';
    data.cons.forEach(function(c){h+='<div style="font-size:11px;color:var(--text2);line-height:1.5;padding:2px 0">\u2013 '+c+'</div>'});
    h+='</div></div></div>';
    fb.innerHTML=h;
  }else if(val==='other'){
    fb.innerHTML='<div style="padding:10px;background:rgba(198,168,94,.04);border-radius:6px;font-size:11px;color:var(--text2);line-height:1.5;animation:fadeIn .3s">Describe your situation in the field above. Dr. Faroqui will review the full context in your submitted report.</div>';
  }
  }
  if(group==='pivot-burnout'&&PIVOT_BURNOUT_FEEDBACK[val]){
    var d=PIVOT_BURNOUT_FEEDBACK[val];
    fb.innerHTML='<div style="padding:12px;background:rgba(198,168,94,.04);border:1px solid rgba(198,168,94,.15);border-radius:8px;animation:fadeIn .3s"><div style="font-size:12px;font-weight:600;color:var(--accent);margin-bottom:6px">'+d.title+'</div><p style="font-size:11px;color:var(--text2);line-height:1.6;margin:0">'+d.msg+'</p></div>';
  }
  if(group==='pivot-regret'){
    if(val==='yes'){
      fb.innerHTML='<div style="padding:10px;background:rgba(198,168,94,.04);border-radius:6px;font-size:11px;color:var(--text2);line-height:1.5;animation:fadeIn .3s"><strong style="color:var(--accent)">That\'s a strong signal.</strong> Regret avoidance is one of the most reliable decision-making heuristics. If the financial reality supports it, this pivot deserves serious consideration.</div>';
    }else{
      fb.innerHTML='<div style="padding:10px;background:rgba(198,168,94,.04);border-radius:6px;font-size:11px;color:var(--text2);line-height:1.5;animation:fadeIn .3s"><strong style="color:var(--accent)">Good to know.</strong> If you won\'t regret staying, consider whether smaller adjustments (setting change, boundary changes, role modification) could address your dissatisfaction without a full pivot.</div>';
    }
  }
}

function pivotCalcAvg(){
  var rows=['stay','adj','full','hyb'];
  var dims=['f','i','t','s'];
  var best='';var bestAvg=0;
  var labels={stay:'Stay + Modify',adj:'Adjacent Pivot',full:'Full Pivot',hyb:'Hybrid'};
  rows.forEach(function(r){
    var sum=0;var count=0;
    dims.forEach(function(d){
      var v=parseInt(document.getElementById('pv-'+r+'-'+d).value);
      if(v){sum+=v;count++}
    });
    var avg=count===4?(sum/4).toFixed(1):'\u2014';
    document.getElementById('pv-'+r+'-avg').textContent=avg;
    if(count===4&&parseFloat(avg)>bestAvg){bestAvg=parseFloat(avg);best=r}
  });
  var rec=document.getElementById('pivot-recommendation');
  if(best&&rec){
    var color=bestAvg>=4?'var(--green)':bestAvg>=3?'var(--accent)':'var(--text3)';
    rec.innerHTML='<div style="padding:10px;background:rgba(198,168,94,.04);border-radius:6px;font-size:12px;color:var(--text2);line-height:1.5"><strong style="color:'+color+'">Highest rated: '+labels[best]+' ('+bestAvg.toFixed(1)+'/5.0)</strong></div>';
  }
}

function pivotCalcTraining(){
  var yrs=parseFloat(document.getElementById('pivot-train-yrs').value)||0;
  var tuition=parseFloat(document.getElementById('pivot-train-cost').value)||0;
  var salary=parseFloat(document.getElementById('pivot-train-salary').value)||0;
  var stipend=parseFloat(document.getElementById('pivot-train-stipend').value)||0;
  if(yrs===0){document.getElementById('pivot-train-result').innerHTML='<span style="font-size:12px;color:var(--text3)">Enter values above to calculate total cost</span>';return}
  var directCost=yrs*tuition;
  var opportunityCost=yrs*(salary-stipend);
  var totalCost=directCost+Math.max(0,opportunityCost);
  var el=document.getElementById('pivot-train-result');
  var h='<div style="font-size:11px;color:var(--text2);line-height:1.8;text-align:left">';
  h+='<div style="display:flex;justify-content:space-between"><span>Direct cost (tuition \u00d7 '+yrs+'yr)</span><strong>$'+directCost.toLocaleString()+'</strong></div>';
  h+='<div style="display:flex;justify-content:space-between"><span>Opportunity cost (lost salary \u2013 stipend)</span><strong>$'+Math.max(0,opportunityCost).toLocaleString()+'</strong></div>';
  h+='<div style="display:flex;justify-content:space-between;padding-top:6px;border-top:1px solid var(--border);margin-top:6px"><span style="font-weight:600">Total cost of transition</span><strong style="color:var(--accent);font-size:14px">$'+totalCost.toLocaleString()+'</strong></div>';
  h+='</div>';
  el.innerHTML=h;
}

async function submitPivot(){
  // Collect structured data
  var cause=document.querySelector('input[name="pivot-cause"]:checked');
  var causeLabel=cause?(PIVOT_PROS_CONS[cause.value]?PIVOT_PROS_CONS[cause.value].title:'Other'):'Not selected';
  var causeOther='';
  if(cause&&cause.value==='other'){var otherText=document.getElementById('pivot-cause-other-text');if(otherText&&otherText.value.trim())causeOther=otherText.value.trim()}
  var burnout=document.querySelector('input[name="pivot-burnout"]:checked');

  var rows=['stay','adj','full','hyb'];
  var labels={stay:'Stay + Modify',adj:'Adjacent Pivot',full:'Full Pivot',hyb:'Hybrid'};
  var dims=['f','i','t','s'];
  var options=[];
  rows.forEach(function(r){
    var vals={};
    dims.forEach(function(d){vals[d]=parseInt(document.getElementById('pv-'+r+'-'+d).value)||0});
    var avg=document.getElementById('pv-'+r+'-avg').textContent;
    options.push({key:r,label:labels[r],f:vals.f,i:vals.i,t:vals.t,s:vals.s,avg:avg});
  });

  var yrs=parseFloat(document.getElementById('pivot-train-yrs').value)||0;
  var cost=parseFloat(document.getElementById('pivot-train-cost').value)||0;
  var sal=parseFloat(document.getElementById('pivot-train-salary').value)||0;
  var stip=parseFloat(document.getElementById('pivot-train-stipend').value)||0;
  var trainCost=yrs>0?Math.round((yrs*cost)+(yrs*Math.max(0,sal-stip))):0;

  var checks=[];
  var checkLabels=['Shadow new role','Informational interviews (3+)','Side project / moonlighting','Decision deadline set'];
  for(var i=1;i<=4;i++){checks.push({label:checkLabels[i-1],done:document.getElementById('pv-check-'+i).checked})}
  var regret=document.querySelector('input[name="pivot-regret"]:checked');
  var readiness=checks.filter(function(c){return c.done}).length;

  // Build clean HTML report
  var h='<div style="font-family:system-ui,sans-serif">';
  h+='<div style="font-size:16px;font-weight:700;margin-bottom:16px;color:#C6A85E">📊 Specialty & Career Fit Report</div>';

  // Step 1
  h+='<div style="margin-bottom:16px;padding:12px;background:rgba(198,168,94,.06);border:1px solid rgba(200,168,124,.1);border-radius:8px">';
  h+='<div style="font-size:11px;font-weight:700;color:#C6A85E;text-transform:uppercase;letter-spacing:1px;margin-bottom:8px">Step 1: Diagnose the Dissatisfaction</div>';
  h+='<table style="width:100%;font-size:12px;border-collapse:collapse">';
  h+='<tr><td style="padding:4px 8px;color:#7a756e;width:40%">Core Issue</td><td style="padding:4px 8px;font-weight:600">'+causeLabel+(causeOther?' — '+causeOther:'')+'</td></tr>';
  h+='<tr><td style="padding:4px 8px;color:#7a756e">What they dislike</td><td style="padding:4px 8px">'+(document.getElementById('pivot-1a').value.trim()||'<em style="color:#7a756e">Not answered</em>')+'</td></tr>';
  h+='<tr><td style="padding:4px 8px;color:#7a756e">Same specialty, different setting?</td><td style="padding:4px 8px">'+(document.getElementById('pivot-1b').value.trim()||'<em style="color:#7a756e">Not answered</em>')+'</td></tr>';
  h+='<tr><td style="padding:4px 8px;color:#7a756e">Burnout vs Misaligned</td><td style="padding:4px 8px;font-weight:600">'+(burnout?burnout.value:'<em style="color:#7a756e">Not selected</em>')+'</td></tr>';
  h+='</table></div>';

  // Step 2 — Options comparison chart
  h+='<div style="margin-bottom:16px;padding:12px;background:rgba(198,168,94,.06);border:1px solid rgba(200,168,124,.1);border-radius:8px">';
  h+='<div style="font-size:11px;font-weight:700;color:#C6A85E;text-transform:uppercase;letter-spacing:1px;margin-bottom:8px">Step 2: Options Comparison</div>';
  h+='<table style="width:100%;font-size:11px;border-collapse:collapse;text-align:center">';
  h+='<tr style="border-bottom:2px solid rgba(198,168,94,.15)"><th style="padding:6px;text-align:left;color:#7a756e">Option</th><th style="padding:6px;color:#7a756e">Feasibility</th><th style="padding:6px;color:#7a756e">Financial</th><th style="padding:6px;color:#7a756e">Timeline</th><th style="padding:6px;color:#7a756e">Satisfaction</th><th style="padding:6px;color:#C6A85E;font-weight:700">Avg</th></tr>';
  var bestAvg=0;var bestKey='';
  options.forEach(function(o){var a=parseFloat(o.avg);if(a>bestAvg){bestAvg=a;bestKey=o.key}});
  options.forEach(function(o){
    var isBest=o.key===bestKey&&bestAvg>0;
    var rowStyle=isBest?'background:rgba(106,191,75,.06);':'';
    function scoreColor(v){if(!v||v===0)return'color:#7a756e';if(v>=8)return'color:#6abf4b;font-weight:700';if(v>=5)return'color:#C6A85E';return'color:#ef4444'}
    h+='<tr style="border-bottom:1px solid rgba(198,168,94,.08);'+rowStyle+'">';
    h+='<td style="padding:6px;text-align:left;font-weight:600">'+(isBest?'✦ ':'')+o.label+'</td>';
    h+='<td style="padding:6px;'+scoreColor(o.f)+'">'+(o.f||'—')+'</td>';
    h+='<td style="padding:6px;'+scoreColor(o.i)+'">'+(o.i||'—')+'</td>';
    h+='<td style="padding:6px;'+scoreColor(o.t)+'">'+(o.t||'—')+'</td>';
    h+='<td style="padding:6px;'+scoreColor(o.s)+'">'+(o.s||'—')+'</td>';
    h+='<td style="padding:6px;font-weight:700;color:#C6A85E">'+o.avg+'</td>';
    h+='</tr>';
  });
  h+='</table>';
  if(bestKey&&bestAvg>0) h+='<div style="margin-top:8px;font-size:11px;color:#6abf4b;font-weight:600">✦ Highest scoring: '+labels[bestKey]+' ('+bestAvg.toFixed(1)+')</div>';
  h+='</div>';

  // Step 3
  h+='<div style="margin-bottom:16px;padding:12px;background:rgba(198,168,94,.06);border:1px solid rgba(200,168,124,.1);border-radius:8px">';
  h+='<div style="font-size:11px;font-weight:700;color:#C6A85E;text-transform:uppercase;letter-spacing:1px;margin-bottom:8px">Step 3: Financial Reality Check</div>';
  h+='<table style="width:100%;font-size:12px;border-collapse:collapse">';
  h+='<tr><td style="padding:4px 8px;color:#7a756e;width:40%">Debt / obligations</td><td style="padding:4px 8px">'+(document.getElementById('pivot-3a').value.trim()||'<em style="color:#7a756e">Not answered</em>')+'</td></tr>';
  h+='<tr><td style="padding:4px 8px;color:#7a756e">Sustain reduced income?</td><td style="padding:4px 8px">'+(document.getElementById('pivot-3b').value.trim()||'<em style="color:#7a756e">Not answered</em>')+'</td></tr>';
  h+='<tr><td style="padding:4px 8px;color:#7a756e">Comparable earning potential?</td><td style="padding:4px 8px">'+(document.getElementById('pivot-3c').value.trim()||'<em style="color:#7a756e">Not answered</em>')+'</td></tr>';
  if(trainCost>0) h+='<tr><td style="padding:4px 8px;color:#7a756e">Retraining cost estimate</td><td style="padding:4px 8px;font-weight:600;color:#ef4444">$'+trainCost.toLocaleString()+' <span style="font-weight:400;color:#7a756e;font-size:11px">('+yrs+' yrs)</span></td></tr>';
  h+='<tr><td style="padding:4px 8px;color:#7a756e">Emergency fund?</td><td style="padding:4px 8px">'+(document.getElementById('pivot-3d').value.trim()||'<em style="color:#7a756e">Not answered</em>')+'</td></tr>';
  h+='</table></div>';

  // Step 4 — Readiness
  h+='<div style="margin-bottom:16px;padding:12px;background:rgba(198,168,94,.06);border:1px solid rgba(200,168,124,.1);border-radius:8px">';
  h+='<div style="font-size:11px;font-weight:700;color:#C6A85E;text-transform:uppercase;letter-spacing:1px;margin-bottom:8px">Step 4: Readiness Check</div>';
  h+='<div style="display:grid;grid-template-columns:1fr 1fr;gap:6px;margin-bottom:10px">';
  checks.forEach(function(c){
    var bg=c.done?'rgba(106,191,75,.08)':'rgba(239,68,68,.05)';
    var bdr=c.done?'rgba(106,191,75,.2)':'rgba(239,68,68,.12)';
    var clr=c.done?'#6abf4b':'#ef4444';
    h+='<div style="padding:8px 10px;background:'+bg+';border:1px solid '+bdr+';border-radius:6px;font-size:11px">';
    h+='<span style="color:'+clr+';font-weight:600">'+(c.done?'✅':'❌')+'</span> '+c.label+'</div>';
  });
  h+='</div>';
  var regretVal=regret?regret.value:'not answered';
  h+='<div style="font-size:12px"><span style="color:#7a756e">Will regret not trying in 5 years:</span> <strong>'+(regretVal==='yes'?'Yes — strong signal to act':regretVal==='no'?'No — may not be the right move':regretVal==='unsure'?'Unsure':regretVal)+'</strong></div>';
  // Readiness score
  var readyColor=readiness>=3?'#6abf4b':readiness>=2?'#c8a87c':'#ef4444';
  var readyLabel=readiness>=3?'Ready to decide':readiness>=2?'Almost ready':'More groundwork needed';
  h+='<div style="margin-top:10px;padding:8px 12px;background:rgba(198,168,94,.04);border-radius:6px;display:flex;align-items:center;gap:10px">';
  h+='<div style="width:36px;height:36px;border-radius:50%;border:3px solid '+readyColor+';display:flex;align-items:center;justify-content:center;font-size:14px;font-weight:700;color:'+readyColor+';flex-shrink:0">'+readiness+'/4</div>';
  h+='<div><div style="font-size:12px;font-weight:600;color:'+readyColor+'">'+readyLabel+'</div><div style="font-size:10px;color:#7a756e">Readiness checklist completion</div></div>';
  h+='</div>';
  h+='</div>';
  h+='</div>';

  var payload={
    user_name:U?U.name:'Unknown',
    user_email:U?U.email:'Unknown',
    type:'pivot-report',
    message:h,
    date:new Date().toISOString(),
    read:false,
    replies:[]
  };
  if(!DB.messages)DB.messages=[];
  DB.messages.push(payload);
  saveDB();
  if(_supaClient){
    try{await _supaClient.from('messages').insert([payload])}catch(ex){console.warn('Pivot sync error',ex)}
  }
  document.getElementById('pivot-form').classList.add('hidden');
  document.getElementById('pivot-success').classList.remove('hidden');
  // Pathway: position + prioritized actions + connect forward
  var pvBest=options.slice().sort(function(a,b){return parseFloat(b.avg)-parseFloat(a.avg)})[0];
  var pvBestAvg=pvBest?parseFloat(pvBest.avg):0;
  var pvPos=readiness>=3&&regretVal==='yes'?'Based on your readiness score and regret test, the data says: make the move. Your highest-rated option is <strong>'+pvBest.label+'</strong> ('+pvBest.avg+'/5). Stop deliberating and start executing.'
    :readiness>=3?'You\u2019ve done the groundwork. Your readiness score says you\u2019re ready to decide. The question isn\u2019t whether to act \u2014 it\u2019s which path to commit to.'
    :readiness>=2?'You\u2019re almost ready, but you have gaps in your validation checklist. Close those gaps before making a final decision \u2014 one more month of due diligence beats a premature leap.'
    :'You need more groundwork before deciding. A career transition without proper validation is a coin flip. Complete the readiness checklist items you missed.';
  var pvActs=[];
  if(readiness<3){
    var unchecked=checks.filter(function(c){return !c.done});
    if(unchecked.length)pvActs.push({text:unchecked[0].label+' \u2014 this is your most critical gap right now.',when:'this week'});
    if(unchecked.length>1)pvActs.push({text:unchecked[1].label+' \u2014 don\u2019t skip this step.',when:'this month'});
  }else{
    pvActs.push({text:'Set a firm decision date within 30 days. Open-ended "maybe someday" never happens.',when:'this week'});
    pvActs.push({text:pvBestAvg>=4?'Start building your transition plan for '+pvBest.label+'.':'Compare your top 2 options with real conversations \u2014 talk to people who\u2019ve made the move.',when:'this month'});
  }
  pvActs.push({text:trainCost>0?'Run the financial reality through the projection tool \u2014 $'+trainCost.toLocaleString()+' transition cost needs a plan.':'Model the financial impact of each option over 30 years.',when:'this month'});
  var pvNxt=trainCost>50000?{id:'v11',icon:'\ud83d\udcc8',title:'Financial Planner',why:'A $'+Math.round(trainCost/1000)+'K transition cost needs 30-year modeling. Make sure the math works.'}
    :readiness>=3?{id:'v12',icon:'\ud83d\udcdd',title:'Contract Review Tool',why:'When you get an offer in the new direction, score every clause before signing.'}
    :{id:'v13',icon:'\ud83e\uddec',title:'Specialty Fit Assessment',why:'Before you pivot, validate that the new direction actually fits who you are now \u2014 not who you were.'};

  // Risk vs Upside breakdown for each option
  var riskUpside='<div style="margin-top:20px;margin-bottom:16px;padding:16px;background:var(--bg2);border:1px solid var(--border);border-radius:12px;text-align:left">';
  riskUpside+='<div style="font-size:11px;font-weight:600;color:var(--accent);text-transform:uppercase;letter-spacing:1px;margin-bottom:12px">Risk versus upside</div>';
  options.forEach(function(opt){
    var optAvg=parseFloat(opt.avg)||0;
    var risk='';var upside='';
    if(opt.label.toLowerCase().indexOf('stay')>=0||opt.label.toLowerCase().indexOf('current')>=0){
      risk='Burnout compounds. If you\u2019re dissatisfied now, it gets worse, not better. Cost of inaction: potentially years of lost fulfillment.';
      upside='No transition cost. No income disruption. Stable for family. Can still make smaller changes within the same path.';
    }else{
      risk='Transition costs ~$'+(trainCost>0?trainCost.toLocaleString():'unknown')+'. Income disruption for '+(trainCost>100000?'2-4':'1-2')+' years. Credentialing delays. New learning curve. Relationship reset with colleagues.';
      upside='Career satisfaction. New growth trajectory. Alignment with what you actually want. '+(optAvg>=4?'Your own ratings say this scores highest on feasibility, satisfaction, and financial viability.':'Potential improvement, but ratings suggest some uncertainty \u2014 validate before committing.');
    }
    riskUpside+='<div style="margin-bottom:12px;padding:10px;background:var(--bg3);border-radius:8px">';
    riskUpside+='<div style="font-size:12px;font-weight:600;color:var(--text);margin-bottom:8px">'+opt.label+' <span style="font-size:11px;color:var(--accent);font-weight:400">('+opt.avg+'/5)</span></div>';
    riskUpside+='<div style="display:grid;grid-template-columns:1fr 1fr;gap:8px">';
    riskUpside+='<div style="padding:8px;background:rgba(239,68,68,.04);border-radius:6px;border-left:3px solid var(--red)"><div style="font-size:10px;font-weight:600;color:var(--red);margin-bottom:4px">RISK</div><div style="font-size:11px;color:var(--text2);line-height:1.5">'+risk+'</div></div>';
    riskUpside+='<div style="padding:8px;background:rgba(106,191,75,.04);border-radius:6px;border-left:3px solid var(--green)"><div style="font-size:10px;font-weight:600;color:var(--green);margin-bottom:4px">UPSIDE</div><div style="font-size:11px;color:var(--text2);line-height:1.5">'+upside+'</div></div>';
    riskUpside+='</div></div>';
  });
  riskUpside+='</div>';

  document.getElementById('pivot-success').innerHTML='<div style="font-size:48px;margin-bottom:16px">\u2713</div><h3 class="serif" style="font-size:20px;margin-bottom:8px">Report Submitted</h3><p style="font-size:13px;color:var(--text2);line-height:1.6;margin-bottom:20px">Your Specialty & Career Fit report has been sent to Dr. Faroqui for review.</p>'+riskUpside+hwGatePathway(hwPathway(pvPos,pvActs,pvNxt));
  notify('Decision Engine report submitted!');
  var pivotInputs={'Cause':causeLabel+(causeOther?' — '+causeOther:''),'Burnout':burnout?burnout.value:'—','Training Years':yrs,'Training Cost':'$'+trainCost.toLocaleString()};
  var pivotHL=['Readiness: '+readyLabel+' ('+readiness+'/4)'];
  checks.forEach(function(c){pivotHL.push((c.done?'✅':'❌')+' '+c.label)});
  if(options.length){var best=options.slice().sort(function(a,b){return parseFloat(b.avg)-parseFloat(a.avg)})[0];pivotHL.push('Top option: '+best.label+' ('+best.avg+')')}
  recordToolUse('Specialty & Career Fit',readiness+'/4','Pivot readiness: '+readyLabel,{inputs:pivotInputs,highlights:pivotHL});
  notifyAdmin(payload);
}

// ===== MOCK INTERVIEW SIMULATOR (v16) =====
var MIS_QUESTIONS={
  medschool:{
    general:[
      {q:'Why do you want to be a doctor?',type:'career',what:'The most important question of your life right now — and the easiest to blow. They hear "I want to help people" 50 times a day. They need YOUR story.',ideal:'A specific personal experience that sparked medicine, genuine intellectual curiosity about the science, understanding of what a doctor\'s life actually looks like, not idealized.',red:['Generic "helping people" answer','Only mentioning prestige or money','A parent/family member being sick as the ONLY reason (needs more depth)','No evidence you\'ve explored what being a doctor actually means']},
      {q:'Tell me about yourself.',type:'behavioral',what:'They want the 60-second version of who you are beyond your application. Hobbies, values, what makes you interesting as a human — not a resume recitation.',ideal:'Personal, memorable, shows character beyond academics, connects who you are to why medicine makes sense for you.',red:['Reading back your activities list','Being boring and forgettable','Only talking about academics','Going over 90 seconds']},
      {q:'What will you do if you don\'t get into medical school?',type:'behavioral',what:'A test of resilience, self-awareness, and whether you have a backup plan. "I\'ll just keep applying" is honest but weak.',ideal:'Genuine backup plan that still connects to healthcare/science, shows you\'ve actually thought about it, demonstrates maturity and adaptability.',red:['Saying "that\'s not an option" — it\'s arrogant and unrealistic','Having zero backup plan','Becoming visibly distressed','A backup plan completely unrelated to science/healthcare']},
      {q:'Tell me about a challenge you\'ve overcome.',type:'behavioral',what:'They want resilience and self-awareness. Choose something real — not a humble brag about how hard you studied for the MCAT.',ideal:'Genuine hardship or failure, specific actions you took, what you learned, how it prepared you for the demands of medicine.',red:['Choosing something trivially easy','Making it a humble brag','Not showing vulnerability','No lesson learned — just "it was hard but I did it"']},
      {q:'What is the biggest issue facing healthcare today?',type:'career',what:'They want informed opinions, not a TED talk. Pick one issue, show you understand its complexity, and have a nuanced take.',ideal:'Specific issue (access, cost, burnout, health equity, AI), nuanced understanding of multiple perspectives, connection to your experience or interests.',red:['Having no opinion on healthcare','Giving a surface-level answer from a headline','Being preachy or political without substance','Not connecting it to why you want to practice medicine']},
      {q:'Describe an experience where you worked with someone very different from you.',type:'behavioral',what:'Diversity and cultural competence test. They want evidence you can connect with patients from all backgrounds.',ideal:'Specific situation, what made it challenging, what you learned about yourself, how it changed your perspective.',red:['Tokenizing the other person','Having no cross-cultural experience','Making yourself the hero who "saved" someone','Being patronizing']},
      {q:'What do you do outside of academics?',type:'fit',what:'They\'re checking if you\'re a real human. All-studying-no-living applicants burn out. They want someone with depth and sustainability.',ideal:'Genuine interests with passion and depth, shows you can balance life, bonus if activities reveal character (not just resume padding).',red:['Listing activities purely for the application','Having nothing outside school','Only mentioning things that are obviously resume-builders','Not being able to talk passionately about anything']}
    ],
    specialty:{other:[]}
  },
  residency:{
    general:[
      {q:'Tell me about yourself.',type:'behavioral',what:'They want your 60-second origin story — not your CV recited back to them. Who are you, what drives you, and why medicine? This is the most common opening question and most people blow it by being too long or too generic.',ideal:'Concise (60-90 sec), personal motivation, clear trajectory to this specialty, ends with forward-looking statement.',red:['Reciting your CV line by line','Going over 2 minutes','No personal motivation — sounds like everyone else','Starting with "Well, I was born in..."']},
      {q:'Why this specialty?',type:'career',what:'They want genuine intellectual curiosity and a specific moment or experience that made it click. Not "I like helping people" — every doctor likes helping people.',ideal:'Specific clinical moment or experience, intellectual excitement about the field, understanding of daily attending life, honest about challenges.',red:['Generic answers that could apply to any specialty','Only mentioning lifestyle or money','No specific patient story or clinical experience','Badmouthing other specialties']},
      {q:'Tell me about a time you made a mistake in patient care. What happened and what did you learn?',type:'behavioral',what:'This is a character test. They want honesty, accountability, and evidence that you grew from it. Everyone makes mistakes — the question is whether you own it or hide behind a team.',ideal:'Specific real example, personal accountability (not blaming the system), what you learned, how it changed your practice going forward.',red:['Saying "I\'ve never made a mistake"','Blaming the nurse, the attending, or the EMR','Choosing something trivially small to avoid vulnerability','Not explaining what changed afterward']},
      {q:'Where do you see yourself in 10 years?',type:'career',what:'They want to see ambition that aligns with reality. Academic programs want to hear about research and teaching. Community programs want clinical excellence and leadership.',ideal:'Realistic and specific, shows you\'ve thought about it, aligns with the program\'s mission, mentions both clinical and non-clinical goals.',red:['Being vague — "I\'ll be a great doctor"','Pure money motivation','Having zero idea what you want','Describing a plan that doesn\'t require this residency']},
      {q:'What is your biggest weakness?',type:'behavioral',what:'The oldest trick in the book. Don\'t give a fake weakness ("I work too hard"). Give a real one with a real plan to address it. Self-awareness is the point.',ideal:'Genuine weakness (not a disguised strength), specific steps you\'re taking to improve, evidence of growth.',red:['The classic "I\'m a perfectionist" non-answer','Revealing something genuinely disqualifying','Not having a plan to address it','Getting defensive or dismissive']},
      {q:'Tell me about a conflict you had with a colleague and how you resolved it.',type:'behavioral',what:'They\'re testing emotional intelligence. Medicine is teamwork. They want to know you can disagree without being disagreeable.',ideal:'Specific situation, your role in the conflict (not just the other person\'s fault), steps you took to resolve it, outcome and what you learned.',red:['Trashing the other person','Making yourself the hero who was always right','Avoiding the question with "I don\'t really have conflicts"','No resolution — just a vent session']},
      {q:'What questions do you have for us?',type:'fit',what:'This is not optional. Having no questions signals disinterest. Having great questions signals that you\'ve done your homework and you\'re evaluating them too.',ideal:'2-3 specific questions about the program that show research (not things on the website), questions about culture/mentorship/resident experience.',red:['No questions','Questions answered on the website or in the brochure','Only asking about schedule, vacation, or salary','Asking something that makes them uncomfortable']}
    ],
    specialty:{
      cards:[
        {q:'Walk me through how you would manage a patient presenting with acute chest pain.',type:'clinical',what:'They want systematic thinking under pressure. Not a perfect answer — a structured approach that shows you know the priorities.',ideal:'ABCs first, focused history, ECG within 10 minutes, troponin, risk stratification, clear decision tree for STEMI vs NSTEMI vs other.',red:['Jumping to cath lab without assessment','Forgetting to mention ECG timing','No mention of differential diagnosis','Panicking or freezing']},
        {q:'Why cardiology specifically, and not another IM subspecialty?',type:'career',what:'They want to hear genuine passion for the heart — not just that it\'s competitive or well-paying. What about cardiology specifically excites your brain?',ideal:'Specific clinical moment, what makes cardiology intellectually unique to you, understanding of the daily grind (not just the glamour cases).',red:['Mentioning salary or lifestyle first','Generic answers about "saving lives"','Not being able to name specific aspects of cardiology that excite you','Comparing it negatively to other specialties']}
      ],
      ic:[
        {q:'You\'re doing a PCI and encounter a complication — a perforation. Walk me through your next 60 seconds.',type:'clinical',what:'They want calm, systematic thinking in a crisis. This is life-or-death and they need to know you won\'t freeze.',ideal:'Immediate balloon inflation at site, call for echo, assess hemodynamics, prepare for pericardiocentesis, consider covered stent, notify attending/team.',red:['Freezing or not having a systematic approach','Not mentioning balloon tamponade first','Forgetting to check for tamponade with echo','Not calling for help']},
        {q:'What draws you to interventional cardiology over general cardiology or EP?',type:'career',what:'They want to know you\'ve thought deeply about this and aren\'t just chasing procedures. What about wires, stents, and hemodynamics lights your brain up?',ideal:'Specific procedural experience that clicked, intellectual challenge of complex anatomy, immediate impact on patients, realistic understanding of call/lifestyle.',red:['Only talking about money','Not mentioning any hands-on experience','Being unable to articulate what\'s different about interventional work','Showing no awareness of the call burden']}
      ],
      im:[
        {q:'What area of internal medicine are you most passionate about and why?',type:'career',what:'Even for IM residency, they want to see intellectual curiosity and some direction, while remaining open to the breadth of IM.',ideal:'Specific area with a patient story, genuine curiosity, openness to discovering other areas during residency.',red:['Being so narrowly focused that you seem like you only want fellowship','Having no interests at all — seems apathetic','Choosing something because it\'s "easy" or "good lifestyle"']},
        {q:'How would you approach a patient with multiple comorbidities who is non-adherent to medications?',type:'clinical',what:'This tests empathy, systems thinking, and realistic medicine. There\'s no magic answer — they want to see how you think about complex patients.',ideal:'Explore barriers (cost, health literacy, side effects, beliefs), motivational interviewing approach, simplify regimen, involve pharmacist/social work, follow-up plan.',red:['Blaming the patient','Having no strategy beyond "tell them to take their meds"','Not considering social determinants','Being paternalistic']}
      ],
      gensurg:[
        {q:'Tell me about the most technically challenging case you\'ve been involved in.',type:'clinical',what:'They want to see genuine surgical experience and the ability to reflect on complexity — not bragging.',ideal:'Specific case, your role, what made it challenging, what you learned, honest about what went well and what didn\'t.',red:['Exaggerating your role','Not being able to describe the actual technical challenge','Only mentioning cases you observed, not participated in']},
        {q:'How do you handle the long hours and physical demands of a surgical career?',type:'behavioral',what:'This is a trap question if you dismiss it. They want realistic self-awareness about sustainability.',ideal:'Specific strategies (exercise, relationships, boundaries), acknowledgment that it\'s hard, evidence you\'ve already managed demanding schedules.',red:['Bravado — "I never get tired"','Complaining about hours','Having no actual coping strategy','Seeming unaware of what surgical residency demands']}
      ],
      other:[
        {q:'What do you think is the biggest challenge facing your chosen specialty in the next decade?',type:'career',what:'This tests whether you\'ve thought beyond the training bubble. Do you understand the landscape you\'re entering?',ideal:'Specific, informed answer (AI impact, workforce shortages, burnout, reimbursement changes), your thoughts on solutions or adaptation.',red:['Having no answer','Something vague like "healthcare is changing"','Being overly negative or cynical','Not connecting it to your own career planning']},
        {q:'Describe a patient encounter that challenged your assumptions or changed how you practice.',type:'behavioral',what:'They want humility and growth. Medicine is supposed to change you. Have you let it?',ideal:'Specific patient, what you assumed going in, what actually happened, how it changed your approach permanently.',red:['Not having an example','Choosing something superficial','Making it about you instead of the patient','No evidence of actual change in practice']}
      ]
    }
  },
  fellowship:{
    general:[
      {q:'Tell me about yourself and your path to this fellowship.',type:'behavioral',what:'By fellowship, your story should be tight. They want a clear narrative arc: why medicine → why this specialty → why this subspecialty → why now. No rambling.',ideal:'Under 90 seconds, clear trajectory, specific inflection points that led to this fellowship, forward-looking.',red:['Starting from medical school day one','No clear narrative arc','Sounding rehearsed and robotic','Going over 2 minutes']},
      {q:'What is your research interest and how do you plan to develop it?',type:'research',what:'For academic fellowship programs, this is non-negotiable. Even clinical fellows need a scholarly plan. They want specifics, not "I\'m interested in research."',ideal:'Specific area, why it matters clinically, preliminary work you\'ve done, realistic plan for fellowship, potential mentors you\'ve identified.',red:['No specific research interest','Only wanting to do clinical work (for academic programs)','Naming a mentor at the program without having contacted them','Having unrealistic expectations about what you can accomplish']},
      {q:'Why our program specifically?',type:'fit',what:'This is where homework pays off. They can tell immediately if you\'ve researched them or if you\'re giving a generic answer you give every program.',ideal:'Specific faculty, unique program features, patient population, research strengths, culture fit — things you learned from visiting or talking to current fellows.',red:['Generic answer that applies to any program','Only mentioning ranking or reputation','Not knowing basic facts about the program','Having clearly not talked to any current fellows']},
      {q:'Describe a difficult clinical decision you made during residency.',type:'clinical',what:'They want clinical maturity. Can you handle ambiguity? Do you know when to ask for help? Did you think through the decision systematically?',ideal:'Specific case with genuine complexity, your thought process, who you consulted, outcome, what you learned.',red:['Choosing an easy case to avoid vulnerability','Not consulting anyone — cowboy medicine','Only describing a textbook decision','No reflection on what you\'d do differently']},
      {q:'What do you think you\'ll struggle with most during fellowship?',type:'behavioral',what:'Self-awareness test. They want to see you\'ve thought about the challenges honestly and have a plan.',ideal:'Genuine anticipated challenge (technical skills, research time management, work-life balance), specific plan to address it.',red:['"Nothing, I\'m ready" — overconfidence','Something that suggests you can\'t handle the fellowship','No plan for how you\'ll address it','Getting defensive about the question']}
    ],
    specialty:{
      cards:[
        {q:'A patient is referred to you for heart failure management. Their EF is 25% and they\'re on no guideline-directed therapy. Walk me through your approach.',type:'clinical',what:'This is bread-and-butter cardiology. They want systematic GDMT initiation, not just drug names.',ideal:'Assess volume status first, initiate the four pillars (ACEi/ARB/ARNI, beta-blocker, MRA, SGLT2i), monitoring plan, device evaluation, patient education.',red:['Missing any of the four pillars','Starting everything at once without monitoring','Not mentioning device therapy evaluation','Forgetting to address the patient\'s understanding']},
        {q:'How do you see the field of cardiology evolving in the next 10 years?',type:'career',what:'They want a thoughtful answer showing you\'re paying attention to the field — AI in imaging, structural heart growth, precision medicine, workforce issues.',ideal:'Specific trends with examples, how they affect your planned career, honest about uncertainties.',red:['Having no opinion','Being too focused on one niche','Ignoring technology/AI impact','Being cynically negative about the field']}
      ],
      ic:[
        {q:'You\'re offered two jobs: academic at $450K with research time, and private practice at $700K pure clinical. How do you think about this decision?',type:'career',what:'No right answer — they want your decision-making framework. How do you weigh money vs career development vs lifestyle?',ideal:'Structured comparison (compensation, PSLF implications, career trajectory, research goals, call burden), acknowledgment of tradeoffs, framework not just gut feeling.',red:['Immediately choosing money without analysis','Dismissing the financial difference as irrelevant','Not considering PSLF or long-term wealth','Having no framework — just vibes']},
        {q:'What is your CTO experience and how comfortable are you with complex PCI?',type:'clinical',what:'Be honest about your level. Overselling will get you caught on day one. They want someone who knows their limits and is hungry to learn.',ideal:'Honest case numbers, specific techniques you\'re comfortable with, areas you want to develop, enthusiasm for learning.',red:['Inflating your numbers','Claiming comfort with procedures you\'ve barely done','Not showing eagerness to learn','Being dismissive about the complexity']}
      ],
      other:[
        {q:'How will you balance clinical duties with research during fellowship?',type:'behavioral',what:'Fellowship is a juggling act. They want a realistic plan, not "I\'ll just work harder."',ideal:'Specific time management strategy, understanding of protected research time, willingness to set boundaries, realistic about tradeoffs.',red:['Saying you\'ll do it all perfectly','Not having a plan','Seeming unaware of how demanding fellowship is','Ignoring the clinical load']},
        {q:'Tell me about a patient you\'ll never forget.',type:'behavioral',what:'This reveals what moves you as a physician. Choose someone who changed how you think about medicine.',ideal:'Specific patient, emotional honesty, what you learned, how it shapes your practice today.',red:['Choosing a case purely for the diagnosis, not the human','Being emotionally disconnected','Making it about your cleverness rather than the patient','Not having one — suggests disengagement']}
      ]
    }
  },
  academic:{
    general:[
      {q:'Tell us about your clinical and academic background.',type:'career',what:'This is your executive summary. They want: training pedigree, clinical focus, research productivity, teaching experience, and where you\'re headed.',ideal:'Crisp 90-second summary, clinical expertise clearly defined, research trajectory with publications mentioned, teaching philosophy briefly noted.',red:['Rambling through your entire CV','No mention of teaching (it\'s academic, teaching matters)','No research direction','Being vague about clinical expertise']},
      {q:'What does your 5-year research plan look like? What grants will you pursue?',type:'research',what:'This separates serious candidates from people who just want to be called "professor." They want a funded research trajectory, not vague interest.',ideal:'Specific aims, target funding (K-award, R01 plan, foundation grants), preliminary data, timeline, collaboration strategy.',red:['No specific grant plan','Only planning chart reviews','Not understanding K vs R funding','Having aims too broad to ever get funded']},
      {q:'How do you approach teaching and mentorship?',type:'behavioral',what:'Academic jobs require teaching. They want to know you\'re not just tolerating it — you should genuinely care about developing the next generation.',ideal:'Specific teaching philosophy, examples of past teaching, how you give feedback, how you mentor diverse learners.',red:['Treating teaching as an afterthought','No specific examples','Only lecturing — no mention of bedside teaching or mentorship','Seeming annoyed by trainees']},
      {q:'What would you need from this department to be successful?',type:'fit',what:'Smart question. They\'re testing whether your needs align with what they can offer. It also shows you know what you need.',ideal:'Specific needs (protected research time, mentorship, lab space, startup funding, administrative support), showing you\'ve thought about infrastructure.',red:['Saying "nothing, I\'m self-sufficient" — unrealistic','Only asking about salary','Having needs they clearly can\'t meet','Not having thought about this']},
      {q:'If you get this position, what will you be known for in 10 years?',type:'career',what:'Vision test. They want someone who will put their department on the map, not just occupy a slot.',ideal:'Specific clinical or research niche, realistic but ambitious, explains how it benefits the department and patients.',red:['Being vague — "I\'ll be a good faculty member"','Goals that don\'t need this department','No connection between your goals and their mission','Sounding like you\'re just passing through']}
    ],
    specialty:{other:[]}
  },
  private:{
    general:[
      {q:'Why are you interested in joining our practice?',type:'fit',what:'They want to know you\'ve researched their group and that you\'re not just applying everywhere. Practice culture matters enormously.',ideal:'Specific reasons (reputation, colleagues, patient population, practice model, call structure), evidence you\'ve talked to current physicians.',red:['Generic answer — "it seems like a great group"','Only mentioning compensation','Not knowing basic facts about the practice','Seeming like you\'re just comparison-shopping']},
      {q:'What kind of patient volume do you expect to handle and how do you plan to build your practice?',type:'career',what:'In private practice, you eat what you kill (at least eventually). They want to know you understand the business side.',ideal:'Realistic ramp-up expectations (12-18 months), networking plan, referral development strategy, community engagement.',red:['Expecting full volume from day one','Having no plan to build referrals','Being dismissive of the business side','Not understanding the ramp-up period']},
      {q:'How do you handle difficult patients or patient complaints?',type:'behavioral',what:'In private practice, patient satisfaction directly affects the business. They want emotional intelligence and de-escalation skills.',ideal:'Specific example, empathetic approach, de-escalation technique, follow-up, systemic changes to prevent recurrence.',red:['Getting defensive about complaints','Having no strategy','Dismissing patient concerns','Not taking satisfaction seriously in a private setting']},
      {q:'What are your long-term career goals? Do you see yourself eventually wanting to be a partner?',type:'career',what:'They\'re evaluating retention risk. Training someone who leaves in 2 years is expensive. They want commitment signals.',ideal:'Honest about timeline, interest in partnership/leadership, understanding of partnership track, long-term community commitment.',red:['Being noncommittal about staying','Only focusing on short-term','Not understanding the partnership model','Seeming like you\'re using this as a stepping stone']},
      {q:'Tell me about a time you had to adapt quickly to an unexpected clinical situation.',type:'clinical',what:'Private practice means less backup. They want to know you can handle things when the specialist is 45 minutes away.',ideal:'Specific case, rapid assessment, resourceful problem-solving, good outcome (or honest about a tough one), lessons learned.',red:['Never having faced real clinical pressure','Only describing cases with attending backup','Not showing independent clinical judgment','Freezing or panicking in the story']}
    ],
    specialty:{other:[]}
  },
  employed:{
    general:[
      {q:'What attracted you to hospital-employed practice versus private practice?',type:'career',what:'They want to know you understand the model and that you chose it for real reasons, not just because it was available.',ideal:'Specific reasons (guaranteed salary, benefits, less business management, institutional resources, team), realistic about tradeoffs.',red:['Badmouthing private practice','Only mentioning salary guarantee','Not understanding the employed model\'s limitations','Seeming like you couldn\'t get a private practice job']},
      {q:'How do you approach working within a large healthcare system with administrative requirements?',type:'behavioral',what:'Hospital systems have bureaucracy. They need to know you won\'t fight every policy and can work within the structure.',ideal:'Balanced approach — advocate for patients within the system, examples of navigating bureaucracy effectively, willingness to participate in committees.',red:['Ranting about administrators','Being a pushover with no advocacy','Not understanding that metrics and documentation matter','Seeming like you\'ll be a constant problem']},
      {q:'What is your approach to RVU-based productivity and meeting targets?',type:'career',what:'Employed positions increasingly tie compensation to productivity. They want to know you understand this and can perform.',ideal:'Understanding of RVU model, realistic expectations, strategies for efficiency without cutting corners, willingness to ramp up.',red:['Not knowing what an RVU is','Being hostile to productivity metrics','Having unrealistic volume expectations','Seeming like you\'ll coast on a guaranteed salary']},
      {q:'Describe your ideal work-life balance and how you manage call responsibilities.',type:'behavioral',what:'They need to know your expectations align with reality. Being honest about boundaries while showing flexibility is key.',ideal:'Realistic expectations, specific strategies for call recovery, acknowledgment that call is part of the job, clear boundaries without rigidity.',red:['Demanding no call','Saying you have no limits — unsustainable','Not asking about the actual call schedule','Having expectations that don\'t match the position']},
      {q:'How do you see yourself contributing to the department beyond clinical care?',type:'fit',what:'Employed positions want team players who improve the department — quality committees, teaching, mentoring, community outreach.',ideal:'Specific interests (QI, teaching, program building, community health), examples of past contributions beyond clinical work.',red:['Only wanting to see patients and go home','Having no interest in department life','Overcommitting to everything','Not understanding what the department needs']}
    ],
    specialty:{other:[]}
  },
  salary:{
    general:[
      {q:'Why do you believe a compensation adjustment is appropriate at this time?',type:'career',what:'This is the moment. You need data, not feelings. They want to see you\'ve done the homework with MGMA, wRVU reports, and market data.',ideal:'Specific data points (MGMA percentile, your wRVU production, market comparisons, recent offers), concrete number or range, professional tone.',red:['No data — just "I deserve more"','Being emotional or threatening','Not knowing your MGMA percentile','Comparing yourself to colleagues by name']},
      {q:'What specific contributions have you made that justify this increase?',type:'behavioral',what:'Document your value. Patient satisfaction scores, RVUs above target, program building, revenue generation, quality metrics.',ideal:'Specific metrics and accomplishments, revenue you\'ve generated, programs you\'ve built, patient outcomes, quantifiable impact.',red:['Vague contributions — "I work hard"','Not tracking your metrics','Only listing clinical volume without broader impact','Being unable to quantify your value']},
      {q:'If we can\'t meet your salary expectations, what other forms of compensation would you consider?',type:'career',what:'Smart negotiators have a full picture. Salary is one lever — there\'s also signing bonus, CME, research time, schedule flexibility, partnership acceleration.',ideal:'Prepared list of alternatives (CME budget, research time, schedule modification, bonus structure, title, partnership timeline), prioritized by what matters to you.',red:['Only caring about base salary','Having no alternatives prepared','Not understanding total compensation','Being inflexible']},
      {q:'Where do you see your career here in the next 3-5 years?',type:'fit',what:'They want to know you\'re invested. A raise is an investment in keeping you — they need to believe you\'re staying.',ideal:'Specific growth plans within the organization, leadership interests, program development, commitment signals.',red:['Hinting you might leave','Having no vision for growth','Seeming like the raise is just to stay afloat','Not connecting your future to their organization']},
      {q:'How do you handle the business and administrative side of your practice?',type:'behavioral',what:'Physicians who understand the business side get paid more because they\'re more valuable. Show you understand revenue, efficiency, and operations.',ideal:'Understanding of practice economics, specific examples of improving efficiency or revenue, willingness to take on leadership, data-driven approach.',red:['Being dismissive of business — "I\'m a doctor, not a businessman"','Not understanding how your practice generates revenue','Having no interest in operational improvement','Only seeing medicine through a clinical lens']}
    ],
    specialty:{other:[]}
  }
};

function misInit(){
  // Reset state on open
  document.getElementById('mis-interview').style.display='none';
  document.getElementById('mis-feedback').innerHTML='';
}

function misUpdateSpec(){
  // Optional — show/hide specialty-specific note
}

function misStart(){
  var type=document.getElementById('mis-type').value;
  var spec=document.getElementById('mis-spec').value;
  var setting=document.getElementById('mis-setting').value;
  var years=document.getElementById('mis-years').value;

  if(!type){notify('Select what you\'re interviewing for.',1);return}

  var bank=MIS_QUESTIONS[type];
  if(!bank){notify('Interview type not found.',1);return}

  // Build question pool: 3 general + 2 specialty (or all general if no specialty match)
  var generalPool=bank.general.slice();
  var specPool=[];

  // Map mis-spec values to specialty keys
  var specMap={
    cards:'cards',ic:'ic',ep:'cards',im:'im',im_outpatient:'im',im_hospitalist:'im',fm:'im',
    gi:'other',pulm:'other',hemonc:'other',neph:'other',endo:'other',
    rheum:'other',id:'other',em:'other',anes:'other',obesity:'other',
    ortho:'gensurg',gensurg:'gensurg',uro:'gensurg',
    psych:'other',derm:'other',rads:'other',path:'other',
    peds:'other',obgyn:'other',neuro:'other',other:'other'
  };
  var specKey=specMap[spec]||'other';

  if(bank.specialty){
    if(bank.specialty[specKey]&&bank.specialty[specKey].length>0){
      specPool=bank.specialty[specKey].slice();
    }else if(bank.specialty.other&&bank.specialty.other.length>0){
      specPool=bank.specialty.other.slice();
    }
  }

  // Shuffle
  function shuffle(arr){for(var i=arr.length-1;i>0;i--){var j=Math.floor(Math.random()*(i+1));var t=arr[i];arr[i]=arr[j];arr[j]=t;}return arr;}

  shuffle(generalPool);
  shuffle(specPool);

  var questions=[];

  // Pick specialty questions first (up to 2)
  var specCount=Math.min(specPool.length,2);
  for(var i=0;i<specCount;i++) questions.push(specPool[i]);

  // Fill remainder from general (total 5)
  var genNeeded=5-questions.length;
  for(var i=0;i<genNeeded&&i<generalPool.length;i++) questions.push(generalPool[i]);

  // Shuffle final order
  shuffle(questions);

  window._misQuestions=questions;
  window._misType=type;
  window._misSetting=setting;

  // Render interview header
  var typeNames={residency:'Residency Interview',fellowship:'Fellowship Interview',academic:'Academic Faculty Interview',private:'Private Practice Interview',employed:'Hospital-Employed Position Interview',salary:'Salary Renegotiation Meeting'};
  var settingNames={academic:'Academic Medical Center',community:'Community Hospital',private:'Private Group Practice',va:'VA / Government'};

  var hdr='<div style="display:flex;align-items:center;gap:12px">';
  hdr+='<div style="font-size:32px"></div>';
  hdr+='<div>';
  hdr+='<div style="font-size:15px;font-weight:600;color:var(--accent);font-family:var(--font-serif)">'+(typeNames[type]||'Interview Simulation')+'</div>';
  hdr+='<div style="font-size:11px;color:var(--text3)">'+(settingNames[setting]||setting)+' • 5 Questions • Answer as if you\'re in the room</div>';
  hdr+='</div></div>';
  hdr+='<div style="margin-top:12px;padding:10px;background:rgba(198,168,94,.06);border-radius:8px;border:1px solid rgba(200,168,124,.1)">';
  hdr+='<div style="font-size:11px;color:var(--text2);line-height:1.6">💡 <strong>Treat this like a real interview.</strong> Type your actual answer — the way you\'d say it out loud. Don\'t look anything up. Your natural response is what we need to evaluate.</div>';
  hdr+='</div>';
  document.getElementById('mis-header').innerHTML=hdr;

  // Render questions
  var typeBadge={clinical:'🩺 Clinical',research:'🔬 Research',behavioral:'🧠 Behavioral',career:'🎯 Career',fit:'🏥 Program Fit'};
  var typeColor={clinical:'#3B82F6',research:'var(--green)',behavioral:'var(--accent)',career:'#8B5CF6',fit:'#E67E22'};

  var qh='';
  questions.forEach(function(q,i){
    qh+='<div style="margin-bottom:16px;padding:16px;background:var(--bg2);border:1px solid var(--border);border-radius:12px">';
    qh+='<div style="display:flex;align-items:center;gap:8px;margin-bottom:10px">';
    qh+='<span style="font-size:16px;font-weight:700;color:var(--accent)">Q'+(i+1)+'</span>';
    qh+='<span style="font-size:9px;padding:2px 8px;border-radius:100px;background:rgba(198,168,94,.06);color:'+(typeColor[q.type]||'var(--text3)')+';font-weight:600;letter-spacing:.5px">'+(typeBadge[q.type]||q.type)+'</span>';
    qh+='</div>';
    qh+='<div style="font-size:14px;font-weight:500;color:var(--text);line-height:1.6;margin-bottom:4px">"'+q.q+'"</div>';
    qh+='<div style="font-size:11px;color:var(--text3);margin-bottom:12px;line-height:1.5;font-style:italic">'+q.what+'</div>';
    qh+='<textarea id="mis-a'+i+'" rows="4" placeholder="Type your answer here... be honest, this is practice." style="width:100%;font-family:inherit;font-size:13px;padding:12px;border:1px solid var(--border);border-radius:8px;background:var(--bg);color:var(--text);resize:vertical;box-sizing:border-box;line-height:1.6"></textarea>';
    qh+='</div>';
  });

  document.getElementById('mis-questions').innerHTML=qh;
  document.getElementById('mis-interview').style.display='block';
  document.getElementById('mis-feedback').innerHTML='';

  // Scroll to interview
  document.getElementById('mis-interview').scrollIntoView({behavior:'smooth',block:'start'});
}

function misGrade(){
  var questions=window._misQuestions;
  if(!questions||!questions.length){notify('Start the interview first.',1);return}

  var answers=[];
  var emptyCount=0;
  for(var i=0;i<questions.length;i++){
    var el=document.getElementById('mis-a'+i);
    var val=el?el.value.trim():'';
    answers.push(val);
    if(!val)emptyCount++;
  }

  if(emptyCount===questions.length){
    notify('Answer at least a few questions before getting feedback.',1);
    return;
  }

  // Grade each answer
  var results=[];
  var overallScore=0;

  questions.forEach(function(q,i){
    var ans=answers[i];
    var grade={score:0,label:'',color:'',strengths:[],concerns:[],advice:'',redFlags:[]};

    if(!ans){
      grade.score=0;
      grade.label='Not Answered';
      grade.color='var(--text3)';
      grade.concerns=['You skipped this question. In a real interview, silence is a red flag.'];
      grade.advice='Even a mediocre answer beats no answer. If you freeze, buy time: "That\'s a great question — let me think about that for a moment." Then give an honest attempt.';
      results.push(grade);
      return;
    }

    var words=ans.split(/\s+/).length;
    var sentences=ans.split(/[.!?]+/).filter(function(s){return s.trim().length>0}).length;
    var lower=ans.toLowerCase();

    // ===== DETECTION FLAGS =====
    // Specificity: real stories, names, cases, concrete details
    var hasSpecific=(/\b(patient|case|example|experience|specifically|instance|time when|I remember|one time|during my|rotation at|while I was|in my (PGY|third|second|first|intern))\b/i).test(ans);
    var hasConcreteDetail=(/\b(Dr\.|hospital|clinic|ICU|ED|floor|cath lab|OR|[A-Z][a-z]+ (Hospital|Medical|University|Center))\b/).test(ans);
    var hasData=(/\b(\d+%|\$[\d,]+|\d+ (year|month|patient|case|publication|hour|week)|MGMA|RVU|wRVU|percentile|score|Step [12]|USMLE)\b/i).test(ans);
    var hasOutcome=(/\b(result|outcome|improved|resolved|discharged|survived|recovered|successful|failed|complication)\b/i).test(ans);

    // Reflection & self-awareness
    var hasReflection=(/\b(learned|realized|changed|grew|taught me|made me|shaped|influenced|understand now|looking back|in hindsight|if I could do it again|what I took away)\b/i).test(ans);
    var hasAccountability=(/\b(my (fault|mistake|responsibility|weakness|limitation)|I should have|I could have done better|I own|I dropped|I missed|I failed|I struggled)\b/i).test(ans);

    // Structure
    var hasStructure=(/\b(first|second|third|additionally|furthermore|finally|in summary|to start|my approach|there are (two|three|four)|the (first|main|key) (thing|reason|point))\b/i).test(ans);
    var hasTransitions=sentences>=3&&(/\b(then|after that|from there|next|subsequently|this led|because of this|as a result)\b/i).test(ans);

    // Red flag patterns — much broader detection
    var hasFiller=(/\b(I think maybe|I guess|sort of|kind of|you know|um+|uh+|like,|basically|honestly I'm not sure|I don't really know|I suppose|whatever|stuff like that|things like that|and stuff|or something)\b/i).test(ans);
    var isGeneric=(/\b(I love helping people|make a difference|passion for medicine|always wanted to be a doctor|great opportunity|I've always been passionate|I really enjoy|I find it rewarding|it's very fulfilling|I like the idea of)\b/i).test(ans);
    var isNegative=(/\b(hate|terrible|worst|stupid|awful|can't stand|never liked|garbage|sucks|ridiculous|waste of time|pointless|boring)\b/i).test(ans);
    var isVague=!hasSpecific&&!hasData&&!hasConcreteDetail&&words>=10; // has words but says nothing concrete
    var isLazy=words<15&&sentences<=2; // barely tried
    var isRambling=words>300&&sentences>8&&!hasStructure;
    var isRepetitive=(function(){var w=lower.split(/\s+/);var seen={};var repeats=0;for(var k=0;k<w.length;k++){var ww=w[k].replace(/[^a-z]/g,'');if(ww.length>4){if(seen[ww])repeats++;seen[ww]=true}}return repeats>words*0.15})();
    var hasNoSubstance=words>=15&&!hasSpecific&&!hasData&&!hasReflection&&!hasStructure&&!hasConcreteDetail;
    var isDismissive=(/\b(I don't know|not sure|no idea|haven't thought about|good question|that's hard|I'll figure it out|we'll see|idk|idc|whatever)\b/i).test(ans);
    var isOverconfident=(/\b(I'm the best|no one else|I never fail|I always succeed|I'm perfect|nothing scares me|I have no weaknesses|I don't make mistakes|everyone says I'm)\b/i).test(ans);
    var mentionsMoney=(/\b(salary|money|pay|compensation|income|rich|wealthy|lucrative|six figures|seven figures)\b/i).test(ans);
    var badmouths=(/\b(my (program|school|hospital|residency|boss|attending|co-resident) (is|was|are|were) (bad|terrible|awful|toxic|incompetent|useless|worst)|I (hate|hated) my|the problem with my)\b/i).test(ans);

    var pts=0;
    var maxPts=100;

    // ===== LENGTH SCORING (15 pts) =====
    if(words>=60&&words<=200){pts+=15;grade.strengths.push('Good length — concise but substantial.')}
    else if(words>=40&&words<60){pts+=10;grade.concerns.push('Slightly short. A strong interview answer runs 60-90 seconds (roughly 100-180 words). Expand with a specific example.')}
    else if(words>=25&&words<40){pts+=6;grade.concerns.push('Too short. This sounds like you\'re dodging the question or haven\'t thought about it. In a real interview, this silence after 15 seconds would be awkward.')}
    else if(words>200&&words<=300){pts+=12;grade.concerns.push('Getting long. Interviewers tune out after 90 seconds. Tighten this up — what\'s the core message?')}
    else if(words>300){pts+=5;grade.concerns.push('Way too long. You\'d lose the interviewer halfway through. Cut this in half. The best answers are tight and memorable.')}
    else if(words<25){pts+=2;grade.concerns.push('Barely an answer. In a real interview, this would signal disinterest or total unpreparedness. You need at least 3-4 solid sentences.')}

    // ===== SPECIFICITY (25 pts) =====
    if(hasSpecific&&hasData&&hasConcreteDetail){pts+=25;grade.strengths.push('Great — specific examples with concrete details and data. This is the kind of answer that sticks with an interviewer.')}
    else if(hasSpecific&&(hasData||hasConcreteDetail)){pts+=20;grade.strengths.push('Good specificity with real examples. Adding one more concrete detail or number would make this even sharper.')}
    else if(hasSpecific){pts+=14;grade.strengths.push('You referenced a specific experience — good. Now anchor it with concrete details: where, when, what exactly happened, what was the outcome.')}
    else if(hasData){pts+=10;grade.concerns.push('You have data but no story. Numbers without context don\'t land. Wrap the data in a specific experience.')}
    else{pts+=2;grade.concerns.push('Too vague and generic. This answer could come from literally any applicant. An interviewer hears this and immediately forgets you. Give a specific patient, case, or situation that only YOU experienced.')}

    // ===== REFLECTION / SELF-AWARENESS (20 pts) =====
    if(hasReflection&&hasAccountability){pts+=20;grade.strengths.push('Excellent self-awareness. Showing growth and accountability is exactly what makes an interviewer lean forward.')}
    else if(hasReflection&&hasOutcome){pts+=16;grade.strengths.push('Good reflection with outcomes mentioned. You show capacity for growth.')}
    else if(hasReflection){pts+=12;grade.strengths.push('Some reflection present. Strengthen it by being more specific about exactly what changed in your thinking or practice.')}
    else if(hasAccountability){pts+=12;grade.strengths.push('Points for owning it. That takes guts and interviewers respect it.')}
    else{pts+=1;grade.concerns.push('No reflection or self-awareness comes through. Every strong interview answer ends with what you learned, how it changed you, or what you\'d do differently. Without this, you\'re just telling a story with no point.')}

    // ===== STRUCTURE & COHERENCE (15 pts) =====
    if(hasStructure&&hasTransitions&&sentences>=3){pts+=15;grade.strengths.push('Well-organized answer with clear structure and flow.')}
    else if(hasStructure&&sentences>=3){pts+=12;grade.strengths.push('Decent structure. Your points are organized.')}
    else if(sentences>=3&&!isRambling){pts+=8}
    else if(sentences>=2){pts+=4;grade.concerns.push('Needs more structure. Try: situation → what you did → result → what you learned. That framework works for 80% of interview questions.')}
    else{pts+=1;grade.concerns.push('This reads like one thought fragment, not a structured answer. Interviewers want to see organized thinking — it signals how you\'ll present at conferences, explain plans to patients, and communicate with teams.')}

    // ===== RED FLAG DETECTION (25 pts — this is where bad answers get punished) =====
    var flagsHit=0;

    // Content quality red flags
    if(isLazy){flagsHit++;grade.redFlags.push('🚩 This barely qualifies as an answer. One or two sentences tells the interviewer you either don\'t care or you\'re completely unprepared. Neither is a good look.')}
    if(isVague&&!isLazy){flagsHit++;grade.redFlags.push('🚩 Vague and unsubstantiated. You made claims without backing them up with anything concrete. Interviewers notice this immediately — it sounds like you\'re making it up on the spot.')}
    if(hasNoSubstance){flagsHit++;grade.redFlags.push('🚩 No substance. You used a lot of words but didn\'t actually say anything specific, reflective, or structured. This is the interview equivalent of writing a paragraph that says nothing.')}
    if(isDismissive){flagsHit++;grade.redFlags.push('🚩 Dismissive language detected. Saying "I don\'t know" or "I haven\'t thought about it" in an interview is a dealbreaker. If you don\'t know, pivot: "I\'m still developing my thinking on this, but here\'s where I am..."')}
    if(isOverconfident){flagsHit++;grade.redFlags.push('🚩 Overconfidence. Claiming you never fail, have no weaknesses, or are the best reads as either delusional or dishonest. Interviewers want self-awareness, not bravado.')}
    if(isRambling){flagsHit++;grade.redFlags.push('🚩 Rambling without direction. This goes on too long without clear structure. An interviewer would be checking their phone by the second paragraph.')}
    if(isRepetitive){flagsHit++;grade.redFlags.push('🚩 Repetitive — you\'re saying the same thing multiple ways. This happens when you don\'t have enough substance, so you fill space by rephrasing. Cut the repetition and add new content.')}

    // Language red flags
    if(hasFiller){flagsHit++;grade.redFlags.push('🚩 Filler language detected ("kind of," "I guess," "sort of," "basically"). This signals uncertainty. In an interview, uncertainty reads as incompetence. Cut every qualifier.')}
    if(isGeneric){flagsHit++;grade.redFlags.push('🚩 Cliché phrasing. "I love helping people" / "I\'ve always been passionate" — every single applicant says this. It\'s meaningless. Replace with the specific moment, case, or experience that actually made this real for you.')}
    if(isNegative){flagsHit++;grade.redFlags.push('🚩 Negative language about people, institutions, or experiences. Even if justified, negativity in an interview makes YOU look bad, not the thing you\'re criticizing. Reframe: what did you learn from a difficult situation?')}
    if(badmouths){flagsHit++;grade.redFlags.push('🚩 Badmouthing your program, school, or colleagues. This is an instant disqualifier at most programs. No matter how bad the situation was, the interviewer wonders: "Will they talk about us like this someday?"')}

    // Context-specific red flags
    if(mentionsMoney&&q.type!=='career'&&window._misType!=='salary'){flagsHit++;grade.redFlags.push('🚩 Mentioning money/salary unprompted. Unless you\'re in a salary negotiation, bringing up compensation signals that money is your primary motivator. Save it for the appropriate conversation.')}

    // Quality-based scoring (not just flag counting)
    if(flagsHit===0&&!isVague&&!isLazy&&!hasNoSubstance){
      pts+=25;
      // Only say "clean answer" if the answer actually has substance
      if(pts>=50){grade.strengths.push('No red flags. Clean, professional answer.')}
    }else if(flagsHit===1){pts+=12}
    else if(flagsHit===2){pts+=4}
    else{pts+=0} // 3+ flags = zero credit

    // ===== CALCULATE FINAL SCORE =====
    grade.score=Math.max(0,Math.min(Math.round(pts),100));

    // Adjust labels to be more honest at the low end
    if(grade.score>=80){grade.label='Strong';grade.color='var(--green)'}
    else if(grade.score>=60){grade.label='Decent';grade.color='var(--accent)'}
    else if(grade.score>=40){grade.label='Needs Work';grade.color='#E67E22'}
    else if(grade.score>=20){grade.label='Weak';grade.color='var(--red)'}
    else{grade.label='Not Ready';grade.color='var(--red)'}

    // ===== GENERATE TARGETED ADVICE =====
    var adviceParts=[];
    if(isLazy) adviceParts.push('You need to actually answer the question. Block 5 minutes, think about what you\'d really say, and write a real response. This isn\'t something you can wing.');
    else if(hasNoSubstance) adviceParts.push('You wrote words but said nothing memorable. Rewrite this starting with: "During my [specific rotation/year/experience] at [specific place], I [specific thing that happened]..."');
    if(!hasSpecific&&!isLazy) adviceParts.push('Start with "Let me tell you about a specific time when..." — stories beat abstractions every time. Name the place, the patient (anonymized), the situation.');
    if(words>=25&&words<60&&!isLazy) adviceParts.push('Flesh this out. Practice saying it out loud for 60-90 seconds. You need at least 4-5 sentences of real content.');
    if(words>250) adviceParts.push('Cut 30-40%. Read it out loud — if you\'re going past 90 seconds, you\'re losing them. What\'s the ONE thing you want them to remember?');
    if(!hasReflection&&!isLazy) adviceParts.push('End with what you learned or how it changed you. That\'s the line they actually remember 10 interviews later.');
    if(hasFiller) adviceParts.push('Remove every filler word. Replace "I think" with a statement. "I believe" or "In my experience" are stronger. "I guess" should never leave your mouth in an interview.');
    if(isGeneric) adviceParts.push('Kill every cliché. Replace "I\'m passionate about helping people" with the exact moment you knew this was your path. What patient? What happened? What did you feel?');
    if(isDismissive) adviceParts.push('Never say "I don\'t know" in an interview. Instead: "That\'s something I\'m actively thinking about. Here\'s where my thinking is so far..." Then give your best honest attempt.');
    if(isRepetitive) adviceParts.push('You\'re circling the same point. State it once, clearly, then move to the next idea. If you don\'t have a next idea, your answer needs more preparation.');
    if(badmouths) adviceParts.push('Rewrite without mentioning anyone negatively. Frame challenges as "I navigated a difficult environment and learned to..." Not "my program was terrible because..."');
    if(adviceParts.length===0){
      if(grade.score>=80) adviceParts.push('This is a strong answer. To go from good to great: practice it out loud 5 times, then record yourself. Watch the recording once. You\'ll immediately see what to tighten.');
      else adviceParts.push('Rewrite this answer from scratch using the STAR method: Situation, Task, Action, Result. Be specific in every section. Then read it out loud — does it sound like something a real person would say?');
    }
    grade.advice=adviceParts.join(' ');

    overallScore+=grade.score;
    results.push(grade);
  });

  var answered=questions.length-emptyCount;
  var avgScore=answered>0?Math.round(overallScore/answered):0;

  // Build feedback HTML
  var h='<div style="margin-top:24px">';

  // Overall score header
  h+='<div style="text-align:center;padding:28px;background:linear-gradient(160deg,rgba(200,168,124,.1),rgba(200,168,124,.03));border:1px solid rgba(198,168,94,.15);border-radius:14px;margin-bottom:20px">';
  h+='<div style="font-size:11px;font-weight:600;color:var(--text3);text-transform:uppercase;letter-spacing:1.5px;margin-bottom:8px">Interview Performance</div>';

  var overallColor=avgScore>=80?'var(--green)':avgScore>=60?'var(--accent)':avgScore>=40?'#E67E22':'var(--red)';
  var overallLabel=avgScore>=80?'Interview Ready':avgScore>=60?'Getting There':avgScore>=40?'Needs Practice':'Significant Work Needed';
  var overallMsg=avgScore>=80?'You\'d hold your own in most interviews. Keep practicing the specifics and you\'ll be sharp on game day.'
    :avgScore>=60?'Decent foundation, but you\'re leaving points on the table. The feedback below shows exactly where.'
    :avgScore>=40?'You\'re not ready yet — and that\'s why you\'re practicing here instead of bombing it live. Read every piece of feedback below.'
    :'Real talk: if you interviewed like this today, you\'d be forgotten by lunch. But that\'s fixable. Every strong interviewer was bad at first. Work through the feedback below methodically.';

  h+='<div style="width:80px;height:80px;border-radius:50%;border:4px solid '+overallColor+';display:flex;align-items:center;justify-content:center;margin:0 auto 12px">';
  h+='<span style="font-size:28px;font-weight:700;color:'+overallColor+'">'+avgScore+'</span>';
  h+='</div>';
  h+='<div style="font-size:16px;font-weight:600;color:'+overallColor+';margin-bottom:4px">'+overallLabel+'</div>';
  h+='<div style="font-size:12px;color:var(--text2);line-height:1.6;max-width:400px;margin:0 auto">'+overallMsg+'</div>';
  if(emptyCount>0) h+='<div style="margin-top:10px;font-size:11px;color:var(--red)">'+emptyCount+' question'+(emptyCount>1?'s':'')+' left blank. Skipping questions in a real interview is never a good look.</div>';
  h+='</div>';

  // Per-question feedback
  questions.forEach(function(q,i){
    var g=results[i];
    var typeBadge={clinical:'🩺 Clinical',research:'🔬 Research',behavioral:'🧠 Behavioral',career:'🎯 Career',fit:'🏥 Program Fit'};
    var typeColor={clinical:'#3B82F6',research:'var(--green)',behavioral:'var(--accent)',career:'#8B5CF6',fit:'#E67E22'};

    h+='<div style="margin-bottom:16px;padding:16px;background:var(--bg2);border:1px solid var(--border);border-radius:12px;border-left:4px solid '+g.color+'">';

    // Question header
    h+='<div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:10px;flex-wrap:wrap;gap:6px">';
    h+='<div style="display:flex;align-items:center;gap:8px">';
    h+='<span style="font-size:14px;font-weight:700;color:var(--accent)">Q'+(i+1)+'</span>';
    h+='<span style="font-size:9px;padding:2px 8px;border-radius:100px;background:rgba(198,168,94,.06);color:'+(typeColor[q.type]||'var(--text3)')+';font-weight:600;letter-spacing:.5px">'+(typeBadge[q.type]||q.type)+'</span>';
    h+='</div>';
    h+='<div style="display:flex;align-items:center;gap:6px"><span style="font-size:12px;font-weight:700;color:'+g.color+'">'+g.score+'/100</span><span style="font-size:10px;color:'+g.color+';font-weight:600">'+g.label+'</span></div>';
    h+='</div>';

    h+='<div style="font-size:12px;color:var(--text3);margin-bottom:12px;font-style:italic">"'+q.q+'"</div>';

    // Your answer (collapsed)
    if(answers[i]){
      h+='<details style="margin-bottom:12px"><summary style="font-size:11px;color:var(--text3);cursor:pointer;font-weight:600">📝 Your Answer</summary>';
      h+='<div style="font-size:12px;color:var(--text2);line-height:1.6;margin-top:8px;padding:10px;background:var(--bg);border-radius:6px;border:1px solid var(--border)">'+answers[i].replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/\n/g,'<br>')+'</div>';
      h+='</details>';
    }

    // Strengths
    if(g.strengths.length>0){
      h+='<div style="margin-bottom:10px">';
      g.strengths.forEach(function(s){
        h+='<div style="font-size:11px;color:var(--green);line-height:1.6;padding:4px 0">✅ '+s+'</div>';
      });
      h+='</div>';
    }

    // Concerns
    if(g.concerns.length>0){
      h+='<div style="margin-bottom:10px">';
      g.concerns.forEach(function(c){
        h+='<div style="font-size:11px;color:#E67E22;line-height:1.6;padding:4px 0">'+c+'</div>';
      });
      h+='</div>';
    }

    // Red flags
    if(g.redFlags.length>0){
      h+='<div style="margin-bottom:10px;padding:10px;background:rgba(239,68,68,.05);border-radius:6px;border:1px solid rgba(239,68,68,.15)">';
      g.redFlags.forEach(function(rf){
        h+='<div style="font-size:11px;color:var(--red);line-height:1.6;padding:2px 0">'+rf+'</div>';
      });
      h+='</div>';
    }

    // What a great answer looks like
    h+='<details style="margin-bottom:8px"><summary style="font-size:11px;color:var(--accent);cursor:pointer;font-weight:600">💡 What a great answer looks like</summary>';
    h+='<div style="font-size:11px;color:var(--text2);line-height:1.7;margin-top:8px;padding:10px;background:var(--bg);border-radius:6px;border:1px solid var(--border)">'+q.ideal+'</div>';
    h+='</details>';

    // Coaching advice
    h+='<div style="margin-top:8px;padding:10px;background:rgba(198,168,94,.04);border-radius:6px;border:1px solid rgba(200,168,124,.1)">';
    h+='<div style="font-size:10px;font-weight:600;color:var(--accent);text-transform:uppercase;letter-spacing:.5px;margin-bottom:4px">Coaching</div>';
    h+='<div style="font-size:11px;color:var(--text2);line-height:1.7">'+g.advice+'</div>';
    h+='</div>';

    h+='</div>';
  });

  // Bottom section: overall tips
  h+='<div style="padding:20px;background:linear-gradient(160deg,rgba(198,168,94,.06),rgba(200,168,124,.02));border:1px solid rgba(198,168,94,.10);border-radius:12px;margin-bottom:16px">';
  h+='<div style="font-size:12px;font-weight:600;color:var(--accent);margin-bottom:12px;font-family:var(--font-serif)">The honest debrief</div>';
  h+='<div style="font-size:12px;color:var(--text2);line-height:1.8">';

  // Count red flags across all answers
  var totalRed=0;results.forEach(function(r){totalRed+=r.redFlags.length});
  var strongCount=0;results.forEach(function(r){if(r.score>=80)strongCount++});
  var weakCount=0;results.forEach(function(r){if(r.score<40)weakCount++});

  if(avgScore>=80){
    h+='You\'re in good shape. Your answers show specificity, self-awareness, and structure. Here\'s how to go from good to memorable:<br><br>';
    h+='• <strong>Practice out loud</strong> — reading and speaking are different skills. Record yourself.<br>';
    h+='• <strong>Time yourself</strong> — 60-90 seconds per answer. You know the content; now polish the delivery.<br>';
    h+='• <strong>Prepare 3 specific questions per program</strong> — not things on their website.<br>';
    h+='• <strong>Have your 30-second career story ready</strong> — why this path, why now, where you\'re going.';
  }else if(avgScore>=60){
    h+='You have the foundation, but you\'re not there yet. The gap between "solid" and "memorable" is specificity.<br><br>';
    h+='• <strong>Replace every generic statement with a specific example</strong> — names, numbers, outcomes.<br>';
    h+='• <strong>Add reflection to every answer</strong> — "Here\'s what I learned" is the line they remember.<br>';
    h+='• <strong>Cut filler language ruthlessly</strong> — "I think," "kind of," "sort of" signal insecurity.<br>';
    h+='• <strong>Do 2-3 mock interviews with attendings</strong> — not friends, attendings. You need honest feedback.';
    if(totalRed>2) h+='<br>• <strong>Address the '+totalRed+' red flags above</strong> — any one of them can tank an otherwise decent interview.';
  }else{
    h+='Let\'s be real: you need more practice before the real thing. But that\'s exactly why this tool exists — better to learn this now than in front of a program director.<br><br>';
    h+='• <strong>Start with one question at a time</strong> — master "Tell me about yourself" before moving on.<br>';
    h+='• <strong>Every answer needs a specific story</strong> — if you can\'t name a patient, a case, or a date, it\'s too vague.<br>';
    h+='• <strong>Record yourself and watch it back</strong> — painful but there\'s no faster way to improve.<br>';
    h+='• <strong>Get honest feedback from a mentor</strong> — not someone who will be nice. Someone who will be real.<br>';
    h+='• <strong>Come back and retake this in a week</strong> — track your improvement.';
    if(weakCount>2) h+='<br><br>'+weakCount+' of your 5 answers scored below 40. That\'s not a disaster — it\'s a starting point. Focus on the coaching notes above and rewrite each one.';
  }

  h+='</div></div>';

  // Pathway: position + prioritized actions + connect forward
  var misPos=avgScore>=80?'Based on this session, you\'re interview-ready. Your answers show the specificity, self-awareness, and structure that program directors remember. Now polish delivery.'
    :avgScore>=60?'You have solid instincts but you\'re leaving points on the table. The difference between "fine" and "they loved me" is 10 hours of targeted practice.'
    :avgScore>=40?'You\'re not ready for a real interview yet — but that\'s exactly why you\'re here. Focus on the weakest answers above and rewrite them from scratch.'
    :'Honest truth: if you interviewed today, you\'d be forgotten. But every strong interviewer started here. This is your starting line, not your ceiling.';
  var misActs=[];
  if(avgScore<60)misActs.push({text:'Rewrite your weakest answer using STAR format (Situation, Task, Action, Result). Then say it out loud 3 times.',when:'this week'});
  else misActs.push({text:'Record yourself answering your weakest question. Watch it once. You\'ll immediately see what to fix.',when:'this week'});
  if(totalRed>0)misActs.push({text:'Eliminate every red flag identified above — any single one can tank an otherwise decent interview.',when:'this week'});
  else misActs.push({text:'Do a mock interview with an attending — not a friend. You need someone who\'ll be honest, not nice.',when:'this month'});
  misActs.push({text:'Come back and retake this in 1-2 weeks. Track your score improvement — that\'s evidence of growth.',when:'this month'});
  var misNxt=avgScore>=70?{id:'v14',icon:'\ud83d\udcca',title:'Match Competitiveness Calculator',why:'Interviews are one piece. See your full competitiveness score and what moves the needle.'}
    :avgScore>=40?{id:'v15',icon:'\ud83d\uddfa\ufe0f',title:'Career Roadmap Tool',why:'Build a complete timeline — interviews are late-stage. Make sure everything else is on track.'}
    :{id:'v14',icon:'\ud83c\udfc6',title:'Match Probability Calculator',why:'Check your overall competitiveness — interview skills matter more when your stats are borderline.'};
  hwSetAssessmentContext('Interview Practice Tool','v16',['Your interview readiness score is <strong>'+avgScore+'/100</strong>.'+(totalRed>0?' '+totalRed+' red flag'+(totalRed>1?'s':'')+' identified in your responses that could hurt you in a real interview.':''),avgScore>=80?'Your answers show the specificity and structure that program directors remember.':avgScore>=60?'Solid instincts, but you\u2019re leaving points on the table. Targeted practice will close the gap.':'Your answers need significant work before real interviews. Focus on rewriting your weakest responses.'],avgScore+'/100',avgScore>=80?'Ready':avgScore>=60?'Good Foundation':'Needs Work');
  h+=hwGatePathway(hwPathway(misPos,misActs,misNxt));

  // Retake button
  h+='<div style="display:flex;gap:10px;margin-top:14px">';
  h+='<button onclick="misStart()" class="btn btn-a" style="flex:1;padding:12px;font-size:13px"> Retake Interview</button>';
  h+='<button onclick="misNewType()" class="btn btn-g" style="flex:1;padding:12px;font-size:13px"> Try Different Type</button>';
  h+='</div>';
  h+='</div>';

  document.getElementById('mis-feedback').innerHTML=h;
  applyBlurGate(document.getElementById('mis-feedback'));
  document.getElementById('mis-feedback').scrollIntoView({behavior:'smooth',block:'start'});
  // Record with resultData for saved scenarios
  var misSpec=document.getElementById('mis-spec')?document.getElementById('mis-spec').value:'';
  var misType=window._misType||'mixed';
  var misInputs={Specialty:misSpec||'General',Type:misType,'Questions Answered':answered+'/'+questions.length};
  var misHL=[overallLabel+' ('+avgScore+'/100)'];
  if(strongCount)misHL.push(strongCount+' strong answer'+(strongCount>1?'s':''));
  if(weakCount)misHL.push(weakCount+' weak answer'+(weakCount>1?'s':''));
  if(totalRed)misHL.push(totalRed+' red flag'+(totalRed>1?'s':''));
  recordToolUse('Interview Practice Tool',avgScore+'/100',overallLabel,{inputs:misInputs,highlights:misHL});
}

function misNewType(){
  document.getElementById('mis-interview').style.display='none';
  document.getElementById('mis-feedback').innerHTML='';
  document.getElementById('mis-type').value='';
  document.getElementById('mis-tool').scrollIntoView({behavior:'smooth',block:'start'});
}


