// Generate leverage AI response (no credits consumed)
function levGenAI(wfId,userInput){
  var wf=LEV_WORKFLOWS.find(function(w){return w.id===wfId});
  if(!wf)return null;
  var spec='your specialty',stage='trainee';
  if(U&&U.careerProfile){
    spec=U.careerProfile.specialty||spec;
    var sl={student:'medical student',applicant:'graduate applicant',resident:'resident',fellow:'fellow',attending:'attending'};
    stage=sl[U.careerProfile.stage]||stage;
  }
  var inp=userInput.substring(0,300);

  var R={
    'lev-study':{
      answer:'Here\u2019s the move: stop re-reading. Take whatever you described and convert it into questions. For every concept, write one "why does this happen" question and one "what would you do if" clinical scenario. Active recall has a 75% retention rate vs 10% for passive reading (Karpicke & Blunt, Science 2011). Review your questions at day 1, 3, 7, and 21.',
      aiTip:'Use HeartWise to generate board-style questions from any topic instantly. Instead of spending an hour making flashcards, describe the topic in the Ask tool and request practice questions with explanations. You can generate a full week of active recall material in 5 minutes.',
      nextStep:'Take the single topic you feel least confident about right now. Go to Ask, type it in, and request 10 practice questions with explanations. Review them tomorrow.'
    },
    'lev-simplify':{
      answer:'If a concept is confusing, you\u2019re probably trying to memorize it instead of understanding it. Break it into three layers: (1) a simple analogy a patient could understand, (2) the actual mechanism step by step, and (3) the clinical correlation \u2014 how it shows up in patients and on boards. If you can explain it simply, you own it.',
      aiTip:'Use HeartWise Ask to get any concept explained at multiple levels. Type the topic and ask for a simple analogy, the mechanism, and board-relevant clinical pearls. It\u2019s like having a tutor who can explain anything at exactly the level you need.',
      nextStep:'Pick the concept that confused you most recently. Go to Ask and type: "Explain [topic] with a simple analogy, then the mechanism, then clinical pearls for boards."'
    },
    'lev-case':{
      answer:'Clinical reasoning comes from structured case exposure, not textbooks. The key is deliberate practice: build a problem representation (one sentence capturing the key features), generate a differential ranked by probability AND severity, then identify the 2\u20133 tests that would most change your thinking. Do this with 2\u20133 cases per week in your weak areas.',
      aiTip:'Use HeartWise Ask to generate realistic cases on demand. Ask for "a challenging [specialty] case with decision points" and work through it step by step. You can practice more cases in a week than most rotations provide in a month.',
      nextStep:'Go to Ask and type: "Give me a challenging '+spec+' case. Present the chief complaint and vitals first, then let me work through the differential step by step."'
    },
    'lev-research':{
      answer:'Don\u2019t wait for the perfect project or perfect mentor. Look at your last 3 rotations \u2014 what made you think "that\u2019s interesting"? Each of those observations is a potential project. The simplest path: find a clinical question, check if retrospective data exists (EHR, registry), write a one-page proposal, and approach a faculty member WITH the proposal in hand. Initiative is the differentiator.',
      aiTip:'Use HeartWise Ask to brainstorm research questions in your area of interest. Describe what you\u2019ve observed clinically and ask for feasible study designs. You can walk into a mentor meeting with a drafted proposal instead of a vague interest \u2014 that\u2019s what gets you a "yes."',
      nextStep:'Go to Ask and type: "I\u2019m a '+stage+' in '+spec+'. Help me turn this clinical observation into a feasible research question: [your observation]."'
    },
    'lev-lit':{
      answer:'You don\u2019t need to read every paper. For any topic, know 3\u20135 landmark trials: who was studied, what was tested, primary endpoint result, key limitations, and how guidelines changed. That\u2019s it. An attending who "knows the literature" is doing exactly this \u2014 extracting what matters and skipping the rest.',
      aiTip:'Use HeartWise Ask before journal club or a new rotation. Type the topic and ask for the landmark trials with results and limitations. You\u2019ll be able to discuss the evidence intelligently in 5 minutes instead of 5 hours of reading.',
      nextStep:'Go to Ask and type: "What are the landmark trials on [your topic]? For each, give me the population, primary result, and main limitation."'
    },
    'lev-fellowship':{
      answer:'The fellowship match is strategic. NRMP data shows what matters most: (1) letter quality, (2) research productivity, (3) away rotation performance. Build an honest self-assessment across these domains, identify your top 2 gaps, and close them aggressively. Work backward from your match year \u2014 3 months ahead of every deadline.',
      aiTip:'Use HeartWise frameworks to run your actual competitiveness score. Then use Ask to build a personalized timeline working backward from your match date. The combination gives you a data-driven strategy instead of guesswork.',
      nextStep:'Run the Match Probability Calculator in Frameworks first. Then go to Ask with your results and type: "Based on these scores, what are my highest-leverage improvements for '+spec+' fellowship?"'
    },
    'lev-network':{
      answer:'Strategic networking isn\u2019t collecting contacts \u2014 it\u2019s building relationships with people who will advocate for you. Research their recent work before reaching out. Ask for 15 minutes, not "mentorship." Follow up with value (a relevant paper, a progress update). One well-crafted email gets a response 40\u201350% of the time. Most trainees never send it.',
      aiTip:'Use HeartWise Ask to draft specific, professional outreach emails. Describe who you\u2019re reaching out to and why, and get a concise email you can customize. Removes the biggest barrier \u2014 not knowing what to say.',
      nextStep:'Go to Ask and type: "Draft a professional 3-sentence email to a '+spec+' faculty member. I\u2019m a '+stage+' interested in [their research area]. Keep it under 100 words."'
    },
    'lev-productivity':{
      answer:'For every hour of patient care, physicians spend ~2 hours on admin (Sinsky et al., Ann Intern Med 2016). The fix isn\u2019t working harder \u2014 it\u2019s building templates for recurring work, batching similar tasks, and protecting blocks for deep work. Start with your single biggest time drain and systematize it.',
      aiTip:'Use HeartWise Ask to generate templates, lecture outlines, patient handouts, and study materials in minutes instead of hours. The structure comes from the tool; the clinical judgment comes from you. That\u2019s the split.',
      nextStep:'Go to Ask with your biggest time drain. If it\u2019s lectures: "Create a 15-slide outline on [topic] with learning objectives and 2 case examples." If it\u2019s notes: "Create a template for [note type] in '+spec+'."'
    },
    'lev-career-sim':{
      answer:'Most career decisions are made on anecdotes and gut feeling. Model it instead: define what actually matters to you (income, lifestyle, geography, intellectual stimulation), rank those honestly, then compare your options across each variable over 5, 10, and 20 years. Talk to physicians 5\u201310 years into each path \u2014 their perspective is worth more than any data.',
      aiTip:'Use the Financial Planner in HeartWise Frameworks for precise 30-year compensation modeling. Then use Ask to compare lifestyle, market demand, and burnout data across your options. Decision-making with data, not anxiety.',
      nextStep:'Run the Financial Planner in Frameworks for each path you\u2019re considering. Then go to Ask: "Compare '+spec+' vs [alternative] across lifestyle, job market, and burnout data over 10 years."'
    },
    'lev-brand':{
      answer:'Pick ONE platform and ONE niche. "'+spec+' for '+stage+'s" beats "medical education" every time. Post once a week consistently. The 3-1 rule: 3 educational posts for every 1 personal one. You don\u2019t need to be an expert \u2014 documenting your learning journey is genuinely valuable to people one step behind you.',
      aiTip:'Use HeartWise Ask to batch-generate content ideas, outlines, and hooks. Describe your niche and ask for 10 content ideas with hooks and formats. What used to take an evening of brainstorming takes 5 minutes.',
      nextStep:'Go to Ask and type: "Give me 10 educational content ideas for a '+stage+' posting about '+spec+' on [platform]. For each, give me a hook and format (carousel, video, thread)."'
    }
  };
  return R[wfId]||null;
}

function levToggleQuiz(){
  var body=document.getElementById('lev-quiz-body');
  var arrow=document.getElementById('lev-quiz-arrow');
  if(body.style.display==='none'){body.style.display='';arrow.style.transform='rotate(90deg)'}
  else{body.style.display='none';arrow.style.transform=''}
}

function levQuizPick(qIdx,val,el){
  _levQuizAnswers[qIdx]=val;
  el.parentElement.querySelectorAll('.lev-opt').forEach(function(b){b.classList.remove('sel')});
  el.classList.add('sel');
  if(_levQuizAnswers.every(function(a){return a!==null}))levCalcScore();
}

function levCalcScore(){
  var total=0;
  _levQuizAnswers.forEach(function(a){total+=(_levScoreMap[a]||0)});
  var score=Math.round(total/15*100);
  var label,color,desc;
  if(score>=70){
    label='Power User';color='var(--green)';
    desc='You\u2019re already using these tools strategically. Explore the advanced workflows below to push further.';
  }else if(score>=35){
    label='Intermediate';color='var(--accent)';
    desc='You\u2019ve started, but there are high-impact workflows below most trainees miss. Focus on the recommended ones first.';
  }else{
    label='Beginner';color='var(--red)';
    desc='You\u2019re leaving real competitive advantage on the table. Start with the recommended workflows \u2014 even one new habit compounds fast.';
  }
  document.getElementById('lev-score-result').style.display='';
  document.getElementById('lev-score-num').textContent=score;
  document.getElementById('lev-score-num').style.color=color;
  document.getElementById('lev-score-label').textContent=label;
  document.getElementById('lev-score-label').style.color=color;
  document.getElementById('lev-score-desc').textContent=desc;
  var badge=document.getElementById('lev-score-badge');
  badge.style.display='';badge.textContent=score+'/100';
  badge.style.background=color==='var(--green)'?'rgba(92,184,154,.15)':color==='var(--accent)'?'var(--accent-dim)':'rgba(196,77,86,.15)';
  badge.style.color=color;

  var recs=[];
  _levQuizAnswers.forEach(function(a,i){
    if(a==='never'||a==='rarely'){
      _levQuizWorkflowMap[i].forEach(function(wfId){
        var wf=LEV_WORKFLOWS.find(function(w){return w.id===wfId});
        if(wf&&recs.indexOf(wf)===-1)recs.push(wf);
      });
    }
  });
  var recsEl=document.getElementById('lev-score-recs');
  if(recs.length){
    var rh='<div style="font-size:10px;font-weight:600;color:var(--accent);text-transform:uppercase;letter-spacing:1px;margin-bottom:8px">\u26a1 Start With These</div>';
    recs.slice(0,3).forEach(function(wf){
      rh+='<div onclick="levScrollToWorkflow(\''+wf.id+'\')" style="display:flex;align-items:center;gap:10px;padding:8px 12px;background:var(--bg3);border-radius:8px;margin-bottom:6px;cursor:pointer;transition:all .2s">';
      rh+='<span style="font-size:18px">'+wf.icon+'</span>';
      rh+='<div style="text-align:left"><div style="font-size:13px;font-weight:600;color:var(--text)">'+wf.title+'</div>';
      rh+='<div style="font-size:11px;color:var(--text3)">'+wf.tagline+'</div></div></div>';
    });
    recsEl.innerHTML=rh;
  }else{recsEl.innerHTML=''}

  if(U){
    if(!U.leverageScores)U.leverageScores=[];
    U.leverageScores.push({date:new Date().toISOString(),score:score,label:label,answers:_levQuizAnswers.slice()});
    saveUser();
    if(U.leverageScores.length>1){
      var prev=U.leverageScores[U.leverageScores.length-2];
      var delta=score-prev.score;
      var histHtml='Previous: '+prev.score+'/100';
      if(delta>0)histHtml+=' <span style="color:var(--green)">+'+delta+' improvement</span>';
      else if(delta<0)histHtml+=' <span style="color:var(--red)">'+delta+'</span>';
      else histHtml+=' No change';
      document.getElementById('lev-score-history').innerHTML=histHtml;
    }
  }
}

function levResetQuiz(){
  _levQuizAnswers=[null,null,null,null,null];
  document.querySelectorAll('#lev-quiz-questions .lev-opt').forEach(function(b){b.classList.remove('sel')});
  document.getElementById('lev-score-result').style.display='none';
  document.getElementById('lev-score-badge').style.display='none';
  document.getElementById('lev-score-recs').innerHTML='';
  document.getElementById('lev-score-history').innerHTML='';
}

function levScrollToWorkflow(id){
  var body=document.getElementById('lev-quiz-body');
  body.style.display='none';
  document.getElementById('lev-quiz-arrow').style.transform='';
  var card=document.getElementById(id);
  if(card&&!card.classList.contains('expanded'))card.classList.add('expanded');
  setTimeout(function(){if(card)card.scrollIntoView({behavior:'smooth',block:'start'})},100);
}

function levToggleWorkflow(id){
  var card=document.getElementById(id);
  if(!card)return;
  var wasExpanded=card.classList.contains('expanded');
  // Close all other open cards
  document.querySelectorAll('.lev-wf-card.expanded').forEach(function(c){if(c.id!==id)c.classList.remove('expanded')});
  // Toggle clicked card
  if(wasExpanded)card.classList.remove('expanded');
  else card.classList.add('expanded');
}

function levMarkTried(wfId){
  if(!U)return;
  if(!U.leverageTried)U.leverageTried=[];
  if(U.leverageTried.indexOf(wfId)===-1){
    U.leverageTried.push(wfId);
    saveUser();
  }
  levUpdateProgress();
}

function levSubmit(wfId,ev){
  if(ev)ev.stopPropagation();
  var input=document.getElementById('lev-input-'+wfId);
  if(!input)return;
  var text=input.value.trim();
  if(!text||text.length<10){notify('Describe your situation in more detail (min 10 characters)',1);return}

  var resp=levGenAI(wfId,text);
  if(!resp){notify('Something went wrong',1);return}

  levMarkTried(wfId);

  // Render response inline
  var respEl=document.getElementById('lev-resp-'+wfId);
  var h='<div style="margin-top:16px">';
  h+='<div style="padding:18px;background:var(--bg2);border:1px solid var(--border);border-radius:12px;margin-bottom:12px">';
  h+='<div style="font-size:11px;font-weight:600;color:var(--accent);text-transform:uppercase;letter-spacing:1px;margin-bottom:10px">Straight Answer</div>';
  h+='<p style="font-size:14px;color:var(--text);line-height:1.7;margin:0">'+resp.answer+'</p>';
  h+='</div>';
  h+='<div style="padding:18px;background:linear-gradient(160deg,rgba(100,149,237,.06),rgba(100,149,237,.02));border:1px solid rgba(100,149,237,.15);border-radius:12px;margin-bottom:12px">';
  h+='<div style="font-size:11px;font-weight:600;color:var(--blue);text-transform:uppercase;letter-spacing:1px;margin-bottom:10px">\u26a1 How HeartWise Can Help</div>';
  h+='<p style="font-size:14px;color:var(--text2);line-height:1.7;margin:0">'+resp.aiTip+'</p>';
  h+='</div>';
  h+='<div style="padding:18px;background:rgba(92,184,154,.06);border:1px solid rgba(92,184,154,.12);border-radius:12px">';
  h+='<div style="font-size:11px;font-weight:600;color:var(--green);text-transform:uppercase;letter-spacing:1px;margin-bottom:10px">Do This Now</div>';
  h+='<p style="font-size:14px;color:var(--text2);line-height:1.7;margin:0">'+resp.nextStep+'</p>';
  h+='</div>';
  h+='<div style="margin-top:10px;font-size:10px;color:var(--text3);font-style:italic;text-align:center">Unlimited tool access with your plan</div>';
  h+='</div>';
  respEl.innerHTML=h;
  respEl.style.display='';

  // Save to leverage history
  if(!U.leverageHistory)U.leverageHistory=[];
  U.leverageHistory.push({wfId:wfId,input:text.substring(0,500),date:new Date().toISOString()});
  if(U.leverageHistory.length>50)U.leverageHistory=U.leverageHistory.slice(-50);
  saveUser();

  // Update the button
  var btn=document.getElementById('lev-btn-'+wfId);
  if(btn){btn.textContent='Get New Guidance';btn.style.background='var(--bg3)';btn.style.color='var(--accent)';btn.style.border='1px solid rgba(198,168,94,.20)'}
}

function levFilter(cat,btn){
  _levCurrentFilter=cat;
  document.querySelectorAll('.lev-filter').forEach(function(b){b.classList.remove('on')});
  btn.classList.add('on');
  LEV_WORKFLOWS.forEach(function(wf){
    var card=document.getElementById(wf.id);
    if(!card)return;
    card.style.display=(cat==='all'||wf.cat===cat)?'':'none';
  });
}

function levUpdateProgress(){
  var tried=(U&&U.leverageTried)?U.leverageTried.length:0;
  var total=LEV_WORKFLOWS.length;
  var pct=Math.round(tried/total*100);
  document.getElementById('lev-progress-count').textContent=tried+' / '+total;
  document.getElementById('lev-progress-fill').style.width=pct+'%';
  var levelEl=document.getElementById('lev-progress-level');
  var msgEl=document.getElementById('lev-progress-msg');
  if(levelEl){
    if(tried===0){levelEl.textContent='NOT STARTED';levelEl.style.color='var(--text3)'}
    else if(tried<=3){levelEl.textContent='EARLY ADOPTER';levelEl.style.color='var(--accent)'}
    else if(tried<=6){levelEl.textContent='STRATEGIST';levelEl.style.color='var(--green)'}
    else if(tried<=9){levelEl.textContent='TOP 5%';levelEl.style.color='var(--blue)'}
    else{levelEl.textContent='TOP 1%';levelEl.style.color='var(--accent)'}
  }
  if(msgEl){
    if(tried===0) msgEl.textContent='Start with a Quick Win tool — takes under 5 minutes.';
    else if(tried<=3) msgEl.textContent='You\'re ahead of 90% of physicians. Keep building leverage.';
    else if(tried<=6) msgEl.textContent='Serious momentum. You\'re thinking like the top 5%.';
    else if(tried<=9) msgEl.textContent='Almost there. '+( total-tried)+' tool'+(total-tried===1?'':'s')+' left to complete your competitive arsenal.';
    else msgEl.textContent='Full leverage unlocked. You\'re operating at the top 1%. Retake tools anytime to sharpen your edge.';
  }
}

function levScrollToWorkflow(wfId){
  var el=document.getElementById(wfId);
  if(el){el.scrollIntoView({behavior:'smooth',block:'center'});setTimeout(function(){levToggleWorkflow(wfId)},400)}
}

function renderLeverage(){
  try{
  if(!U)return;
  var hasAccess=(U.tier==='elite'&&!U.isTrial)||U.tier==='admin';
  var isCore=U.tier==='core';
  var hero=document.getElementById('lev-hero');
  var filters=document.getElementById('lev-filter-section');
  var quiz=document.getElementById('lev-quiz-section');
  var progress=document.getElementById('lev-progress-bar');
  var workflows=document.getElementById('lev-workflows');
  var wfList=document.getElementById('lev-workflow-list');
  var personalRec=document.getElementById('lev-personal-rec');
  if(!hasAccess){
    // Show static HTML gate, hide interactive sections
    if(hero)hero.style.display='none';
    if(filters)filters.style.display='none';
    if(quiz)quiz.style.display='none';
    if(progress)progress.style.display='none';
    if(workflows)workflows.style.display='none';
    if(personalRec)personalRec.style.display='none';
    var gate=document.getElementById('lev-gate');
    if(gate)gate.style.display='';
    return;
  }
  // Full access
  var gate=document.getElementById('lev-gate');
  if(gate)gate.style.display='none';
  if(hero)hero.style.display='';
  if(filters)filters.style.display='';
  if(quiz)quiz.style.display='';
  if(progress)progress.style.display='';
  if(workflows){workflows.style.display='';workflows.style.padding='12px 24px 100px'}
  if(!U.leverageTried)U.leverageTried=[];
  levUpdateProgress();

  // Personalized recommendations based on career profile
  if(personalRec){
    var cp=U.careerProfile||{};
    var stage=cp.stage||'';
    var goal=cp.concern||'';
    var tried=U.leverageTried||[];
    var recTools=[];var recText='';
    if(stage==='student'||stage==='applicant'){
      recText='As a medical student, these tools will give you the biggest head start:';
      recTools=[{id:'lev-study',why:'Convert lectures into active recall — 75% retention vs 10% passive reading'},{id:'lev-simplify',why:'Master complex concepts at three levels of depth'},{id:'lev-research',why:'Walk into mentor meetings with research proposals ready'}];
    }else if(stage==='resident'){
      recText='Residents who use these tools outperform their peers within weeks:';
      recTools=[{id:'lev-case',why:'Build clinical reasoning faster with realistic case simulations'},{id:'lev-research',why:'Generate publishable research ideas — a PGY-2 got 3 manuscripts started in one session'},{id:'lev-fellowship',why:'Build a strategic fellowship match plan with real data'}];
    }else if(stage==='fellow'){
      recText='As a fellow, your leverage multiplier is highest with these tools:';
      recTools=[{id:'lev-lit',why:'Know every key trial on any topic in minutes, not hours'},{id:'lev-network',why:'Build the strategic relationships that lead to job offers'},{id:'lev-career-sim',why:'Model academic vs private practice with actual data'}];
    }else if(stage==='attending'){
      recText='These tools give attending physicians an immediate competitive edge:';
      recTools=[{id:'lev-career-sim',why:'Make career decisions with data — not assumptions or gut feelings'},{id:'lev-productivity',why:'Reclaim hours from admin work that doesn\'t need your clinical judgment'},{id:'lev-brand',why:'Build the professional platform that compounds over your career'}];
    }else{
      recText='Not sure where to start? These 3 tools take under 5 minutes and deliver immediate value:';
      recTools=[{id:'lev-study',why:'Quick win — convert any topic into active recall instantly'},{id:'lev-simplify',why:'Quick win — understand any concept at three levels of depth'},{id:'lev-lit',why:'Quick win — know the key trials on any topic in minutes'}];
    }
    // Filter out already-tried tools
    var untried=recTools.filter(function(r){return tried.indexOf(r.id)===-1});
    if(untried.length===0)untried=recTools; // show all if all tried
    if(untried.length>0){
      personalRec.style.display='';
      var rText=document.getElementById('lev-personal-rec-text');
      var rTools=document.getElementById('lev-personal-rec-tools');
      if(rText)rText.textContent=recText;
      if(rTools){
        var rh='';
        untried.slice(0,3).forEach(function(r){
          var wf=LEV_WORKFLOWS.find(function(w){return w.id===r.id});
          if(!wf)return;
          var used=tried.indexOf(r.id)!==-1;
          rh+='<div onclick="levScrollToWorkflow(\''+r.id+'\')" style="display:flex;align-items:center;gap:12px;padding:12px;background:var(--bg2);border:1px solid var(--border);border-radius:10px;cursor:pointer;transition:all .2s">';
          rh+='<span style="font-size:22px;flex-shrink:0">'+wf.icon+'</span>';
          rh+='<div style="flex:1;min-width:0"><div style="font-size:13px;font-weight:600;color:var(--text)">'+wf.title+(used?' <span style="font-size:10px;color:var(--green)">✓</span>':'')+'</div>';
          rh+='<div style="font-size:11px;color:var(--text3);line-height:1.4;margin-top:2px">'+r.why+'</div></div>';
          rh+='<span style="color:var(--accent);font-size:14px;flex-shrink:0">→</span></div>';
        });
        rTools.innerHTML=rh;
      }
    }else{
      personalRec.style.display='none';
    }
  }

  // Restore quiz state — collapsed by default
  var quizBody=document.getElementById('lev-quiz-body');
  var quizArrow=document.getElementById('lev-quiz-arrow');
  if(U.leverageScores&&U.leverageScores.length){
    var last=U.leverageScores[U.leverageScores.length-1];
    if(last.answers){
      _levQuizAnswers=last.answers.slice();
      quizBody.style.display='none';quizArrow.style.transform='';
      setTimeout(function(){
        _levQuizAnswers.forEach(function(a,i){
          if(a===null)return;
          var qs=document.querySelectorAll('#lev-quiz-questions .lev-q');
          if(qs[i]){
            var opts=qs[i].querySelectorAll('.lev-opt');
            var vals=['never','rarely','sometimes','daily'];
            var idx=vals.indexOf(a);
            if(idx>=0&&opts[idx])opts[idx].classList.add('sel');
          }
        });
        levCalcScore();
      },50);
    }
  }else{
    // Collapsed by default — user can expand if interested
    quizBody.style.display='none';quizArrow.style.transform='';
  }

  // Render workflow cards
  var tried=U.leverageTried||[];
  var diffLabels={starter:'Starter',intermediate:'Intermediate',advanced:'Advanced'};
  var diffColors={starter:'var(--green)',intermediate:'var(--accent)',advanced:'var(--red)'};
  // Quick win tools + outcome examples
  var quickWins={'lev-study':true,'lev-simplify':true,'lev-lit':true};
  var outcomes={
    'lev-study':'A PGY-1 converted a week of cardiology lectures into 200+ active recall questions in 15 minutes.',
    'lev-research':'A PGY-2 generated 3 publishable research ideas and walked into their mentor meeting prepared for the first time.',
    'lev-case':'A fellow practiced 5 complex PCI scenarios in one sitting — more than she\'d see in a month of call.',
    'lev-lit':'An attending prepped for journal club on DAPA-HF in 8 minutes instead of 3 hours.',
    'lev-network':'A resident built a targeted networking plan for TCT and got introduced to 2 interventional PDs.',
    'lev-fellowship':'A PGY-2 from a community program identified 3 CV gaps and fixed them before applications opened.',
    'lev-productivity':'An attending automated lecture prep — what used to take 4 hours now takes 30 minutes.',
    'lev-career-sim':'A fellow modeled academic vs private practice and realized the 10-year difference was $2.1M.',
    'lev-brand':'A resident launched a medical education account and had 1,000 followers within a month.',
    'lev-simplify':'A student went from failing to understand heart failure pathophys to teaching it to classmates.'
  };
  var h='';
  LEV_WORKFLOWS.forEach(function(wf){
    var isTried=tried.indexOf(wf.id)!==-1;
    var triedBadge=isTried?'<span class="lev-tried-badge" style="background:rgba(92,184,154,.15);color:var(--green)">\u2713 Used</span>':'';
    var quickBadge=quickWins[wf.id]&&!isTried?'<span style="background:rgba(198,168,94,.12);color:var(--accent);font-size:9px;padding:2px 7px;border-radius:10px;font-weight:600;letter-spacing:.3px">⚡ Quick Win</span>':'';

    h+='<div class="lev-wf-card" id="'+wf.id+'" data-cat="'+wf.cat+'" onclick="levToggleWorkflow(\''+wf.id+'\')">';
    h+='<div style="display:flex;gap:14px;align-items:flex-start">';
    h+='<div style="font-size:26px;flex-shrink:0;margin-top:2px">'+wf.icon+'</div>';
    h+='<div style="flex:1;min-width:0">';
    h+='<div style="display:flex;align-items:center;gap:8px;flex-wrap:wrap;margin-bottom:4px">';
    h+='<span style="font-size:15px;font-weight:600;color:var(--text)">'+wf.title+'</span>';
    h+='<span style="font-size:9px;padding:2px 7px;border-radius:10px;font-weight:600;letter-spacing:.3px;border:1px solid;color:'+diffColors[wf.difficulty]+';border-color:'+diffColors[wf.difficulty]+';opacity:.7">'+diffLabels[wf.difficulty]+'</span>';
    h+=triedBadge;
    h+=quickBadge;
    h+='</div>';
    h+='<p style="font-size:13px;color:var(--text3);line-height:1.5;margin:0">'+wf.tagline+'</p>';
    if(outcomes[wf.id]){
      h+='<p style="font-size:11px;color:var(--text3);line-height:1.4;margin:6px 0 0;font-style:italic;opacity:.8">"'+outcomes[wf.id]+'"</p>';
    }
    h+='</div>';
    h+='<span style="color:var(--text3);font-size:14px;flex-shrink:0;transition:transform .2s">\u203a</span>';
    h+='</div>';

    // Expandable detail
    h+='<div class="lev-wf-detail" onclick="event.stopPropagation()">';
    h+='<p style="font-size:14px;color:var(--text2);line-height:1.7;margin-bottom:16px">'+wf.message+'</p>';

    // Input area
    h+='<div style="margin-bottom:12px">';
    h+='<label style="font-size:11px;font-weight:600;color:var(--accent);text-transform:uppercase;letter-spacing:1px;display:block;margin-bottom:8px">Describe Your Situation</label>';
    h+='<textarea id="lev-input-'+wf.id+'" placeholder="'+wf.placeholder+'" style="width:100%;min-height:80px;padding:12px 14px;background:var(--bg3);border:1px solid var(--border);border-radius:10px;color:var(--text);font-size:14px;line-height:1.6;resize:vertical;font-family:inherit" onclick="event.stopPropagation()"></textarea>';
    h+='</div>';
    h+='<button id="lev-btn-'+wf.id+'" class="btn btn-a" onclick="levSubmit(\''+wf.id+'\',event)" style="padding:12px 20px;font-size:14px;font-weight:600;width:100%;border-radius:10px">Get Strategic Guidance \u2192</button>';

    // Response area (hidden until generated)
    h+='<div id="lev-resp-'+wf.id+'" style="display:none"></div>';

    if(wf.linkText){
      h+='<button onclick="event.stopPropagation();'+wf.linkAction+'" style="margin-top:14px;padding:10px 20px;background:var(--accent-dim);border:1px solid rgba(198,168,94,.15);border-radius:8px;color:var(--accent);font-size:13px;font-weight:600;cursor:pointer;width:100%;text-align:center">'+wf.linkText+'</button>';
    }

    h+='<div style="margin-top:12px;font-size:11px;color:var(--text3);text-align:center">\u2728 Run as many times as you want</div>';

    h+='</div>'; // detail
    h+='</div>'; // card
  });
  document.getElementById('lev-workflow-list').innerHTML=h;
  }catch(ex){console.error('renderLeverage error:',ex);var wl=document.getElementById('lev-workflow-list');if(wl)wl.innerHTML='<div style="padding:40px;text-align:center;color:#c44d56">Error: '+ex.message+'</div>'}
}

// ===== SAVED SCENARIOS + COMPARE =====
function getSavedScenarios(toolName){if(!U||!U.toolHistory)return[];return U.toolHistory.filter(function(t){return t.tool===toolName&&t.data}).slice(-10)}
function showSavedScenarios(toolName){
  var sc=getSavedScenarios(toolName);
  if(!sc.length){notify('No saved scenarios yet. Run the tool first.');return}
  var h='<div style="padding:20px"><div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:16px"><div style="font-size:16px;font-weight:600;color:var(--text);font-family:var(--font-serif)">📊 Saved Scenarios</div><button onclick="closeModal(\'modal-q\')" style="background:none;border:none;color:var(--text3);font-size:18px;cursor:pointer">✕</button></div>';
  h+='<div style="font-size:11px;color:var(--text3);margin-bottom:14px">'+toolName+' — '+sc.length+' saved</div>';
  if(sc.length>=2){
    h+='<div style="margin-bottom:14px;padding:12px;background:linear-gradient(160deg,rgba(198,168,94,.08),rgba(200,168,124,.03));border:1px solid rgba(198,168,94,.15);border-radius:10px"><div style="font-size:11px;font-weight:600;color:var(--accent);margin-bottom:8px">Compare Two Runs</div><div style="display:flex;gap:8px;align-items:center">';
    h+='<select id="sc-a" style="flex:1;padding:8px;border:1px solid var(--border);border-radius:6px;background:var(--bg);color:var(--text);font-size:11px">';
    sc.forEach(function(s,i){h+='<option value="'+i+'">'+new Date(s.date).toLocaleDateString('en-US',{month:'short',day:'numeric'})+' — '+(s.summary||'Run '+(i+1))+'</option>'});
    h+='</select><span style="color:var(--text3);font-size:11px">vs</span><select id="sc-b" style="flex:1;padding:8px;border:1px solid var(--border);border-radius:6px;background:var(--bg);color:var(--text);font-size:11px">';
    sc.forEach(function(s,i){h+='<option value="'+i+'"'+(i===sc.length-1?' selected':'')+'>'+new Date(s.date).toLocaleDateString('en-US',{month:'short',day:'numeric'})+' — '+(s.summary||'Run '+(i+1))+'</option>'});
    h+='</select><button onclick="compareScenarios(\''+toolName.replace(/'/g,"\\'")+'\',document.getElementById(\'sc-a\').value,document.getElementById(\'sc-b\').value)" style="padding:8px 14px;background:var(--accent);color:#1C1A17;border:none;border-radius:6px;font-size:11px;font-weight:600;cursor:pointer">Compare</button></div></div>';
  }
  sc.slice().reverse().forEach(function(s,ri){var i=sc.length-1-ri;var d=new Date(s.date);
    h+='<div class="card" style="padding:14px;margin-bottom:8px;cursor:pointer" onclick="viewScenario(\''+toolName.replace(/'/g,"\\'")+'\','+i+')">';
    h+='<div style="display:flex;justify-content:space-between;align-items:center"><div><div style="font-size:12px;font-weight:600;color:var(--text)">'+(s.summary||'Run '+(i+1))+'</div>';
    h+='<div style="font-size:10px;color:var(--text3);margin-top:2px">'+d.toLocaleDateString('en-US',{month:'long',day:'numeric',hour:'numeric',minute:'2-digit'})+'</div></div>';
    if(s.score) h+='<div style="font-size:14px;font-weight:700;color:var(--accent)">'+s.score+'</div>';
    h+='</div></div>';
  });
  h+='</div>';
  document.getElementById('modal-q-content').innerHTML=h;document.getElementById('modal-q').classList.remove('hidden');
}
function viewScenario(toolName,idx){
  var sc=getSavedScenarios(toolName);if(!sc[idx])return;var s=sc[idx];var d=new Date(s.date);
  var h='<div style="padding:20px"><div style="display:flex;justify-content:space-between;margin-bottom:16px"><div><div style="font-size:16px;font-weight:600;color:var(--text);font-family:var(--font-serif)">'+(s.summary||toolName)+'</div><div style="font-size:10px;color:var(--text3);margin-top:2px">'+d.toLocaleDateString('en-US',{month:'long',day:'numeric',year:'numeric'})+'</div></div><button onclick="showSavedScenarios(\''+toolName.replace(/'/g,"\\'")+'\');return" style="background:none;border:none;color:var(--accent);font-size:12px;cursor:pointer;font-weight:600">← Back</button></div>';
  if(s.data&&s.data.inputs){h+='<div style="margin-bottom:14px"><div style="font-size:10px;font-weight:600;color:var(--accent);text-transform:uppercase;letter-spacing:1px;margin-bottom:6px">Inputs</div>';
    Object.keys(s.data.inputs).forEach(function(k){var v=s.data.inputs[k];if(v===''||v===null||v===undefined)return;h+='<div style="display:flex;justify-content:space-between;padding:4px 0;border-bottom:1px solid var(--border);font-size:11px"><span style="color:var(--text3)">'+k+'</span><span style="color:var(--text);font-weight:500">'+v+'</span></div>'});h+='</div>'}
  if(s.score) h+='<div style="margin-bottom:14px;text-align:center;padding:16px;background:var(--bg2);border-radius:10px"><div style="font-size:10px;color:var(--text3);margin-bottom:4px">Score</div><div style="font-size:28px;font-weight:700;color:var(--accent);font-family:var(--font-serif)">'+s.score+'</div></div>';
  if(s.data&&s.data.highlights){h+='<div><div style="font-size:10px;font-weight:600;color:var(--accent);text-transform:uppercase;letter-spacing:1px;margin-bottom:6px">Key Results</div>';s.data.highlights.forEach(function(hl){h+='<div style="font-size:12px;color:var(--text);line-height:1.6;padding:3px 0">• '+hl+'</div>'});h+='</div>'}
  h+='</div>';document.getElementById('modal-q-content').innerHTML=h;
}
function compareScenarios(toolName,ai,bi){
  var sc=getSavedScenarios(toolName);var a=sc[parseInt(ai)],b=sc[parseInt(bi)];
  if(!a||!b){notify('Select two scenarios',1);return}
  if(ai===bi){notify('Pick two different runs',1);return}
  var dA=new Date(a.date),dB=new Date(b.date);
  var h='<div style="padding:20px"><div style="display:flex;justify-content:space-between;margin-bottom:16px"><div style="font-size:16px;font-weight:600;color:var(--text);font-family:var(--font-serif)">📊 Comparison</div><button onclick="showSavedScenarios(\''+toolName.replace(/'/g,"\\'")+'\');return" style="background:none;border:none;color:var(--accent);font-size:12px;cursor:pointer;font-weight:600">← Back</button></div>';
  h+='<div style="display:grid;grid-template-columns:1fr 1fr 1fr;gap:8px;margin-bottom:12px;font-size:10px;font-weight:600;color:var(--text3);text-transform:uppercase"><div></div><div style="text-align:center">'+dA.toLocaleDateString('en-US',{month:'short',day:'numeric'})+'</div><div style="text-align:center">'+dB.toLocaleDateString('en-US',{month:'short',day:'numeric'})+'</div></div>';
  if(a.score||b.score){h+='<div style="display:grid;grid-template-columns:1fr 1fr 1fr;gap:8px;padding:10px 0;border-bottom:1px solid var(--border)"><div style="font-size:11px;font-weight:600;color:var(--text)">Score</div><div style="text-align:center;font-size:18px;font-weight:700;color:var(--accent);font-family:var(--font-serif)">'+(a.score||'—')+'</div><div style="text-align:center;font-size:18px;font-weight:700;color:var(--accent2);font-family:var(--font-serif)">'+(b.score||'—')+'</div></div>'}
  if(a.data&&a.data.inputs&&b.data&&b.data.inputs){var keys={};Object.keys(a.data.inputs).forEach(function(k){keys[k]=1});Object.keys(b.data.inputs).forEach(function(k){keys[k]=1});
    Object.keys(keys).forEach(function(k){var av=a.data.inputs[k]||'—',bv=b.data.inputs[k]||'—';var diff=String(av)!==String(bv);h+='<div style="display:grid;grid-template-columns:1fr 1fr 1fr;gap:8px;padding:6px 0;border-bottom:1px solid var(--border);font-size:11px;'+(diff?'background:rgba(200,168,124,.05)':'')+'"><div style="color:var(--text3)">'+k+'</div><div style="text-align:center;color:var(--text);font-weight:'+(diff?'600':'400')+'">'+av+'</div><div style="text-align:center;color:var(--text);font-weight:'+(diff?'600':'400')+'">'+bv+'</div></div>'})}
  h+='</div>';document.getElementById('modal-q-content').innerHTML=h;
}

// ===== WEEKLY CHECK-IN =====
function showWeeklyCheckin(){
  if(!U)return;if(!U.weeklyGoals)U.weeklyGoals=[];if(!U.checkins)U.checkins=[];
  var h='<div style="padding:24px"><div style="text-align:center;margin-bottom:20px"><div style="font-size:32px;margin-bottom:8px">📋</div><div style="font-size:18px;font-weight:600;color:var(--text);font-family:var(--font-serif)">Weekly Check-in</div><div style="font-size:12px;color:var(--text3);margin-top:4px">2 minutes. Update your trajectory.</div></div>';
  var lastGoal=U.weeklyGoals.length?U.weeklyGoals[U.weeklyGoals.length-1]:null;
  if(lastGoal&&lastGoal.status==='active'){
    h+='<div style="margin-bottom:16px"><div style="font-size:11px;font-weight:600;color:var(--accent);text-transform:uppercase;letter-spacing:1px;margin-bottom:6px">Last Week\'s Goal</div>';
    h+='<div style="padding:10px 14px;background:var(--bg2);border-radius:8px;font-size:12px;color:var(--text);margin-bottom:8px">"'+lastGoal.goal+'"</div>';
    h+='<div style="display:flex;gap:8px"><input type="hidden" id="ci-status" value="">';
    h+='<button onclick="this.parentElement.querySelectorAll(\'button\').forEach(function(b){b.style.borderColor=\'var(--border)\';b.style.background=\'var(--bg)\'});this.style.borderColor=\'var(--green)\';this.style.background=\'rgba(106,170,100,.1)\';document.getElementById(\'ci-status\').value=\'completed\'" style="flex:1;padding:10px;border:2px solid var(--border);border-radius:8px;background:var(--bg);cursor:pointer;font-size:11px;font-weight:600;color:var(--green)">✅ Done</button>';
    h+='<button onclick="this.parentElement.querySelectorAll(\'button\').forEach(function(b){b.style.borderColor=\'var(--border)\';b.style.background=\'var(--bg)\'});this.style.borderColor=\'var(--accent)\';this.style.background=\'rgba(200,168,124,.1)\';document.getElementById(\'ci-status\').value=\'progress\'" style="flex:1;padding:10px;border:2px solid var(--border);border-radius:8px;background:var(--bg);cursor:pointer;font-size:11px;font-weight:600;color:var(--accent)"> In Progress</button>';
    h+='<button onclick="this.parentElement.querySelectorAll(\'button\').forEach(function(b){b.style.borderColor=\'var(--border)\';b.style.background=\'var(--bg)\'});this.style.borderColor=\'var(--red)\';this.style.background=\'rgba(192,96,96,.1)\';document.getElementById(\'ci-status\').value=\'missed\'" style="flex:1;padding:10px;border:2px solid var(--border);border-radius:8px;background:var(--bg);cursor:pointer;font-size:11px;font-weight:600;color:var(--red)">❌ Missed</button>';
    h+='</div></div>';
  }
  h+='<div style="margin-bottom:16px"><div style="font-size:11px;font-weight:600;color:var(--accent);text-transform:uppercase;letter-spacing:1px;margin-bottom:6px">Any New Developments?</div><div style="font-size:10px;color:var(--text3);margin-bottom:6px">Offers, interviews, publications, scores, decisions...</div><textarea id="ci-dev" rows="3" style="width:100%;padding:10px;border:1px solid var(--border);border-radius:8px;background:var(--bg);color:var(--text);font-size:12px;resize:vertical;font-family:var(--font-body)" placeholder="e.g., Got an interview at Hopkins, Step 2 came back 255..."></textarea></div>';
  h+='<div style="margin-bottom:20px"><div style="font-size:11px;font-weight:600;color:var(--accent);text-transform:uppercase;letter-spacing:1px;margin-bottom:6px">This Week\'s Goal</div><input type="text" id="ci-goal" style="width:100%;padding:10px;border:1px solid var(--border);border-radius:8px;background:var(--bg);color:var(--text);font-size:12px;font-family:var(--font-body)" placeholder="e.g., Submit 2 fellowship apps, finish abstract..."></div>';
  h+='<button onclick="submitCheckin()" style="width:100%;padding:14px;background:var(--accent);color:#1C1A17;border:none;border-radius:10px;font-size:14px;font-weight:600;cursor:pointer">Save Check-in →</button></div>';
  document.getElementById('modal-q-content').innerHTML=h;document.getElementById('modal-q').classList.remove('hidden');
}
function submitCheckin(){
  if(!U)return;if(!U.weeklyGoals)U.weeklyGoals=[];if(!U.checkins)U.checkins=[];
  var st=document.getElementById('ci-status');var statusVal=st?st.value:'';
  var dev=document.getElementById('ci-dev');var devVal=dev?dev.value.trim():'';
  var goal=document.getElementById('ci-goal');var goalVal=goal?goal.value.trim():'';
  U.checkins.push({date:new Date().toISOString(),status:statusVal,developments:devVal,goal:goalVal});
  if(U.checkins.length>52)U.checkins=U.checkins.slice(-52);
  if(statusVal&&U.weeklyGoals.length)U.weeklyGoals[U.weeklyGoals.length-1].status=statusVal;
  if(goalVal){U.weeklyGoals.push({goal:goalVal,date:new Date().toISOString(),status:'active'});if(U.weeklyGoals.length>52)U.weeklyGoals=U.weeklyGoals.slice(-52)}
  U.lastCheckin=new Date().toISOString();saveUser();closeModal('modal-q');
  notify('Check-in saved! Stay focused this week. 💪');renderHome();
}

// ===== "YOUR STATUS" — WHAT CHANGED FEED =====
function renderWhatsChanged(){
  var el=document.getElementById('whats-changed');if(!el||!U)return;
  if(U.tier==='free'&&!U.isTrial){el.style.display='none';return}
  var now=new Date();var items=[];var cp=U.careerProfile||{};var stage=cp.stage||'student';
  if(U.weeklyGoals&&U.weeklyGoals.length){var cur=U.weeklyGoals[U.weeklyGoals.length-1];if(cur.status==='active')items.push({icon:'🎯',text:'This week: <strong>'+cur.goal+'</strong>'})}
  var lc=U.lastCheckin?new Date(U.lastCheckin):null;
  var daysSinceCheckin=lc?Math.floor((now-lc)/86400000):999;
  var isMonday=now.getDay()===1;
  if(isMonday&&daysSinceCheckin>=5){
    items.unshift({icon:'📋',text:'<strong style="color:var(--accent)">Monday check-in!</strong> <span onclick="showWeeklyCheckin()" style="color:var(--accent);cursor:pointer;text-decoration:underline">Start your weekly check-in</span> — set this week\'s goal'});
  }else if(daysSinceCheckin>=7){
    items.push({icon:'📋',text:'<span onclick="showWeeklyCheckin()" style="color:var(--accent);cursor:pointer;text-decoration:underline">Weekly check-in ready</span> — 2 min'});
  }
  if(cp.lastUpdated){var age=Math.floor((now-new Date(cp.lastUpdated))/86400000);if(age>=30)items.push({icon:'',text:'Scores are <strong>'+age+'d old</strong>. <span onclick="showUpdateProfile()" style="color:var(--accent);cursor:pointer;text-decoration:underline">Refresh</span>'})}
  var m=now.getMonth();var alerts={student:[{m:8,t:'ERAS opens soon — personal statement ready?'},{m:2,t:'Match Day this month! 🎉'},{m:6,t:'Away rotation season'}],resident:[{m:5,t:'Fellowship apps opening soon'},{m:9,t:'Contract season — run Contract Review'}],fellow:[{m:9,t:'Job search — analyze every offer'}],attending:[{m:0,t:'New year — review financial trajectory'},{m:9,t:'Contract renewal season'}]};
  (alerts[stage]||alerts.student).forEach(function(a){if(a.m===m)items.push({icon:'📅',text:a.t})});
  if(U.toolHistory&&U.toolHistory.length){var lt=U.toolHistory[U.toolHistory.length-1];items.push({icon:'🧭',text:'Last ran <strong>'+lt.tool+'</strong>'+(lt.score?' ('+lt.score+')':'')})}
  if(!items.length){el.style.display='none';return}
  el.style.display='';
  var h='<div style="padding:14px 16px;background:linear-gradient(160deg,rgba(198,168,94,.06),rgba(200,168,124,.02));border:1px solid rgba(198,168,94,.15);border-radius:12px">';
  h+='<div style="font-size:10px;font-weight:600;color:var(--accent);text-transform:uppercase;letter-spacing:1px;margin-bottom:8px">📌 Your Status</div>';
  items.forEach(function(it){h+='<div style="display:flex;align-items:flex-start;gap:8px;padding:4px 0;font-size:12px;color:var(--text);line-height:1.5"><span style="flex-shrink:0">'+it.icon+'</span><span>'+it.text+'</span></div>'});
  h+='</div>';el.innerHTML=h;
}


