function ocSelectType(btn,val){
  btn.parentElement.querySelectorAll('button').forEach(function(b){
    b.style.background='var(--bg3)';b.style.borderColor='var(--border)';b.style.color='var(--text3)';
  });
  btn.style.background='rgba(198,168,94,.15)';btn.style.borderColor='var(--accent)';btn.style.color='var(--accent)';
  btn.dataset.selected='true';
}

function ocSelectHelped(btn,val){
  document.querySelectorAll('#oc-helped button').forEach(function(b){
    b.style.background='var(--bg3)';b.style.borderColor='var(--border)';b.style.color='var(--text3)';
  });
  btn.style.background='rgba(198,168,94,.15)';btn.style.borderColor='var(--accent)';btn.style.color='var(--accent)';
  btn.dataset.selected='true';
}

function saveOutcome(){
  if(!U)return;
  if(!U.outcomes)U.outcomes=[];
  // Get selected type
  var typeBtn=document.querySelector('[data-val][data-selected="true"][onclick*="ocSelectType"]');
  if(!typeBtn){notify('Select what you achieved',1);return}
  var type=typeBtn.dataset.val;
  var details=(document.getElementById('oc-details')||{}).value||'';
  if(!details.trim()){notify('Tell us what happened — even a sentence helps',1);return}
  var dateVal=(document.getElementById('oc-date')||{}).value||new Date().toISOString().split('T')[0];

  // Get helpful tools
  var helpfulTools=[];
  document.querySelectorAll('.oc-tool-active').forEach(function(b){helpfulTools.push(b.dataset.tool)});

  // Get helped rating
  var helpedBtn=document.querySelector('#oc-helped button[data-selected="true"]');
  var helped=helpedBtn?helpedBtn.dataset.val:'';

  var outcome={
    id:'oc-'+Date.now(),
    date:dateVal,
    type:type,
    typeLabel:typeBtn.textContent.trim(),
    details:details,
    salary:(document.getElementById('oc-salary')||{}).value||'',
    bonus:(document.getElementById('oc-bonus')||{}).value||'',
    program:(document.getElementById('oc-program')||{}).value||'',
    location:(document.getElementById('oc-location')||{}).value||'',
    helpfulTools:helpfulTools,
    helped:helped,
    recordedAt:new Date().toISOString(),
    // Snapshot scores at time of achievement
    scoresAtTime:U.scoreHistory&&U.scoreHistory.length?JSON.parse(JSON.stringify(U.scoreHistory[U.scoreHistory.length-1].scores)):null,
    profileAtTime:{
      stage:(U.careerProfile||{}).stage||'',
      specialty:(U.careerProfile||{}).specialty||'',
      pubs:(U.careerProfile||{}).pubs||'',
      step2:(U.careerProfile||{}).step2||''
    }
  };

  U.outcomes.push(outcome);
  if(U.outcomes.length>50)U.outcomes=U.outcomes.slice(-50);
  saveUser();
  closeModal('modal-q');
  notify('Achievement documented! 🏆 This is saved to your profile.');
  if(typeof renderProfile==='function')renderProfile();
  if(typeof renderOutcomesOnProfile==='function')renderOutcomesOnProfile();
}

// ===== USER-FACING: OUTCOMES ON PROFILE =====
function renderOutcomesOnProfile(){
  var el=document.getElementById('profile-outcomes');
  if(!el||!U)return;
  var outcomes=U.outcomes||[];
  var hasPlan=U.tier==='student'||U.tier==='core'||U.tier==='elite'||U.tier==='admin'||U.isTrial;
  if(!hasPlan){el.style.display='none';return}

  el.style.display='';
  var h='<div class="card" style="padding:16px">';
  h+='<div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:12px">';
  h+='<div style="font-size:14px;font-weight:600;color:var(--text);font-family:var(--font-serif)">🏆 My Achievements</div>';
  h+='<button onclick="showOutcomeCapture()" style="padding:6px 14px;font-size:11px;background:var(--accent);color:#1C1A17;border:none;border-radius:8px;cursor:pointer;font-weight:600">+ Record Win</button>';
  h+='</div>';

  if(!outcomes.length){
    h+='<div style="text-align:center;padding:20px 0">';
    h+='<div style="font-size:28px;margin-bottom:8px">🎯</div>';
    h+='<div style="font-size:13px;color:var(--text2)">No achievements documented yet.</div>';
    h+='<div style="font-size:11px;color:var(--text3);margin-top:4px">When you reach a career milestone — match, job offer, negotiation win, debt payoff — record it here.</div>';
    h+='</div>';
  } else {
    outcomes.slice().reverse().forEach(function(o,idx){
      var oDate=new Date(o.date).toLocaleDateString('en-US',{month:'long',day:'numeric',year:'numeric'});
      h+='<div style="padding:12px;background:var(--bg2);border-radius:10px;margin-bottom:8px;border-left:3px solid var(--accent)">';
      h+='<div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:4px">';
      h+='<div style="font-size:13px;font-weight:600;color:var(--text)">'+o.typeLabel+'</div>';
      h+='<span style="font-size:10px;color:var(--text3)">'+oDate+'</span></div>';
      h+='<div style="font-size:12px;color:var(--text2);line-height:1.6">'+o.details+'</div>';
      var meta=[];
      if(o.program)meta.push(o.program);
      if(o.location)meta.push(o.location);
      if(o.salary)meta.push(o.salary);
      if(meta.length)h+='<div style="font-size:11px;color:var(--text3);margin-top:4px">'+meta.join(' · ')+'</div>';
      if(o.helpfulTools&&o.helpfulTools.length){
        h+='<div style="display:flex;flex-wrap:wrap;gap:3px;margin-top:6px">';
        o.helpfulTools.forEach(function(t){
          h+='<span style="font-size:9px;padding:2px 8px;background:rgba(198,168,94,.08);color:var(--accent);border-radius:10px">'+t+'</span>';
        });
        h+='</div>';
      }
      // Score snapshot comparison
      if(o.scoresAtTime){
        var currentScores=U.scoreHistory&&U.scoreHistory.length?U.scoreHistory[U.scoreHistory.length-1].scores:{};
        h+='<div style="display:flex;gap:6px;margin-top:6px">';
        ['competitiveness','research','readiness','financial'].forEach(function(d){
          var then=o.scoresAtTime[d]||0;
          h+='<span style="font-size:9px;color:var(--text3);padding:2px 6px;background:var(--bg);border-radius:4px">'+d.substring(0,4)+': '+then+'</span>';
        });
        h+='</div>';
      }
      h+='</div>';
    });
  }
  h+='</div>';
  el.innerHTML=h;
}

// ===== ADMIN-FACING: OUTCOMES TAB =====
function admRenderOutcomes(c){
  var users=admGetUsers();
  var allOutcomes=[];

  users.forEach(function(u){
    var outcomes=u.outcomes||(u.session_data&&u.session_data.outcomes)||[];
    if(typeof outcomes==='string'){try{outcomes=JSON.parse(outcomes)}catch(e){outcomes=[]}}
    if(!Array.isArray(outcomes))outcomes=[];
    outcomes.forEach(function(o){
      allOutcomes.push({
        user:u.name||u.email||'Unknown',
        userId:u.id,
        email:u.email||'',
        stage:u.stage||u.training_stage||(u.profile_data&&u.profile_data.stage)||'',
        specialty:u.specialty||(u.profile_data&&u.profile_data.specialty)||'',
        tier:u.tier||'free',
        outcome:o
      });
    });
  });

  // Sort by date descending
  allOutcomes.sort(function(a,b){return new Date(b.outcome.date)-new Date(a.outcome.date)});

  var h='<div style="margin-bottom:16px">';
  h+='<div style="font-size:16px;font-weight:600;color:var(--text);font-family:var(--font-serif);margin-bottom:4px">🏆 User Outcomes & Achievements</div>';
  h+='<div style="font-size:12px;color:var(--text3);margin-bottom:16px">'+allOutcomes.length+' documented outcome'+(allOutcomes.length!==1?'s':'')+' across all users. This data is private — only visible to admin.</div>';
  h+='</div>';

  if(!allOutcomes.length){
    h+='<div style="text-align:center;padding:40px 0">';
    h+='<div style="font-size:40px;margin-bottom:12px">📊</div>';
    h+='<div style="font-size:14px;color:var(--text2)">No outcomes documented yet.</div>';
    h+='<div style="font-size:12px;color:var(--text3);margin-top:4px">When users record career achievements, they\'ll appear here.</div>';
    h+='</div>';
    c.innerHTML=h;return;
  }

  // Summary stats
  var typeCount={};var helpedCount={yes:0,somewhat:0,no:0};var toolMentions={};
  allOutcomes.forEach(function(ao){
    var o=ao.outcome;
    typeCount[o.type]=(typeCount[o.type]||0)+1;
    if(o.helped)helpedCount[o.helped]=(helpedCount[o.helped]||0)+1;
    if(o.helpfulTools)o.helpfulTools.forEach(function(t){toolMentions[t]=(toolMentions[t]||0)+1});
  });

  h+='<div style="display:grid;grid-template-columns:repeat(4,1fr);gap:8px;margin-bottom:16px">';
  h+='<div style="text-align:center;padding:12px;background:var(--bg2);border-radius:10px"><div style="font-size:24px;font-weight:700;color:var(--accent)">'+allOutcomes.length+'</div><div style="font-size:10px;color:var(--text3)">Total Outcomes</div></div>';
  h+='<div style="text-align:center;padding:12px;background:var(--bg2);border-radius:10px"><div style="font-size:24px;font-weight:700;color:var(--green)">'+helpedCount.yes+'</div><div style="font-size:10px;color:var(--text3)">HW Helped (Yes)</div></div>';
  h+='<div style="text-align:center;padding:12px;background:var(--bg2);border-radius:10px"><div style="font-size:24px;font-weight:700;color:var(--text)">'+helpedCount.somewhat+'</div><div style="font-size:10px;color:var(--text3)">Somewhat</div></div>';
  var uniqueUsers={};allOutcomes.forEach(function(ao){uniqueUsers[ao.userId]=true});
  h+='<div style="text-align:center;padding:12px;background:var(--bg2);border-radius:10px"><div style="font-size:24px;font-weight:700;color:var(--text)">'+Object.keys(uniqueUsers).length+'</div><div style="font-size:10px;color:var(--text3)">Users w/ Outcomes</div></div>';
  h+='</div>';

  // Top mentioned tools
  var sortedTools=Object.entries(toolMentions).sort(function(a,b){return b[1]-a[1]});
  if(sortedTools.length){
    h+='<div style="margin-bottom:16px;padding:12px;background:var(--bg2);border-radius:10px">';
    h+='<div style="font-size:11px;font-weight:600;color:var(--accent);text-transform:uppercase;letter-spacing:1px;margin-bottom:8px">Most Helpful Tools (User-Reported)</div>';
    sortedTools.slice(0,5).forEach(function(t){
      h+='<div style="display:flex;justify-content:space-between;align-items:center;padding:4px 0">';
      h+='<span style="font-size:12px;color:var(--text)">'+t[0]+'</span>';
      h+='<span style="font-size:12px;font-weight:600;color:var(--accent)">'+t[1]+' mention'+(t[1]>1?'s':'')+'</span>';
      h+='</div>';
    });
    h+='</div>';
  }

  // Individual outcomes
  allOutcomes.forEach(function(ao){
    var o=ao.outcome;
    var oDate=new Date(o.date).toLocaleDateString('en-US',{month:'short',day:'numeric',year:'numeric'});
    var tc=ao.tier==='elite'?'var(--green)':ao.tier==='core'?'var(--accent)':'var(--text3)';
    var helpColor=o.helped==='yes'?'var(--green)':o.helped==='somewhat'?'var(--accent)':'var(--text3)';
    var helpLabel=o.helped==='yes'?'HW Helped ✅':o.helped==='somewhat'?'Somewhat':o.helped==='no'?'Not really':'—';

    h+='<div class="adm-card" style="border-left:3px solid '+(o.helped==='yes'?'var(--green)':'var(--accent)')+'">';
    h+='<div style="display:flex;justify-content:space-between;align-items:flex-start;margin-bottom:6px">';
    h+='<div>';
    h+='<div style="font-size:14px;font-weight:600;color:var(--text)">'+o.typeLabel+'</div>';
    h+='<div style="font-size:11px;color:var(--text3)"><a href="#" onclick="event.preventDefault();admShowUser(\''+ao.userId+'\')" style="color:var(--accent);text-decoration:none">'+ao.user+'</a> · '+ao.email+' · <span style="color:'+tc+'">'+ao.tier.toUpperCase()+'</span></div>';
    h+='</div>';
    h+='<div style="text-align:right"><div style="font-size:11px;color:var(--text3)">'+oDate+'</div>';
    h+='<div style="font-size:10px;color:'+helpColor+';font-weight:600">'+helpLabel+'</div>';
    h+='</div></div>';

    h+='<div style="font-size:12px;color:var(--text2);line-height:1.6;margin-bottom:6px">'+o.details+'</div>';

    var meta=[];
    if(o.program)meta.push('📍 '+o.program);
    if(o.location)meta.push(o.location);
    if(o.salary)meta.push('💰 '+o.salary);
    if(o.bonus)meta.push('Signing: '+o.bonus);
    if(ao.stage)meta.push('Stage: '+ao.stage);
    if(ao.specialty)meta.push('Spec: '+ao.specialty);
    if(meta.length)h+='<div style="font-size:11px;color:var(--text3);margin-bottom:4px">'+meta.join(' · ')+'</div>';

    if(o.helpfulTools&&o.helpfulTools.length){
      h+='<div style="display:flex;flex-wrap:wrap;gap:3px;margin-top:4px">';
      o.helpfulTools.forEach(function(t){
        h+='<span style="font-size:9px;padding:2px 8px;background:rgba(198,168,94,.08);color:var(--accent);border-radius:10px">'+t+'</span>';
      });
      h+='</div>';
    }

    if(o.scoresAtTime){
      h+='<div style="display:flex;gap:4px;margin-top:6px">';
      ['competitiveness','research','readiness','financial'].forEach(function(d){
        var v=o.scoresAtTime[d]||0;
        h+='<span style="font-size:9px;color:var(--text3);padding:2px 6px;background:var(--bg3);border-radius:4px">'+d.substring(0,4)+': '+v+'</span>';
      });
      h+='</div>';
    }
    h+='</div>';
  });

  c.innerHTML=h;
}

// ===== ADMIN: OUTCOMES IN USER DETAIL =====
function admRenderUserOutcomes(u){
  var outcomes=u.outcomes||(u.session_data&&u.session_data.outcomes)||[];
  if(typeof outcomes==='string'){try{outcomes=JSON.parse(outcomes)}catch(e){outcomes=[]}}
  if(!Array.isArray(outcomes))outcomes=[];
  if(!outcomes.length)return'';

  var h='<div class="adm-card"><div style="font-size:12px;font-weight:600;color:var(--text);margin-bottom:8px">🏆 Documented Achievements ('+outcomes.length+')</div>';
  outcomes.slice().reverse().forEach(function(o){
    var oDate=new Date(o.date).toLocaleDateString('en-US',{month:'short',day:'numeric',year:'numeric'});
    var helpColor=o.helped==='yes'?'var(--green)':o.helped==='somewhat'?'var(--accent)':'var(--text3)';
    h+='<div style="padding:10px 12px;background:var(--bg3);border-radius:8px;margin-bottom:6px;border-left:3px solid var(--accent)">';
    h+='<div style="display:flex;justify-content:space-between;align-items:center">';
    h+='<div style="font-size:13px;font-weight:600;color:var(--text)">'+o.typeLabel+'</div>';
    h+='<span style="font-size:10px;color:var(--text3)">'+oDate+'</span></div>';
    h+='<div style="font-size:12px;color:var(--text2);margin-top:2px;line-height:1.5">'+o.details+'</div>';
    var meta=[];
    if(o.program)meta.push(o.program);if(o.location)meta.push(o.location);if(o.salary)meta.push(o.salary);
    if(meta.length)h+='<div style="font-size:10px;color:var(--text3);margin-top:4px">'+meta.join(' · ')+'</div>';
    if(o.helped)h+='<div style="font-size:10px;color:'+helpColor+';margin-top:2px">HeartWise helped: '+(o.helped==='yes'?'Yes ✅':o.helped==='somewhat'?'Somewhat':'Not really')+'</div>';
    h+='</div>';
  });
  h+='</div>';
  return h;
}
// ===== LIFETIME IMPACT CALCULATOR — "WHAT THIS COSTS YOU" =====
// Renders a gold-bordered impact box with dollar amounts, delay tax, and alternative paths
// Called from inside tool result sections, right before hwPathway()

function hwLifetimeImpact(config){
  // config: {
  //   annual: number (annual dollar impact, positive = gain, negative = loss),
  //   type: 'gap'|'gain'|'risk'|'savings'|'cost',
  //   title: string (optional, override default title),
  //   description: string (one-line context),
  //   delayPerMonth: number (optional, cost of each month of inaction),
  //   comparison: string (optional, "most physicians" anchor text),
  //   alternatives: [{action:string, impact:string, tool:{id,name}?}] (paths to fix/capture this),
  //   specialty: string (optional, for context),
  //   yearsToProject: number (optional, default 25)
  // }
  if(!config||!config.annual)return'';
  var annual=config.annual;
  var absAnnual=Math.abs(annual);
  var isLoss=annual<0||config.type==='gap'||config.type==='risk'||config.type==='cost';
  var years=config.yearsToProject||25;
  var rate=0.07; // 7% market return

  // Calculate projections
  var y5=absAnnual*5;
  var y10=0;var lifetime=0;
  for(var i=0;i<years;i++){
    var yearVal=absAnnual*Math.pow(1.05,Math.min(i,10)); // 5% raises for first 10 years
    lifetime+=yearVal*Math.pow(1+rate,years-i);
    if(i<10)y10+=yearVal;
  }
  y10=Math.round(y10);
  lifetime=Math.round(lifetime);

  // Format
  function fmt(n){
    if(n>=1000000)return'$'+(n/1000000).toFixed(1)+'M';
    if(n>=1000)return'$'+Math.round(n/1000)+'K';
    return'$'+n.toLocaleString();
  }

  // Physician salary context
  var cp=(typeof U!=='undefined'&&U&&U.careerProfile)?U.careerProfile:{};
  var monthsOfSalary='';
  var compVal=parseInt(String(cp.comp||'0').replace(/[^0-9]/g,''))||0;
  if(!compVal){
    // Estimate by stage
    var salaryEst={student:60000,resident:68000,fellow:75000,attending:350000};
    compVal=salaryEst[cp.stage]||300000;
  }
  if(compVal>0){
    var months=Math.round(absAnnual*5/(compVal/12));
    if(months>=12)monthsOfSalary=Math.round(months/12)+' years of take-home pay';
    else if(months>=1)monthsOfSalary=months+' months of take-home pay';
  }

  // Debt context
  var debtVal=parseInt(String(cp.debt||'0').replace(/[^0-9]/g,''))||0;
  var debtContext='';
  if(debtVal>0&&y5>=debtVal*0.25){
    var pctOfDebt=Math.round(y5/debtVal*100);
    debtContext=pctOfDebt+'% of your student debt';
  }

  // Choose title and colors
  var title=config.title||(isLoss?'What This Costs You':'What This Gains You');
  var borderColor=isLoss?'rgba(192,96,96,.3)':'rgba(106,191,75,.3)';
  var bgColor=isLoss?'rgba(192,96,96,.04)':'rgba(106,191,75,.04)';
  var accentColor=isLoss?'var(--red)':'var(--green)';
  var icon=isLoss?'💸':'💰';

  var h='<div style="margin:16px 0;padding:18px;background:'+bgColor+';border:1px solid '+borderColor+';border-radius:14px">';

  // Header
  h+='<div style="display:flex;align-items:center;gap:8px;margin-bottom:12px">';
  h+='<span style="font-size:18px">'+icon+'</span>';
  h+='<div style="font-size:12px;font-weight:700;color:'+accentColor+';text-transform:uppercase;letter-spacing:1px">'+title+'</div>';
  h+='</div>';

  // Description
  if(config.description){
    h+='<div style="font-size:13px;color:var(--text);line-height:1.6;margin-bottom:14px">'+config.description+'</div>';
  }

  // Big numbers
  h+='<div style="display:grid;grid-template-columns:repeat(3,1fr);gap:8px;margin-bottom:12px">';
  h+='<div style="text-align:center;padding:12px 8px;background:var(--bg);border-radius:10px;border:1px solid var(--border)">';
  h+='<div style="font-size:20px;font-weight:700;color:'+accentColor+';font-family:var(--font-serif)">'+(isLoss?'-':'+')+''+fmt(y5)+'</div>';
  h+='<div style="font-size:9px;color:var(--text3);margin-top:2px">5-Year Impact</div></div>';
  h+='<div style="text-align:center;padding:12px 8px;background:var(--bg);border-radius:10px;border:1px solid var(--border)">';
  h+='<div style="font-size:20px;font-weight:700;color:'+accentColor+';font-family:var(--font-serif)">'+(isLoss?'-':'+')+''+fmt(y10)+'</div>';
  h+='<div style="font-size:9px;color:var(--text3);margin-top:2px">10-Year Impact</div></div>';
  h+='<div style="text-align:center;padding:12px 8px;background:var(--bg);border-radius:10px;border:1px solid var(--border)">';
  h+='<div style="font-size:20px;font-weight:700;color:'+accentColor+';font-family:var(--font-serif)">'+(isLoss?'-':'+')+''+fmt(lifetime)+'</div>';
  h+='<div style="font-size:9px;color:var(--text3);margin-top:2px">Lifetime (invested)</div></div>';
  h+='</div>';

  // Context line — physician terms
  var contextParts=[];
  if(monthsOfSalary)contextParts.push(monthsOfSalary);
  if(debtContext)contextParts.push(debtContext);
  if(contextParts.length){
    h+='<div style="font-size:11px;color:var(--text2);text-align:center;margin-bottom:10px;line-height:1.5">That 5-year total is equivalent to <strong>'+contextParts.join('</strong> or <strong>')+'</strong>.</div>';
  }

  // Delay tax
  if(config.delayPerMonth){
    var dpm=config.delayPerMonth;
    h+='<div style="display:flex;align-items:center;gap:8px;padding:10px 12px;background:rgba(192,96,96,.06);border:1px solid rgba(192,96,96,.12);border-radius:8px;margin-bottom:12px">';
    h+='<span style="font-size:14px">⏰</span>';
    h+='<div style="flex:1"><div style="font-size:12px;font-weight:600;color:var(--red)">Delay Tax: '+fmt(dpm)+'/month</div>';
    h+='<div style="font-size:10px;color:var(--text3)">Every month you wait costs you '+fmt(dpm)+'. That\'s '+fmt(dpm*12)+'/year in lost value.</div>';
    h+='</div></div>';
  }

  // "Most physicians" anchor
  if(config.comparison){
    h+='<div style="font-size:11px;color:var(--text3);padding:8px 12px;background:var(--bg2);border-radius:8px;margin-bottom:12px;line-height:1.5">';
    h+='<strong style="color:var(--text2)">For context:</strong> '+config.comparison;
    h+='</div>';
  }

  // Alternative paths / solutions
  if(config.alternatives&&config.alternatives.length){
    h+='<div style="margin-top:4px">';
    h+='<div style="font-size:11px;font-weight:700;color:var(--accent);text-transform:uppercase;letter-spacing:1px;margin-bottom:8px">'+(isLoss?'How to Recover This':'How to Capture This')+'</div>';
    config.alternatives.forEach(function(alt,i){
      h+='<div style="display:flex;align-items:flex-start;gap:10px;padding:8px 0;'+(i<config.alternatives.length-1?'border-bottom:1px solid var(--border)':'')+'">';
      h+='<div style="width:20px;height:20px;border-radius:50%;background:rgba(198,168,94,.1);color:var(--accent);font-size:10px;font-weight:700;display:flex;align-items:center;justify-content:center;flex-shrink:0;margin-top:2px">'+(i+1)+'</div>';
      h+='<div style="flex:1">';
      h+='<div style="font-size:12px;color:var(--text);line-height:1.5">'+alt.action+'</div>';
      if(alt.impact)h+='<div style="font-size:11px;color:'+accentColor+';font-weight:600;margin-top:2px">Impact: '+alt.impact+'</div>';
      h+='</div>';
      if(alt.tool)h+='<button onclick="openFramework(\''+alt.tool.id+'\')" style="padding:6px 12px;background:var(--accent);color:#1C1A17;border:none;border-radius:6px;font-size:10px;font-weight:600;cursor:pointer;white-space:nowrap;flex-shrink:0">'+alt.tool.name+' →</button>';
      h+='</div>';
    });
    h+='</div>';
  }

  h+='</div>';
  return h;
}

