// ===== DECISION JOURNAL — CAREER CO-PILOT =====
// 7 components: Decision Capture, Tripwire Alerts, Timeline View,
// 6-Month Revisits, Pre-Decision Mode, Decision Patterns, Shared Decision Context

// ===== 1. STRUCTURED DECISION CAPTURE =====
// Called after every recordToolUse — prompts user to capture their decision

function promptDecisionCapture(toolName, score, summary, resultData){
  if(!U)return;
  if(!U.decisions)U.decisions=[];
  // Don't prompt every single time — only after meaningful tools
  var meaningfulTools=['Contract Review Scorecard','Contract & Offer Analyzer','Specialty Fit Assessment',
    'Match Probability Calculator','Career Roadmap Tool',
    'Contract Review Tool','Financial Planner','RVU Compensation Calculator',
    'Financial Planner','Financial Planner','Specialty & Career Fit',
    'Application Review Tool','Mock Interview Simulator','Observership Database'];
  if(meaningfulTools.indexOf(toolName)<0)return;
  // Don't prompt if they just did one in the last hour
  var lastDecision=U.decisions.length?U.decisions[U.decisions.length-1]:null;
  if(lastDecision&&(Date.now()-new Date(lastDecision.date).getTime())<3600000)return;

  // Store context for the prompt
  window._djToolContext={toolName:toolName,score:score,summary:summary,resultData:resultData};

  // Show a subtle, non-intrusive prompt after a delay
  setTimeout(function(){
    showDecisionPrompt(toolName,score,summary);
  },1500);
}

function showDecisionPrompt(toolName,score,summary){
  // Floating prompt at bottom of results — not a modal
  var existing=document.getElementById('dj-capture-prompt');
  if(existing)existing.remove();

  var prompt=document.createElement('div');
  prompt.id='dj-capture-prompt';
  prompt.style.cssText='position:fixed;bottom:80px;left:50%;transform:translateX(-50%);width:calc(100% - 48px);max-width:480px;background:#1a1620;border:1px solid rgba(198,168,94,.3);border-radius:16px;padding:20px;box-shadow:0 12px 40px rgba(0,0,0,.3);z-index:800;animation:slideUp .4s ease';
  prompt.innerHTML='<div style="display:flex;align-items:flex-start;gap:14px">'
    +'<span style="font-size:24px;flex-shrink:0">🧭</span>'
    +'<div style="flex:1">'
    +'<div style="font-size:14px;font-weight:600;color:#f0ece6;margin-bottom:4px">What are you going to do with this?</div>'
    +'<div style="font-size:11px;color:#b8b3ac;line-height:1.5">Recording your decision now helps you track what works and revisit it later.</div>'
    +'</div>'
    +'<button onclick="this.parentElement.parentElement.remove()" style="background:none;border:none;color:#b8b3ac;cursor:pointer;font-size:16px;padding:0;line-height:1">✕</button>'
    +'</div>'
    +'<div style="display:flex;gap:8px;margin-top:14px">'
    +'<button onclick="openDecisionCapture()" style="flex:1;padding:12px;background:var(--accent);color:#1a1620;border:none;border-radius:10px;font-size:13px;font-weight:600;cursor:pointer">Record Decision</button>'
    +'<button onclick="this.closest(\'#dj-capture-prompt\').remove()" style="padding:12px 16px;background:rgba(255,255,255,.08);color:#b8b3ac;border:none;border-radius:10px;font-size:13px;cursor:pointer">Skip</button>'
    +'</div>';
  document.body.appendChild(prompt);

  // Auto-dismiss after 20 seconds
  setTimeout(function(){var el=document.getElementById('dj-capture-prompt');if(el)el.remove()},20000);
}

