function generateMonthlyReport(){
  if(!U)return;var cp=U.careerProfile||{};var now=new Date();
  var monthName=now.toLocaleDateString('en-US',{month:'long',year:'numeric'});
  var sl={student:'Medical Student',applicant:'Graduate / Applicant',resident:'Resident',fellow:'Fellow',attending:'Attending Physician'}[cp.stage]||'Physician';
  var spec=cp.specialty?(cp.specialty.charAt(0).toUpperCase()+cp.specialty.slice(1)):'';
  var scores=U.scoreHistory&&U.scoreHistory.length?U.scoreHistory[U.scoreHistory.length-1].scores:{};
  var prev=U.scoreHistory&&U.scoreHistory.length>1?U.scoreHistory[U.scoreHistory.length-2].scores:null;
  var mTools=(U.toolHistory||[]).filter(function(t){var td=new Date(t.date);return td.getMonth()===now.getMonth()&&td.getFullYear()===now.getFullYear()});
  var total=VAULT_ITEMS?VAULT_ITEMS.length:15;
  var uniq=[];(U.toolHistory||[]).forEach(function(t){if(uniq.indexOf(t.tool)<0)uniq.push(t.tool)});
  var mCheckins=(U.checkins||[]).filter(function(c){var cd=new Date(c.date);return cd.getMonth()===now.getMonth()});
  var goalsHit=(U.weeklyGoals||[]).filter(function(g){return g.status==='completed'&&new Date(g.date).getMonth()===now.getMonth()}).length;
  var h='<div style="padding:24px;max-width:600px;margin:0 auto">';
  h+='<div style="text-align:center;margin-bottom:24px;padding-bottom:20px;border-bottom:2px solid rgba(198,168,94,.15)"><div style="font-size:12px;color:var(--accent);font-weight:600;letter-spacing:1px;text-transform:uppercase;margin-bottom:4px">HeartWise Career Report</div><div style="font-size:24px;font-weight:600;color:var(--text);font-family:var(--font-serif)">'+monthName+'</div><div style="font-size:13px;color:var(--text3);margin-top:4px">'+U.name+' · '+sl+(spec?' · '+spec:'')+'</div></div>';
  h+='<div style="margin-bottom:20px"><div style="font-size:12px;font-weight:600;color:var(--accent);text-transform:uppercase;letter-spacing:1px;margin-bottom:10px">Career Scores</div><div style="display:grid;grid-template-columns:1fr 1fr;gap:8px">';
  [{k:'competitiveness',l:'Competitiveness',i:'🏆'},{k:'research',l:'Research',i:'🔬'},{k:'readiness',l:'Readiness',i:'🎯'},{k:'financial',l:'Financial',i:'💰'}].forEach(function(si){
    var v=scores[si.k]||0;var d=prev?(v-(prev[si.k]||0)):0;var ds=d>0?'<span style="color:var(--green)">↑+'+d+'</span>':d<0?'<span style="color:var(--red)">↓'+d+'</span>':'';
    var c=v>=75?'var(--green)':v>=55?'var(--accent)':'var(--red)';
    h+='<div style="padding:12px;background:var(--bg2);border-radius:8px;text-align:center"><div style="font-size:12px;margin-bottom:4px">'+si.i+'</div><div style="font-size:22px;font-weight:700;color:'+c+';font-family:var(--font-serif)">'+v+'</div><div style="font-size:10px;color:var(--text3)">'+si.l+'</div>'+(ds?'<div style="margin-top:2px">'+ds+'</div>':'')+'</div>'});
  h+='</div></div>';
  h+='<div style="margin-bottom:20px"><div style="font-size:12px;font-weight:600;color:var(--accent);text-transform:uppercase;letter-spacing:1px;margin-bottom:10px">Monthly Activity</div><div style="display:grid;grid-template-columns:1fr 1fr 1fr;gap:8px">';
  h+='<div style="padding:12px;background:var(--bg2);border-radius:8px;text-align:center"><div style="font-size:20px;font-weight:700;color:var(--text)">'+mTools.length+'</div><div style="font-size:10px;color:var(--text3)">Tools Run</div></div>';
  h+='<div style="padding:12px;background:var(--bg2);border-radius:8px;text-align:center"><div style="font-size:20px;font-weight:700;color:var(--text)">'+mCheckins.length+'</div><div style="font-size:10px;color:var(--text3)">Check-ins</div></div>';
  h+='<div style="padding:12px;background:var(--bg2);border-radius:8px;text-align:center"><div style="font-size:20px;font-weight:700;color:var(--text)">'+goalsHit+'</div><div style="font-size:10px;color:var(--text3)">Goals Hit</div></div></div></div>';
  var pct=Math.round((uniq.length/total)*100);
  h+='<div style="margin-bottom:20px"><div style="font-size:12px;font-weight:600;color:var(--accent);text-transform:uppercase;letter-spacing:1px;margin-bottom:10px">Tool Coverage</div>';
  h+='<div style="font-size:11px;color:var(--text2);margin-bottom:6px">'+uniq.length+' of '+total+' tools explored ('+pct+'%)</div>';
  h+='<div style="height:8px;background:var(--bg3);border-radius:4px;overflow:hidden"><div style="height:100%;width:'+pct+'%;background:linear-gradient(90deg,var(--accent),var(--accent2));border-radius:4px"></div></div></div>';
  if(mCheckins.length){
    h+='<div style="margin-bottom:20px"><div style="font-size:12px;font-weight:600;color:var(--accent);text-transform:uppercase;letter-spacing:1px;margin-bottom:10px">Check-in Summary</div>';
    mCheckins.forEach(function(ci){var cd=new Date(ci.date);
      h+='<div style="padding:8px 0;border-bottom:1px solid var(--border);font-size:11px"><div style="color:var(--text3);margin-bottom:2px">'+cd.toLocaleDateString('en-US',{month:'short',day:'numeric'})+'</div>';
      if(ci.goal) h+='<div style="color:var(--text)">Goal: '+ci.goal+'</div>';
      if(ci.developments) h+='<div style="color:var(--text2);font-style:italic;margin-top:2px">'+ci.developments+'</div>';
      h+='</div>'});
    h+='</div>';
  }
  h+='<div style="text-align:center;padding-top:16px;border-top:1px solid var(--border)"><div style="font-size:10px;color:var(--text3);margin-bottom:12px">Generated by HeartWise · '+new Date().toLocaleDateString('en-US',{month:'long',day:'numeric',year:'numeric'})+'</div>';
  h+='<button onclick="printReport()" style="padding:10px 24px;background:var(--accent);color:#1C1A17;border:none;border-radius:8px;font-size:12px;font-weight:600;cursor:pointer;margin-right:8px">🖨 Print / Save PDF</button>';
  h+='<button onclick="closeModal(\'modal-q\')" style="padding:10px 24px;background:var(--bg2);color:var(--text);border:1px solid var(--border);border-radius:8px;font-size:12px;cursor:pointer">Close</button></div></div>';
  document.getElementById('modal-q-content').innerHTML=h;document.getElementById('modal-q').classList.remove('hidden');
}
