function shouldShowTour(){
  if(!U)return false;
  // Only show for trial users or paid subscribers (not free, not admin)
  if(U.tier==='admin')return false;
  if(U.tier==='free'&&!U.isTrial)return false;
  // Check if already completed
  if(localStorage.getItem('hw_tour_done'))return false;
  // Don't show if user has already explored significantly
  if(U.toolHistory&&U.toolHistory.length>3)return false;
  if(U.scoreHistory&&U.scoreHistory.length>1)return false;
  return true;
}

function startTour(){
  _tourStep=0;
  // Create backdrop (catches clicks outside tooltip)
  var backdrop=document.createElement('div');
  backdrop.id='tour-backdrop';
  backdrop.className='tour-backdrop';
  backdrop.onclick=function(){};// block clicks through
  document.body.appendChild(backdrop);
  // Create highlight (fixed position)
  var hl=document.createElement('div');
  hl.id='tour-highlight';
  hl.className='tour-highlight';
  document.body.appendChild(hl);
  // Create tooltip (fixed position)
  var tt=document.createElement('div');
  tt.id='tour-tooltip';
  tt.className='tour-tooltip';
  document.body.appendChild(tt);
  // Reposition on scroll/resize (debounced)
  var _tourReposTimer=null;
  window._tourRepos=function(){
    if(_tourReposTimer)clearTimeout(_tourReposTimer);
    _tourReposTimer=setTimeout(function(){repositionTour()},50);
  };
  window.addEventListener('scroll',window._tourRepos,true);
  window.addEventListener('resize',window._tourRepos);
  showTourStep(0);
}

function showTourStep(idx){
  _tourStep=idx;
  if(idx>=_tourSteps.length){endTour();return}
  var step=_tourSteps[idx];
  var el=step.target();
  if((!el||el.offsetHeight===0)&&step.fallback)el=step.fallback();
  if(!el||el.offsetHeight===0){showTourStep(idx+1);return}

  // Scroll target into view first
  el.scrollIntoView({behavior:'smooth',block:'center'});

  // Wait for scroll to settle then position everything using fixed coords
  setTimeout(function(){
    var rect=el.getBoundingClientRect();
    var pad=8;
    var hl=document.getElementById('tour-highlight');
    // Fixed positioning — rect values are already viewport-relative
    hl.style.top=(rect.top-pad)+'px';
    hl.style.left=(rect.left-pad)+'px';
    hl.style.width=(rect.width+pad*2)+'px';
    hl.style.height=(rect.height+pad*2)+'px';

    // Build tooltip content
    var dots='';
    for(var i=0;i<_tourSteps.length;i++){dots+='<div class="tour-dot'+(i===idx?' active':'')+'"></div>'}

    var tt=document.getElementById('tour-tooltip');
    tt.innerHTML='<div class="tour-step-num">Step '+(idx+1)+' of '+_tourSteps.length+'</div>'+
      '<div class="tour-tooltip-title">'+step.title+'</div>'+
      '<div class="tour-tooltip-body">'+step.body+'</div>'+
      '<div class="tour-tooltip-footer">'+
      '<div class="tour-dots">'+dots+'</div>'+
      '<div style="display:flex;align-items:center;gap:8px">'+
      (idx>0?'<button class="tour-btn-skip" onclick="showTourStep('+(_tourStep-1)+')">← Back</button>':'')+
      '<button class="tour-btn-skip" onclick="endTour()">Skip</button>'+
      '<button class="tour-btn tour-btn-next" onclick="showTourStep('+(_tourStep+1)+')">'+(idx===_tourSteps.length-1?'Done ✓':'Next →')+'</button>'+
      '</div></div>';

    // Position tooltip — use fixed coords from rect
    var viewH=window.innerHeight;
    var viewW=window.innerWidth;
    // Measure tooltip
    tt.style.top='0px';tt.style.left='-9999px';tt.style.visibility='hidden';
    var ttH=tt.offsetHeight;var ttW=tt.offsetWidth;
    tt.style.visibility='';

    var ttTop;
    // Prefer below, but go above if not enough room
    if(rect.bottom+16+ttH<=viewH){
      ttTop=rect.bottom+16;
    }else if(rect.top-16-ttH>=0){
      ttTop=rect.top-16-ttH;
    }else{
      // Neither fits — put it in the middle of the viewport
      ttTop=Math.max(8,(viewH-ttH)/2);
    }
    var ttLeft=Math.max(16,Math.min(rect.left+(rect.width-ttW)/2,viewW-ttW-16));
    tt.style.top=ttTop+'px';
    tt.style.left=ttLeft+'px';
  },400);
}

// Reposition highlight+tooltip without scrolling (for scroll/resize events)
function repositionTour(){
  if(_tourStep>=_tourSteps.length)return;
  var step=_tourSteps[_tourStep];
  var el=step.target();
  if((!el||el.offsetHeight===0)&&step.fallback)el=step.fallback();
  if(!el)return;
  var rect=el.getBoundingClientRect();
  var pad=8;
  var hl=document.getElementById('tour-highlight');
  if(!hl)return;
  hl.style.top=(rect.top-pad)+'px';
  hl.style.left=(rect.left-pad)+'px';
  hl.style.width=(rect.width+pad*2)+'px';
  hl.style.height=(rect.height+pad*2)+'px';
  var tt=document.getElementById('tour-tooltip');
  if(!tt)return;
  var viewH=window.innerHeight;var viewW=window.innerWidth;
  var ttH=tt.offsetHeight;var ttW=tt.offsetWidth;
  var ttTop;
  if(rect.bottom+16+ttH<=viewH)ttTop=rect.bottom+16;
  else if(rect.top-16-ttH>=0)ttTop=rect.top-16-ttH;
  else ttTop=Math.max(8,(viewH-ttH)/2);
  var ttLeft=Math.max(16,Math.min(rect.left+(rect.width-ttW)/2,viewW-ttW-16));
  tt.style.top=ttTop+'px';
  tt.style.left=ttLeft+'px';
}

function restartTour(){
  localStorage.removeItem('hw_tour_done');
  navTo('scr-home');
  setTimeout(startTour,500);
}
function endTour(){
  var hl=document.getElementById('tour-highlight');
  var tt=document.getElementById('tour-tooltip');
  var bd=document.getElementById('tour-backdrop');
  if(hl)hl.remove();
  if(tt)tt.remove();
  if(bd)bd.remove();
  if(window._tourRepos){
    window.removeEventListener('scroll',window._tourRepos,true);
    window.removeEventListener('resize',window._tourRepos);
    window._tourRepos=null;
  }
  localStorage.setItem('hw_tour_done','1');
}

// ===== BROWSER NOTIFICATIONS =====
function requestNotifPermission(){
  if(!('Notification' in window))return;
  if(Notification.permission==='default'){
    // Ask after a delay so it doesn't feel aggressive
    setTimeout(function(){
      // Only ask if user has been here at least 2 sessions
      var visits=parseInt(localStorage.getItem('hw_visit_count')||'0')+1;
      localStorage.setItem('hw_visit_count',String(visits));
      if(visits>=2){
        Notification.requestPermission();
      }
    },15000);
  }
}
function sendBrowserNotif(title,body,onclick){
  if(!('Notification' in window)||Notification.permission!=='granted')return;
  try{
    var n=new Notification(title,{body:body,icon:'data:image/svg+xml,<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 100 100"><text y=".9em" font-size="80">🫀</text></svg>',badge:'data:image/svg+xml,<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 100 100"><text y=".9em" font-size="80">🫀</text></svg>'});
    if(onclick)n.onclick=function(){window.focus();onclick();n.close()};
    setTimeout(function(){n.close()},8000);
  }catch(e){}
}
// Schedule weekly notification check (runs while page is open)
function scheduleNotifChecks(){
  if(!('Notification' in window)||Notification.permission!=='granted')return;
  // Check every 30 minutes for things worth notifying about
  setInterval(function(){
    if(!U)return;
    // Score staleness
    var age=getScoreAge();
    var lastNotif=localStorage.getItem('hw_notif_score_age');
    if(age>=14&&(!lastNotif||Date.now()-parseInt(lastNotif)>86400000)){
      sendBrowserNotif('Your Career Score needs attention','It\'s been '+age+' days since your last assessment. Recalculate to stay on track.',function(){navTo('scr-vault')});
      localStorage.setItem('hw_notif_score_age',String(Date.now()));
    }
    // Weekly check-in reminder (Mon-Wed)
    var day=new Date().getDay();
    var lastCheckinNotif=localStorage.getItem('hw_notif_checkin');
    if(day>=1&&day<=3&&(!lastCheckinNotif||Date.now()-parseInt(lastCheckinNotif)>86400000)){
      var weekAgo=new Date();weekAgo.setDate(weekAgo.getDate()-7);
      var recent=(U.checkins||[]).find(function(c){return new Date(c.date)>=weekAgo});
      if(!recent&&(U.toolHistory||[]).length>0){
        sendBrowserNotif('Weekly Check-in Ready','2 minutes to update your goals and track progress.',function(){showWeeklyCheckin()});
        localStorage.setItem('hw_notif_checkin',String(Date.now()));
      }
    }
  },1800000); // 30 minutes
}
// Start notification scheduling on page load
if(document.readyState==='complete')setTimeout(scheduleNotifChecks,5000);
else window.addEventListener('load',function(){setTimeout(scheduleNotifChecks,5000)});

